 <!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover">
<title>人生重开 · 角色建卡</title>
</head>
<body>
<style>
/* ============================================================
   人生重开模拟器 · 角色建卡界面
   单色编辑部 / 报纸杂志风格（黑白灰 + 强描边 + 衬线标题）
   全部图标为内联 SVG，无 emoji，无外链字体/图片
   ============================================================ */

/* ── 作用域根容器（防止样式外溢到酒馆 UI） ── */
.cc-root {
  /* ── 色彩体系（单色编辑部） ── */
  --bg-page:    #e9e6dd;   /* 页面外底（暖纸灰） */
  --bg-card:    #fbfaf6;   /* 主卡纸面 */
  --bg-sub:     #f2efe7;   /* 区块底纹 */
  --bg-input:   #ffffff;   /* 输入框 */
  --bg-chip:    #f6f4ec;   /* 标签底 */
  --ink:        #15130e;   /* 主墨色 */
  --ink-soft:   #4a4639;   /* 次要文字 */
  --ink-mute:   #8b8676;   /* 弱化文字 */
  --line:       #15130e;   /* 强描边 */
  --line-mid:   #b7b2a3;   /* 中等分隔 */
  --line-soft:  #ded9cb;   /* 浅分隔 */
  --accent:     #15130e;   /* 强调（黑） */
  --accent-ink: #fbfaf6;   /* 强调上的字 */
  --sel-bg:     #15130e;   /* 选中底 */
  --warn:       #8a3a2a;   /* 警示赭红 */
  --ok:         #2f5d3a;   /* 成功墨绿 */

  /* ── 响应式字号 ── */
  --fs-xs:  clamp(10px, 2vw, 11px);
  --fs-sm:  clamp(11px, 2.2vw, 12.5px);
  --fs-base:clamp(12.5px, 2.5vw, 14px);
  --fs-md:  clamp(13px, 2.8vw, 15px);
  --fs-lg:  clamp(15px, 3.2vw, 18px);
  --fs-xl:  clamp(18px, 4vw, 22px);
  --fs-2xl: clamp(22px, 5vw, 28px);
  --fs-3xl: clamp(30px, 8vw, 46px);

  /* ── 响应式间距 ── */
  --sp-xs: clamp(4px, 1vw, 7px);
  --sp-sm: clamp(7px, 1.8vw, 11px);
  --sp-md: clamp(11px, 2.6vw, 16px);
  --sp-lg: clamp(16px, 3.6vw, 24px);
  --sp-xl: clamp(20px, 5vw, 34px);

  --safe-top:    env(safe-area-inset-top, 0px);
  --safe-bottom: env(safe-area-inset-bottom, 0px);
  --safe-left:   env(safe-area-inset-left, 0px);
  --safe-right:  env(safe-area-inset-right, 0px);

  --ff-serif: 'Noto Serif SC','Songti SC','Source Han Serif SC','SimSun',serif;
  --ff-sans:  'PingFang SC','Microsoft YaHei','Noto Sans SC','system-ui','-apple-system','Segoe UI',sans-serif;
}

.cc-root, .cc-root *, .cc-root *::before, .cc-root *::after {
  margin: 0; padding: 0; box-sizing: border-box;
  -webkit-tap-highlight-color: transparent;
}

.cc-root {
  display: flex;
  justify-content: center;
  width: 100%;
  background: var(--bg-page);
  color: var(--ink);
  font-family: var(--ff-sans);
  font-size: var(--fs-base);
  line-height: 1.6;
  padding: clamp(8px, 3vw, 28px);
  /* 报纸细网点底纹 */
  background-image:
    radial-gradient(var(--line-soft) 0.5px, transparent 0.6px);
  background-size: 7px 7px;
}

/* ── 外层卡片：强黑描边 ── */
.cc-paper {
  position: relative;
  width: 100%;
  max-width: 900px;
  background: var(--bg-card);
  border: 2px solid var(--line);
  box-shadow: 7px 7px 0 var(--line);
}

/* ====== 顶部刊头 ====== */
.cc-masthead {
  display: flex;
  align-items: stretch;
  border-bottom: 2px solid var(--line);
}
.cc-mast-left {
  flex: 1 1 auto;
  padding: var(--sp-lg) var(--sp-lg) var(--sp-md);
  min-width: 0;
}
.cc-kicker {
  font-size: var(--fs-xs);
  letter-spacing: 0.4em;
  color: var(--ink-mute);
  text-transform: uppercase;
  margin-bottom: var(--sp-xs);
}
.cc-title {
  font-family: var(--ff-serif);
  font-size: var(--fs-3xl);
  font-weight: 800;
  letter-spacing: clamp(4px, 2.2vw, 16px);
  line-height: 1.05;
  color: var(--ink);
}
.cc-subtitle {
  margin-top: var(--sp-xs);
  font-size: var(--fs-sm);
  letter-spacing: 0.18em;
  color: var(--ink-soft);
}
.cc-subtitle .cc-en {
  display: block;
  font-size: var(--fs-xs);
  letter-spacing: 0.42em;
  color: var(--ink-mute);
  margin-top: 2px;
}
.cc-mast-right {
  flex: 0 0 auto;
  width: clamp(96px, 26vw, 168px);
  border-left: 2px solid var(--line);
  background: var(--bg-sub);
  display: flex;
  align-items: stretch;
}
.cc-portrait {
  width: 100%;
  display: block;
}

/* ====== 工具条（一键随机） ====== */
.cc-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--sp-sm);
  padding: var(--sp-md) var(--sp-lg);
  border-bottom: 1px solid var(--line-mid);
  background: var(--bg-sub);
  flex-wrap: wrap;
}
.cc-toolbar-info { min-width: 0; }
.cc-toolbar-info h2 {
  font-family: var(--ff-serif);
  font-size: var(--fs-lg);
  letter-spacing: 0.12em;
}
.cc-toolbar-info p {
  font-size: var(--fs-xs);
  color: var(--ink-mute);
  letter-spacing: 0.1em;
  margin-top: 2px;
}

/* ====== 内容主体 ====== */
.cc-body {
  padding: var(--sp-lg);
  display: flex;
  flex-direction: column;
  gap: var(--sp-xl);
}

/* ── 区块 ── */
.cc-section { position: relative; }
.cc-sec-head {
  display: flex;
  align-items: center;
  gap: var(--sp-sm);
  flex-wrap: wrap;
  padding-bottom: var(--sp-sm);
  margin-bottom: var(--sp-md);
  border-bottom: 1.5px solid var(--line);
}
.cc-sec-no {
  font-family: var(--ff-serif);
  font-size: var(--fs-xl);
  font-weight: 800;
  line-height: 1;
  color: var(--ink);
  min-width: 1.6em;
}
.cc-sec-title {
  font-family: var(--ff-serif);
  font-size: var(--fs-md);
  letter-spacing: 0.18em;
  font-weight: 700;
}
.cc-sec-en {
  margin-left: auto;
  font-size: var(--fs-xs);
  letter-spacing: 0.3em;
  color: var(--ink-mute);
  text-transform: uppercase;
  white-space: nowrap;
}

/* ── 字段行（标签 | 输入 | 随机） ── */
.cc-field {
  display: grid;
  grid-template-columns: clamp(64px, 18vw, 96px) 1fr auto;
  align-items: center;
  gap: var(--sp-sm);
  padding: var(--sp-xs) 0;
  border-bottom: 1px dashed var(--line-soft);
}
.cc-field:last-child { border-bottom: none; }
.cc-flabel {
  font-size: var(--fs-sm);
  letter-spacing: 0.14em;
  color: var(--ink-soft);
  white-space: nowrap;
}
.cc-grid2 {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-sm);
}
.cc-grid3 {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: var(--sp-sm);
}

/* ── 输入控件 ── */
.cc-input, .cc-select, .cc-textarea {
  width: 100%;
  min-height: 44px;
  padding: clamp(8px, 1.8vw, 11px) clamp(9px, 2vw, 12px);
  touch-action: manipulation;
  background: var(--bg-input);
  border: 1px solid var(--line-mid);
  border-radius: 0;
  color: var(--ink);
  font-family: var(--ff-sans);
  font-size: var(--fs-base);
  outline: none;
  transition: border-color .18s, box-shadow .18s;
}
.cc-textarea { min-height: 64px; resize: vertical; line-height: 1.7; }
.cc-input:focus, .cc-select:focus, .cc-textarea:focus {
  border-color: var(--line);
  box-shadow: 2px 2px 0 var(--line-mid);
}
.cc-input::placeholder, .cc-textarea::placeholder { color: var(--ink-mute); }
.cc-input.cc-shake { animation: cc-shake .4s; border-color: var(--warn) !important; }
@keyframes cc-shake {
  0%,100%{transform:translateX(0)} 20%,60%{transform:translateX(-4px)} 40%,80%{transform:translateX(4px)}
}
.cc-select {
  appearance: none; -webkit-appearance: none;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%2315130e' stroke-width='2'><path d='M6 9l6 6 6-6'/></svg>");
  background-repeat: no-repeat;
  background-position: right 10px center;
  background-size: 15px;
  padding-right: 32px;
  cursor: pointer;
}

/* ── 随机 / 重抽 小按钮 ── */
.cc-dice {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  min-width: 44px;
  min-height: 44px;
  padding: 0 clamp(7px, 1.6vw, 10px);
  background: var(--bg-card);
  border: 1px solid var(--line);
  color: var(--ink);
  font-family: var(--ff-sans);
  font-size: var(--fs-xs);
  letter-spacing: 0.12em;
  cursor: pointer;
  white-space: nowrap;
  touch-action: manipulation;
  transition: background .15s, color .15s, transform .08s;
}
.cc-dice:hover { background: var(--accent); color: var(--accent-ink); }
.cc-dice:active { transform: translate(1px,1px); }
.cc-dice svg { width: 15px; height: 15px; display: block; }
.cc-dice .cc-dice-txt { display: inline; }

/* ====== 天赋池 ====== */
.cc-talent-block { margin-bottom: var(--sp-md); }
.cc-tb-head {
  display: flex; align-items: center; justify-content: space-between;
  gap: var(--sp-sm); margin-bottom: var(--sp-sm); flex-wrap: wrap;
}
.cc-tb-title {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: var(--fs-sm); letter-spacing: 0.14em; color: var(--ink-soft); font-weight: 600;
}
.cc-tb-title .cc-count { color: var(--ink-mute); font-size: var(--fs-xs); }
.cc-talent-list {
  display: flex; flex-wrap: wrap; gap: var(--sp-sm);
}
.cc-talent {
  position: relative;
  display: flex; flex-direction: column; gap: 3px;
  flex: 1 1 clamp(150px, 40%, 240px);
  min-width: 0;
  padding: var(--sp-sm) var(--sp-md);
  background: var(--bg-chip);
  border: 1px solid var(--line);
  cursor: default;
  transition: transform .1s, box-shadow .15s;
}
.cc-talent.cc-rar-传说 { box-shadow: inset 0 0 0 2px var(--line); background: var(--bg-card); }
.cc-talent.cc-rar-隐藏 { border-style: dashed; }
.cc-talent .cc-t-top {
  display: flex; align-items: center; justify-content: space-between; gap: 6px;
}
.cc-talent .cc-t-name {
  font-family: var(--ff-serif); font-size: var(--fs-md); font-weight: 700; letter-spacing: 0.05em;
  word-break: break-all;
}
.cc-talent .cc-t-effect {
  font-size: var(--fs-xs); color: var(--ink-mute); line-height: 1.6;
}
.cc-rarity { display: inline-flex; align-items: center; gap: 1px; flex: 0 0 auto; }
.cc-rarity svg { width: 12px; height: 12px; display: block; }
.cc-tag-mini {
  flex: 0 0 auto;
  font-size: 10px; letter-spacing: 0.1em;
  padding: 1px 6px; border: 1px solid var(--line); border-radius: 999px;
  color: var(--ink-soft); white-space: nowrap;
}
.cc-t-del, .cc-cdel {
  position: absolute; top: -8px; right: -8px;
  width: 22px; height: 22px; border-radius: 50%;
  background: var(--bg-card); border: 1px solid var(--line);
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; transition: background .15s;
}
.cc-t-del:hover, .cc-cdel:hover { background: var(--accent); }
.cc-t-del:hover svg, .cc-cdel:hover svg { stroke: var(--accent-ink); }
.cc-t-del svg, .cc-cdel svg { width: 11px; height: 11px; stroke: var(--ink); stroke-width: 2.4; }
.cc-talent-empty {
  width: 100%;
  font-size: var(--fs-xs); color: var(--ink-mute);
  border: 1px dashed var(--line-mid);
  padding: var(--sp-sm); text-align: center; letter-spacing: 0.1em;
}
.cc-add-row { display: flex; gap: var(--sp-xs); margin-top: var(--sp-sm); }
.cc-add-row .cc-input { flex: 1 1 auto; min-height: 34px; }
.cc-add-btn {
  flex: 0 0 auto; min-height: 34px; padding: 0 var(--sp-md);
  background: var(--bg-card); border: 1px dashed var(--line);
  color: var(--ink-soft); font-family: var(--ff-sans); font-size: var(--fs-xs);
  letter-spacing: 0.12em; cursor: pointer; touch-action: manipulation;
}
.cc-add-btn:hover { background: var(--accent); color: var(--accent-ink); border-style: solid; }

/* ====== 缺陷 ====== */
.cc-defect-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-md);
}
.cc-defect-col { border: 1px solid var(--line-mid); padding: var(--sp-sm) var(--sp-md); background: var(--bg-sub); }
.cc-defect-col h4 {
  font-size: var(--fs-sm); letter-spacing: 0.14em; color: var(--ink-soft);
  display: flex; align-items: center; gap: 6px; margin-bottom: var(--sp-sm);
  padding-bottom: var(--sp-xs); border-bottom: 1px dashed var(--line-soft);
}
.cc-defect-col h4 .cc-dice { margin-left: auto; min-height: 28px; min-width: 28px; padding: 0 6px; }
.cc-chip-wrap { display: flex; flex-wrap: wrap; gap: 6px; }
.cc-chip {
  display: inline-flex; align-items: center; gap: 5px;
  padding: 4px 6px 4px 10px;
  background: var(--bg-card); border: 1px solid var(--line);
  font-size: var(--fs-xs); letter-spacing: 0.06em;
}
.cc-chip .cc-chip-x {
  display: inline-flex; align-items: center; justify-content: center;
  width: 16px; height: 16px; cursor: pointer; border-radius: 50%;
}
.cc-chip .cc-chip-x:hover { background: var(--accent); }
.cc-chip .cc-chip-x:hover svg { stroke: var(--accent-ink); }
.cc-chip .cc-chip-x svg { width: 9px; height: 9px; stroke: var(--ink); stroke-width: 2.6; }
.cc-defect-none { font-size: var(--fs-xs); color: var(--ink-mute); letter-spacing: 0.1em; }

/* ====== 属性 ====== */
.cc-attr-budget {
  display: flex; align-items: center; justify-content: space-between;
  gap: var(--sp-sm); margin-bottom: var(--sp-md);
  padding: var(--sp-sm) var(--sp-md); background: var(--bg-sub); border: 1px solid var(--line-mid);
}
.cc-budget-label { font-size: var(--fs-sm); letter-spacing: 0.12em; color: var(--ink-soft); }
.cc-budget-val { font-family: var(--ff-serif); font-size: var(--fs-lg); font-weight: 800; }
.cc-budget-val .cc-rem { color: var(--ink); }
.cc-budget-val.cc-over .cc-rem { color: var(--warn); }
.cc-attr-row {
  display: grid;
  grid-template-columns: clamp(48px, 12vw, 64px) 1fr auto;
  align-items: center; gap: var(--sp-sm);
  padding: var(--sp-xs) 0;
  border-bottom: 1px dashed var(--line-soft);
}
.cc-attr-name { font-size: var(--fs-sm); letter-spacing: 0.16em; color: var(--ink-soft); }
.cc-attr-bar { position: relative; height: 12px; background: var(--bg-sub); border: 1px solid var(--line-mid); }
.cc-attr-fill { position: absolute; left: 0; top: 0; bottom: 0; background: var(--ink); transition: width .2s; }
.cc-stepper { display: inline-flex; align-items: center; border: 1px solid var(--line); }
.cc-step-btn {
  width: 30px; height: 32px; display: flex; align-items: center; justify-content: center;
  background: var(--bg-card); border: none; cursor: pointer; touch-action: manipulation;
}
.cc-step-btn:hover { background: var(--accent); }
.cc-step-btn:hover svg { stroke: var(--accent-ink); }
.cc-step-btn:disabled { opacity: 0.3; cursor: not-allowed; }
.cc-step-btn:disabled:hover { background: var(--bg-card); }
.cc-step-btn:disabled:hover svg { stroke: var(--ink); }
.cc-step-btn svg { width: 13px; height: 13px; stroke: var(--ink); stroke-width: 2.4; }
.cc-step-val {
  width: 34px; text-align: center; font-family: var(--ff-serif); font-weight: 800;
  font-size: var(--fs-md); border-left: 1px solid var(--line); border-right: 1px solid var(--line);
  line-height: 32px; background: var(--bg-input);
}

/* 运气滑条 */
.cc-luck-row {
  display: grid; grid-template-columns: clamp(48px,12vw,64px) 1fr auto auto;
  align-items: center; gap: var(--sp-sm);
  padding-top: var(--sp-sm); margin-top: var(--sp-xs); border-top: 1.5px solid var(--line);
}
.cc-range {
  -webkit-appearance: none; appearance: none;
  width: 100%; height: 4px; background: var(--line-mid); outline: none; cursor: pointer;
}
.cc-range::-webkit-slider-thumb {
  -webkit-appearance: none; appearance: none;
  width: 20px; height: 20px; border-radius: 50%;
  background: var(--bg-card); border: 2px solid var(--line); cursor: pointer;
}
.cc-range::-moz-range-thumb {
  width: 18px; height: 18px; border-radius: 50%;
  background: var(--bg-card); border: 2px solid var(--line); cursor: pointer;
}
.cc-luck-val { font-family: var(--ff-serif); font-weight: 800; font-size: var(--fs-md); min-width: 28px; text-align: center; }

/* ====== 世界设定书 / 提交区 ====== */
.cc-foot {
  border-top: 2px solid var(--line);
  background: var(--bg-sub);
  padding: var(--sp-lg);
}
.cc-codex {
  display: flex; gap: var(--sp-md); align-items: flex-start;
  padding: var(--sp-md); background: var(--bg-card); border: 1px solid var(--line);
  margin-bottom: var(--sp-lg);
}
.cc-codex-icon { flex: 0 0 auto; }
.cc-codex-icon svg { width: clamp(30px, 8vw, 40px); height: clamp(30px, 8vw, 40px); stroke: var(--ink); }
.cc-codex-text h3 { font-family: var(--ff-serif); font-size: var(--fs-md); letter-spacing: 0.14em; margin-bottom: 4px; }
.cc-codex-text p { font-size: var(--fs-sm); color: var(--ink-soft); line-height: 1.7; }
.cc-codex-text textarea { margin-top: var(--sp-sm); }

.cc-submit-wrap { display: flex; flex-direction: column; align-items: center; gap: var(--sp-sm); }
.cc-submit {
  width: 100%; max-width: 460px;
  min-height: 52px; padding: var(--sp-md) var(--sp-lg);
  background: var(--accent); color: var(--accent-ink);
  border: 2px solid var(--line);
  box-shadow: 4px 4px 0 var(--line-mid);
  font-family: var(--ff-serif); font-size: var(--fs-lg); font-weight: 700;
  letter-spacing: 0.2em; cursor: pointer; touch-action: manipulation;
  display: inline-flex; align-items: center; justify-content: center; gap: var(--sp-sm);
  transition: transform .08s, box-shadow .08s, opacity .2s;
}
.cc-submit:hover { transform: translate(-1px,-1px); box-shadow: 6px 6px 0 var(--line-mid); }
.cc-submit:active { transform: translate(2px,2px); box-shadow: 1px 1px 0 var(--line-mid); }
.cc-submit:disabled { opacity: 0.6; cursor: progress; transform: none; box-shadow: 4px 4px 0 var(--line-mid); }
.cc-submit.cc-done { background: var(--bg-card); color: var(--ok); border-color: var(--ok); }
.cc-submit.cc-err  { background: var(--bg-card); color: var(--warn); border-color: var(--warn); }
.cc-submit svg { width: 18px; height: 18px; }
.cc-hint { font-size: var(--fs-xs); color: var(--ink-mute); letter-spacing: 0.1em; text-align: center; }

/* ── 一键随机大按钮 ── */
.cc-rollall {
  display: inline-flex; align-items: center; gap: 7px;
  min-height: 40px; padding: 0 var(--sp-md);
  background: var(--accent); color: var(--accent-ink);
  border: 1px solid var(--line);
  font-family: var(--ff-serif); font-size: var(--fs-sm); font-weight: 700; letter-spacing: 0.16em;
  cursor: pointer; white-space: nowrap; touch-action: manipulation;
  transition: transform .08s;
}
.cc-rollall:hover { transform: translateY(-1px); }
.cc-rollall:active { transform: translateY(1px); }
.cc-rollall svg { width: 16px; height: 16px; }

/* ── Toast ── */
.cc-toast {
  position: fixed;
  left: 50%; bottom: calc(18px + var(--safe-bottom));
  transform: translateX(-50%) translateY(20px);
  background: var(--accent); color: var(--accent-ink);
  border: 1px solid var(--line);
  padding: 10px 18px; font-size: var(--fs-sm); letter-spacing: 0.08em;
  z-index: 9999; opacity: 0; pointer-events: none;
  transition: opacity .25s, transform .25s; max-width: 80vw; text-align: center;
}
.cc-toast.cc-show { opacity: 1; transform: translateX(-50%) translateY(0); }
.cc-toast.cc-t-warn { background: var(--warn); }
.cc-toast.cc-t-ok { background: var(--ok); }

/* ====== 关系 / NPC 模块 ====== */
