  /* =========================================================
     五、天赋抽取（含互斥逻辑）
     ========================================================= */
  // 全部天赋的名称→定义索引（跨正/负/隐藏，用于双向互斥）
  var ALL_TALENTS = {};
  (function () {
    DATA.posTalents.concat(DATA.negTalents, DATA.hidTalents).forEach(function (t) { ALL_TALENTS[t.n] = t; });
  })();
  // cand 与 againstNames 中任意一个是否互斥（双向判定）
  function conflicts(candName, againstNames) {
    var cand = ALL_TALENTS[candName];
    for (var i = 0; i < againstNames.length; i++) {
      var nm = againstNames[i];
      if (cand && cand.x && cand.x.indexOf(nm) >= 0) return true;
      var other = ALL_TALENTS[nm];
      if (other && other.x && other.x.indexOf(candName) >= 0) return true;
    }
    return false;
  }
  // 按展示等级加权生成抽取袋
  function weightedBag(list, weights) {
    var bag = [];
    list.forEach(function (t) {
      var c = weights ? (weights[t.r] || 10) : 10;
      for (var i = 0; i < c; i++) bag.push(t);
    });
    return bag;
  }
  // 抽取 count 个天赋，避开 lockedNames（其它已选天赋）及其互斥项
  function drawTalents(kind, count, lockedNames) {
    var POS_W = { '普通':100, '优秀':52, '稀有':26, '史诗':9, '传说':3 };  // 越高级越稀有
    var NEG_W = { '小毛病':100, '弱点':52, '缺陷':26, '不幸':9, '诅咒':3 };
    var bag = kind === 'pos' ? weightedBag(DATA.posTalents, POS_W)
            : kind === 'neg' ? weightedBag(DATA.negTalents, NEG_W)
            : DATA.hidTalents.slice();
    var chosen = [], names = (lockedNames || []).slice(), guard = 0;
    while (chosen.length < count && guard < 600) {
      guard++;
      var cand = pick(bag);
      if (names.indexOf(cand.n) >= 0) continue;
      if (conflicts(cand.n, names)) continue;
      chosen.push({ n: cand.n, r: cand.r || (kind === 'hid' ? '隐藏' : '普通'), e: cand.e || '', mod: '', src: '先天' });
      names.push(cand.n);
    }
    return chosen;
  }
  function namesOf(arr) { return arr.map(function (t) { return t.n; }); }
  function rollPos() {
    var locked = namesOf(state.neg).concat(namesOf(state.hid));
    state.pos = drawTalents('pos', 2, locked);
    renderTalents('pos');
  }
  function rollNeg() {
    var locked = namesOf(state.pos).concat(namesOf(state.hid));
    state.neg = drawTalents('neg', 2, locked);
    renderTalents('neg');
  }
  function rollHid() {
    // 约 55% 概率抽到 1 个隐藏天赋
    var locked = namesOf(state.pos).concat(namesOf(state.neg));
    state.hid = Math.random() < 0.55 ? drawTalents('hid', 1, locked) : [];
    renderTalents('hid');
    if (state.hid.length === 0) toast('命运未眷顾 · 本次无隐藏天赋');
  }

