  function attrSum() {
    var s = 0; ATTR_NAMES.forEach(function (k) { s += state.attrs[k]; }); return s;
  }
  function renderAttrs() {
    var box = $('attr-rows');
    var html = '';
    ATTR_NAMES.forEach(function (k) {
      var v = state.attrs[k];
      var pct = Math.min(100, Math.round(v / 20 * 100));
      html += '<div class="cc-attr-row">' +
        '<span class="cc-attr-name">' + k + '</span>' +
        '<span class="cc-attr-bar"><span class="cc-attr-fill" style="width:' + pct + '%"></span></span>' +
        '<span class="cc-stepper">' +
          '<button class="cc-step-btn" type="button" data-attr="' + k + '" data-d="-1"><svg viewBox="0 0 24 24" fill="none"><path d="M5 12h14"/></svg></button>' +
          '<span class="cc-step-val">' + v + '</span>' +
          '<button class="cc-step-btn" type="button" data-attr="' + k + '" data-d="1"><svg viewBox="0 0 24 24" fill="none"><path d="M12 5v14M5 12h14"/></svg></button>' +
        '</span>' +
        '<div class="cc-attr-desc">' + esc(ATTR_DESC[k] || '') + '</div>' +
        '</div>';
    });
    box.innerHTML = html;
    updateBudget();
  }
  function updateBudget() {
    var info = ageBudget(parseInt(val('f-age'),10)||18);
    ATTR_BUDGET = info.cap;
    var capEl = document.getElementById('budget-cap'); if (capEl) capEl.textContent = info.cap;
    var tierEl = document.getElementById('budget-tier'); if (tierEl) tierEl.textContent = info.tier;
    var rem = ATTR_BUDGET - attrSum();
    var box = $('budget-box'), remEl = $('budget-rem');
    if (remEl) remEl.textContent = rem;
    if (box) box.className = 'cc-budget-val' + (rem < 0 ? ' cc-over' : '');
    // 同步禁用 +/-
    var btns = document.querySelectorAll('#attr-rows .cc-step-btn');
    for (var i = 0; i < btns.length; i++) {
      var k = btns[i].getAttribute('data-attr');
      var d = parseInt(btns[i].getAttribute('data-d'), 10);
      if (d > 0) btns[i].disabled = rem <= 0 || state.attrs[k] >= (ATTR_MAX_EACH[k] || 100);
      else btns[i].disabled = state.attrs[k] <= ATTR_MIN;
    }
  }
  function stepAttr(k, d) {
    var rem = ATTR_BUDGET - attrSum();
    if (d > 0 && rem <= 0) { toast('点池已用尽（上限 ' + ATTR_BUDGET + '）', 'warn'); return; }
    var nv = state.attrs[k] + d;
    if (nv < ATTR_MIN) return;
    if (nv > (ATTR_MAX_EACH[k] || 100)) return;
    state.attrs[k] = nv;
    renderAttrs();
  }
  function rollAttrs() {
    // 剩余分配法：先各给最小值，再把剩余点随机洒入
    var rem = ATTR_BUDGET - ATTR_NAMES.length * ATTR_MIN;
    ATTR_NAMES.forEach(function (k) { state.attrs[k] = ATTR_MIN; });
    while (rem > 0) {
      var k = pick(ATTR_NAMES);
      if (state.attrs[k] < (ATTR_MAX_EACH[k] || 100)) { state.attrs[k]++; rem--; }
    }
    renderAttrs();
  }

  /* =========================================================
     八、肖像 / 年龄联动
     ========================================================= */
  function updatePortrait() {
    var surname = val('f-surname');
    var t = $('cc-portrait-initial');
    if (!t) return;
    if (surname) {
      t.textContent = surname.charAt(0);
      t.setAttribute('opacity', '0.9');
    } else {
      t.setAttribute('opacity', '0');
    }
  }
  function clampAttrsToBudget() {
    var cap = ageBudget(parseInt(val('f-age'), 10) || 0).cap;
    var guard = 0;
    while (attrSum() > cap && guard < 2000) {
      var best = null;
      ATTR_NAMES.forEach(function (k) { if (state.attrs[k] > ATTR_MIN && (best === null || state.attrs[k] > state.attrs[best])) best = k; });
      if (best === null) break;
      state.attrs[best]--;
      guard++;
    }
  }
  function onAgeChange() {
    var raw = val('f-age');
    var age = parseInt(raw, 10);
    if (isNaN(age)) age = 0;
    if (age < 0) age = 0;
    if (age > 150) age = 150;
    if (String(age) !== raw && raw !== '') setVal('f-age', age);
    var rp = $('row-past'); if (rp) rp.style.display = age > 0 ? 'grid' : 'none';
    clampAttrsToBudget();
    renderAttrs();
  }

  /* =========================================================
     九、一键全随机
     ========================================================= */
  function rollAll() {
    // 先定地域：国家→省/州→城市→居住地 级联，并据真实人口权重决定难易（同时决定姓名文化）
    rollCountry();
    rollGender();
    rollOrient();
    rollName();          // 依据所在国家生成对应文化的姓名
    rollAge();
    // 出生年份与年龄联动：让「起始年代」落在合理区间，保持时序自洽
    var age = parseInt(val('f-age'), 10) || 0;
    var startYear = (Math.random() < 0.7) ? ri(1980, 2020) : ri(1960, 2024);
    var by = startYear - age; if (by < 1940) by = 1940;
    setVal('f-byear', by);
    setVal('f-bmonth', ri(1, 12));
    setVal('f-bday', ri(1, 28));
    // 身份板（不可折叠）
    rollIdentity(); rollOcc(); rollAspiration();
    rollPersonality(); rollMbti(); rollAppearance(); rollRepTag(); rollOpening();
    BIG5.forEach(function (k) { state.bigFive[k] = ri(20, 80); });
    renderBigFive();
    // 籍贯家境（可折叠 → 折叠则跳过）
    if (!secCollapsed('sec-origin')) {
      rollWealth();        // 加权：多数人温饱/小康
      rollClan();          // 加权：多数人普通工薪/务农
      rollMood();
      state.npcs = defaultNpcs();   // 父母姓名随机化，且与子女姓氏/所在国文化自洽
      renderNpcs();
      if (age > 0) rollPast();
    }
    // 天赋（可折叠）
    if (!secCollapsed('sec-talent')) { rollPos(); rollNeg(); rollHid(); }
    // 技能·物品·爱好（可折叠）
    if (!secCollapsed('sec-skill')) { rollSkill(); rollItem(); rollHobby(); }
    // 缺陷（可折叠）
    if (!secCollapsed('sec-defect')) {
      state.defects = { '先天缺陷':[], '性格缺陷':[], '身体缺陷':[], '心理缺陷':[] };
      var defCount = wpick([[0,34],[1,40],[2,20],[3,6]]);
      var dims = ['先天缺陷','性格缺陷','身体缺陷','心理缺陷'].slice();
      for (var s = dims.length - 1; s > 0; s--) { var j = Math.floor(Math.random() * (s + 1)); var tmp = dims[s]; dims[s] = dims[j]; dims[j] = tmp; }
      for (var i = 0; i < defCount && i < dims.length; i++) { state.defects[dims[i]].push(pick(DATA.defects[dims[i]])); }
      renderDefects();
    }
    // 属性 / 体征 / 心理（不可折叠）
    rollAttrs(); rollLuck(); rollBeauty(); rollFavor(); rollRenown(); rollIq(); rollShengwang();
    rollHeight(); rollWeight(); rollBodytype(); rollDevstage();
    // 世界引擎（不可折叠）
    rollEngine();
    // 学籍（可折叠）
    if (!secCollapsed('sec-academic')) rollAcademic();
    // 组织 / 信念 / 秘密（可折叠 → 折叠则跳过）
    if (!secCollapsed('sec-org') && typeof rollOrgSection === 'function') rollOrgSection();
    if (!secCollapsed('sec-belief') && typeof rollBeliefSection === 'function') rollBeliefSection();
    if (!secCollapsed('sec-secret') && typeof rollSecretSection === 'function') rollSecretSection();
    updatePortrait();
    onAgeChange();
    computeOpeningYear();
    syncRangeLabels();
    toast('已随机生成全部字段（已折叠的板块未参与）', 'ok');
  }

  /* =========================================================
     十、序列化 —— 提交文本 / 世界书 / 变量
     ========================================================= */
  function fullName() {
    var s = val('f-surname'), g = val('f-given');
    if (/[A-Za-z]/.test(s + g)) { return (g + ' ' + s).trim() || (s || g); }  // 西文：名 + 姓
    return (s + g).trim() || (s || g);
  }
  function collect() {
    var d = {};
    d.name = fullName();
    d.surname = val('f-surname'); d.given = val('f-given');
    d.gender = val('f-gender');
    d.orient = val('f-orient');
    d.age = parseInt(val('f-age'), 10) || 0;
    d.byear = parseInt(val('f-byear'), 10) || 0;
    d.bmonth = parseInt(val('f-bmonth'), 10) || 1;
    d.bday = parseInt(val('f-bday'), 10) || 1;
    d.country = val('f-country') || '中国';
    d.province = val('f-province');
    d.city = val('f-city');
    d.residence = val('f-residence');
    d.wealth = val('f-wealth') || '小康';
    d.clan = val('f-clan');
    d.familyMood = val('f-family-mood');
    d.npcs = state.npcs.map(function (n) {
      return { tag: (n.tag || '').trim(), name: (n.name || '').trim(), job: (n.job || '').trim(), persona: (n.persona || '').trim(), cat: (n.cat || '').trim(), relTags: (n.relTags || []).slice(), trust: (n.trust != null ? n.trust : 0), note: (n.note || '').trim(), affinity: n.affinity, depth: n.depth };
    }).filter(function (n) { return n.tag || n.name || n.job || n.persona || (n.relTags && n.relTags.length) || n.note; });
    d.past = val('f-past');
    d.appearance = val('f-appearance');
    d.personality = val('f-personality');
    d.mbti = (state.mbti || val('f-mbti') || '').toUpperCase();
    d.pos = state.pos; d.neg = state.neg; d.hid = state.hid;
    d.defects = state.defects;
    d.attrs = state.attrs;
    d.luck = parseInt(val('f-luck'), 10) || 50;
    d.beauty = (function () { var b = parseInt(val('f-beauty'), 10); return isNaN(b) ? 50 : b; })();
    d.birthplace = [d.country, d.province, d.city].filter(function (x) { return x; }).join('·');
    d.realism = val('f-realism');
    d.tendency = val('f-tendency');
    d.narrative = val('f-narrative');
    d.difficulty = val('f-difficulty') || '普通';   // [NEW] 难度等级
    d.grain = val('f-grain') || '月';
    d.worldnote = val('f-worldnote');
    d.appearTraits = (state.appear || []).slice();
    d.favor = parseInt(val('f-favor'), 10) || 0;
    d.renown = parseInt(val('f-renown'), 10) || 0;
    d.iq = (function () { var x = parseInt(val('f-iq'), 10); return isNaN(x) ? 100 : x; })();
    d.bigFive = { '外向': state.bigFive['外向'], '亲和': state.bigFive['亲和'], '尽责': state.bigFive['尽责'], '情绪稳定': state.bigFive['情绪稳定'], '开放': state.bigFive['开放'] };
    d.repTag = val('f-reptag');
    d.omonth = parseInt(val('f-omonth'), 10) || 0;
    d.oday = parseInt(val('f-oday'), 10) || 0;
    d.oyear = parseInt(val('f-oyear'), 10) || (d.byear + d.age);
    d.background = val('f-background');
    d.occ = val('f-occ');
    d.identity = val('f-identity');
    d.title = val('f-title');
    d.aspiration = val('f-aspiration');
    d.skills = (state.skills || []).map(function (sk) { return { name: (sk.name || '').trim(), level: sk.level, prof: sk.prof, desc: (sk.desc || '').trim() }; }).filter(function (sk) { return sk.name; });
    d.items = (state.items || []).map(function (it) { return { name: (it.name || '').trim(), tier: it.tier || '贵重', desc: (it.desc || '').trim() }; }).filter(function (it) { return it.name; });
    d.hobbies = (state.hobbies || []).map(function (h) { return { name: (h.name || '').trim(), addiction: h.addiction }; }).filter(function (h) { return h.name; });
    d.orgs = (state.orgs || []).slice();
    d.titles = (state.titles || []).slice();
    d.residency = (state.residency || []).slice();
    d.beliefs = (state.beliefs || []).slice();
    d.secrets = (state.secrets || []).slice();
    // [阶段B 接线] 体征 / 心理 / 学籍 / 家境描述 / 声望 —— 此前 collect 漏采，导致档案与随机失效，现补齐
    d.familyDesc = val('f-family-desc');
    d.height = parseInt(val('f-height'), 10) || 0;
    d.weight = parseInt(val('f-weight'), 10) || 0;
    d.bodyType = val('f-bodytype');
    d.devStage = val('f-devstage');
    d.eduStatus = val('f-edu-status');
    d.eduStageText = val('f-edu-stage');
    d.eduSchool = val('f-edu-school');
    d.eduGrade = val('f-edu-grade');
    d.eduMajor = val('f-edu-major');
    d.eduTier = val('f-edu-tier');
    d.eduRank = val('f-edu-rank');
    d.eduClassRank = val('f-edu-classrank');
    d.shengwang = (function () { var x = parseInt(val('f-shengwang'), 10); return isNaN(x) ? 0 : x; })();
    d.person = state.person || '第二人称';
    return d;
  }
  function pad2(n) { return (n < 10 ? '0' : '') + n; }
  function ageToStage(age) {
    age = parseInt(age, 10) || 0;
    if (age <= 2) return '婴幼儿';
    if (age <= 6) return '幼儿';
    if (age <= 12) return '儿童';
    if (age <= 17) return '青少年';
    if (age <= 24) return '青年';
    if (age <= 39) return '壮年';
    if (age <= 59) return '中年';
    if (age <= 79) return '老年';
    return '耄耋';
  }
  function ageToEcon(age) {
    age = parseInt(age, 10) || 0;
    if (age < 16) return '依附家庭';
    if (age < 22) return '半独立';
    return '独立';
  }
  function wealthToTier(w) {
    var map = { '赤贫':'赤贫', '贫困':'贫困', '温饱':'温饱', '小康':'小康', '富裕':'富裕', '豪富':'豪富', '巨富':'巨富' };
    return map[w] || w || '小康';
  }
  function itemTierToLevel(tier) {
    var map = { '普通':'普通', '贵重':'贵重', '命运':'命运', '传家宝':'传家宝' };
    return map[tier] || tier || '普通';
  }
  function talentStr(arr, withRarity) {
    if (!arr.length) return '无';
    return arr.map(function (t) {
      return t.n + (withRarity && t.r && t.r !== '隐藏' ? '[' + t.r + ']' : '') + (t.e ? '（' + t.e + '）' : '');
    }).join('，');
  }
  function defectStr(d) {
    var lines = [];
    ['先天缺陷','性格缺陷','身体缺陷','心理缺陷'].forEach(function (dim) {
      if (d.defects[dim] && d.defects[dim].length) lines.push(dim + '：' + d.defects[dim].join('、'));
    });
    return lines.length ? lines.join(' ｜ ') : '无';
  }
