  function applyToStatData(stat, d) {
    // 读取-修改-写回，仅改动主角/世界/家庭/顶层运气，保留其余结构
    if (!stat || typeof stat !== 'object') stat = {};
    function ensure(obj, key) { if (!obj[key] || typeof obj[key] !== 'object') obj[key] = {}; return obj[key]; }

    stat['$运气'] = d.luck;

    // [FIX] 游戏模式/难度/写实程度/叙事风格/事件倾向/人称 均归流程状态（非顶层 $ / 非世界）
    var flow = ensure(stat, '流程状态');
    flow['游戏模式'] = 'CHARACTER_CREATION';
    flow['人称'] = d.person || '第二人称';
    if (d.difficulty) flow['难度'] = d.difficulty;
    if (d.realism) flow['写实程度'] = d.realism;
    if (d.narrative) flow['叙事风格'] = d.narrative;
    if (d.tendency) flow['事件倾向'] = d.tendency;

    var w = ensure(stat, '世界');
    w['国家地区'] = d.country;
    w['城市'] = d.city || '待初始化';
    w['年代背景'] = String(d.byear);
    w['当前时间粒度'] = d.grain || '月';
    var oy = d.oyear || (d.byear + d.age);
    w['当前日期'] = oy + '年' + pad2(d.omonth || d.bmonth) + '月' + pad2(d.oday || d.bday) + '日';

    var p = ensure(stat, '主角');
    p['姓名'] = d.name || '待初始化';
    p['性别'] = d.gender || '待初始化';
    p['年龄'] = d.age;
    p['生日'] = pad2(d.bmonth) + '-' + pad2(d.bday);
    p['出生日期'] = d.byear + '年' + pad2(d.bmonth) + '月' + pad2(d.bday) + '日';
    p['身份阶段'] = ageToStage(d.age);
    p['经济模式'] = ageToEcon(d.age);
    p['家境等级'] = wealthToTier(d.wealth);   // [FIX] 映射到 schema 家境等级 enum
    if (d.familyDesc) p['家境描述'] = d.familyDesc;   // [项目1] 家境描述自由文本
    if (d.birthplace) p['出生地'] = d.birthplace;
    if (d.appearance || (d.appearTraits && d.appearTraits.length)) p['外貌描述'] = ((d.appearTraits && d.appearTraits.length) ? ('小特点：' + d.appearTraits.join('、')) : '') + (d.appearance ? (((d.appearTraits && d.appearTraits.length) ? '；' : '') + d.appearance) : '');
