    if (d.mbti) p['性格类型'] = d.mbti;
    if (d.occ) p['职业'] = d.occ;
    var _tt = [d.identity, d.title].filter(function (x) { return x; }); if (_tt.length) p['头衔爵位'] = _tt;   // 身份 + 头衔 → 头衔爵位（数组）
    if (d.aspiration) { var goal = ensure(p, '目标'); goal['长期'] = [{ '描述': d.aspiration, '进度': 0, '状态': '进行中' }]; }   // [FIX] 人生志向→目标.长期[]

    var attr = ensure(p, '属性');
    attr['体质'] = d.attrs['体质']; attr['智慧'] = d.attrs['智慧']; attr['魅力'] = d.attrs['魅力'];
    attr['财富'] = d.attrs['财富']; attr['心理'] = d.attrs['心理'];
    attr['声望'] = (typeof d.shengwang === 'number' ? d.shengwang : 0);   // [项目6] 初始声望可填(-100~100)

