    (d.secrets || []).forEach(function (s, i) { var label = (s.label || '').trim() || ('秘密' + (i + 1)); secObj[label] = { '类型': s.type || '私密', '发起方': '', '目标': '', '进展': clampInt(s.progress, 0, 100, 0), '严重度': clampInt(s.severity, 0, 100, 0), '已暴露线索': [], '知情圈': {} }; });
