    if (!d.gender) { shake('f-gender'); toast('请填写性别', 'warn'); return false; }
    if (!d.byear) { shake('f-byear'); toast('请填写出生年份', 'warn'); return false; }
    return true;
  }
  function shake(id) {
    var el = $(id); if (!el) return;
