  }

  function setBtn(txt, cls, disabled) {
    var b = $('cc-confirm');
    b.disabled = !!disabled;
    b.className = 'cc-submit' + (cls ? ' ' + cls : '');
    b.innerHTML = esc(txt) + (cls === 'cc-done'
      ? ' <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><path d="M5 13l4 4L19 7"/></svg>'
      : (!cls ? ' <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14"/><path d="M13 6l6 6-6 6"/></svg>' : ''));
  }

  function onConfirm() {
    var d = collect();
    if (!validate(d)) return;

    // 环境检测
    if (typeof getCharWorldbookNames === 'undefined' || typeof createChatMessages === 'undefined' || typeof Mvu === 'undefined') {
      toast('未在酒馆环境中运行，已向控制台打印档案', 'warn');
      console.log('[人生重开] 角色档案：\n' + buildProfileText(d));
      console.log('[人生重开] 世界书条目：\n' + buildWorldbookContent(d));
      return;
    }

    setBtn('数据载入中…', '', true);
    $('cc-hint').textContent = '正在写入变量与世界书……';

    var profileText = buildProfileText(d);
    var wbContent = buildWorldbookContent(d);
    var existingData, wbName;

    Promise.resolve()
      .then(function () {
        if (typeof waitGlobalInitialized === 'function') return waitGlobalInitialized('Mvu');
      })
      .then(function () {
        var charWB = getCharWorldbookNames('current');
        wbName = charWB && (charWB.primary || (charWB.additional && charWB.additional[0]));
        // 读取完整 MVU 数据，仅替换 stat_data
        existingData = Mvu.getMvuData({ type: 'message', message_id: 0 }) || {};
        var stat = existingData.stat_data || {};
        existingData.stat_data = applyToStatData(stat, d);
        // 创建玩家提交楼层（携带完整 MVU 数据，保留 initialized_lorebooks 等内部字段）
        // [BUGFIX] refresh:'all' 会全量重渲染聊天列表 → 卡顿/闪屏/滚到顶；改为 'affected' 只刷新被影响的消息。
        return createChatMessages([{ role: 'user', message: profileText, data: existingData }], { refresh: 'affected' });
      })
      .then(function () {
        return Mvu.replaceMvuData(existingData, { type: 'message', message_id: 0 });
      })
      .then(function () {
        if (!wbName) return null;
        return deleteWorldbookEntries(wbName, function (e) { return e.name === '角色创建档案' || e.comment === '角色创建档案'; })
          .catch(function () { return null; });
      })
      .then(function () {
        if (!wbName) return null;
        return createWorldbookEntries(wbName, [{
          name: '角色创建档案',
          comment: '角色创建档案',
          enabled: true,
          strategy: { type: 'constant', keys: [], keys_secondary: { logic: 'and_any', keys: [] }, scan_depth: 'same_as_global' },
          position: { type: 'before_character_definition', role: 'system', depth: 0, order: 5 },
          content: wbContent,
          probability: 100,
          recursion: { prevent_incoming: true, prevent_outgoing: true, delay_until: null },
          effect: { sticky: null, cooldown: null, delay: null }
        }]);
      })
      .then(function () {
        // 数据写入完成：先让 AI 生成开场叙事，最后再收起建卡界面。
        // 顺序很关键：若此刻就替换第 0 楼会触发重渲染并销毁本 iframe，
        // 导致后续 generate / 写楼层被中断、界面也无法切换。
        setBtn('降生成功！', 'cc-done', true);
        $('cc-hint').textContent = 'AI 正在生成你的人生序章……';
        toast('降生成功 · 人生开始', 'ok');
        // 触发 AI 生成欢迎叙事 + 完整初始化
        return generate({ user_input: '', should_stream: true });
      })
      .then(function (aiReply) {
        if (aiReply != null) {
          // [BUGFIX] 仅刷新受影响消息，避免滚动位置被重置
          return createChatMessages([{ role: 'assistant', message: String(aiReply), data: existingData }], { refresh: 'affected' });
        }
      })
      .then(function () {
        // 收尾（最后一步）：把第 0 楼的建卡 HTML 永久替换为纯文字档案。
        // 替换内容不含任何尖括号 / 代码块 → 酒馆不再渲染建卡界面，仅显示文字，
        // 即“角色创建后自动跳转为文字不渲染”。此时变量 / 世界书 / 开场叙事均已写入。
        // 即便本 iframe 被销毁也不影响最终结果。
        try {
          setChatMessages([{ message_id: 0, message: buildArchiveText(d) }], { refresh: 'affected' });
        } catch (e) {}
      })
      .catch(function (err) {
        console.error('[人生重开] 提交失败：', err);
        setBtn('提交失败 · 点击重试', 'cc-err', false);
        $('cc-hint').textContent = '错误：' + ((err && err.message) || String(err));
        toast('提交失败，请重试', 'warn');
      });
  }

