  function rollHeight() { var age = parseInt(val('f-age'), 10); if (isNaN(age)) age = 18; var h = age < 2 ? ri(50, 85) : age < 12 ? ri(95, 150) : age < 18 ? ri(150, 178) : ri(150, 190); setVal('f-height', h); }
