  function rollDevstage() { var age = parseInt(val('f-age'), 10); if (isNaN(age)) age = 18; var s = age < 3 ? '婴幼儿' : age < 12 ? '儿童' : age < 14 ? '青春期前' : age < 18 ? '青春期' : age < 60 ? '成熟' : '衰老'; setVal('f-devstage', s); }
  function rollShengwang() { setVal('f-shengwang', ri(-20, 30)); syncRangeLabels(); }
  function eduPlanByAge(age) {
    if (isNaN(age)) age = 18;
    var r = { status: '在读', stage: '', grade: '' };
    if (age < 3) { r.status = '失学'; }
    else if (age < 6) { r.stage = '幼儿园'; r.grade = '在园'; }
    else if (age < 12) { r.stage = '小学'; r.grade = '小学' + cnNum(Math.min(6, Math.max(1, age - 5))) + '年级'; }
    else if (age < 15) { r.stage = '初中'; r.grade = '初' + cnNum(Math.min(3, Math.max(1, age - 11))); }
    else if (age < 18) { r.stage = '高中'; r.grade = '高' + cnNum(Math.min(3, Math.max(1, age - 14))); }
    else if (age < 23) { r.stage = '大学'; r.grade = '大' + cnNum(Math.min(4, Math.max(1, age - 17))); }
    else { r.status = '毕业'; r.stage = '大学'; }
    return r;
  }
  function schoolNameByStage(stage) {
