    if (stage === '大学') return pre + pick(['大学', '理工大学', '师范大学', '财经大学']);
    if (stage === '高中') return pre + pick(['高级中学', '中学']);
    if (stage === '初中') return pre + pick(['初级中学', '中学']);
    if (stage === '小学') return pre + '小学';
    if (stage === '幼儿园') return pre + '幼儿园';
