      case 'skill': rollSkill(); rollItem(); rollHobby(); break;
      case 'defect':
        state.defects = { '先天缺陷': [], '性格缺陷': [], '身体缺陷': [], '心理缺陷': [] };
        var dc = wpick([[0, 34], [1, 40], [2, 20], [3, 6]]);
        var dims = ['先天缺陷', '性格缺陷', '身体缺陷', '心理缺陷'].slice();
        for (var s = dims.length - 1; s > 0; s--) { var j = Math.floor(Math.random() * (s + 1)); var tmp = dims[s]; dims[s] = dims[j]; dims[j] = tmp; }
        for (var i = 0; i < dc && i < dims.length; i++) { state.defects[dims[i]].push(pick(DATA.defects[dims[i]])); }
        renderDefects();
        break;
      case 'attr': rollAttrs(); rollLuck(); rollBeauty(); rollFavor(); rollRenown(); rollIq(); rollShengwang(); break;
      case 'engine': rollEngine(); break;
      case 'phys': rollHeight(); rollWeight(); rollBodytype(); rollDevstage(); break;
      case 'academic': rollAcademic(); break;
      case 'org': if (typeof rollOrgSection === 'function') rollOrgSection(); break;
      case 'belief': if (typeof rollBeliefSection === 'function') rollBeliefSection(); break;
      case 'secret': if (typeof rollSecretSection === 'function') rollSecretSection(); break;
    }
  }

  /* =========================================================
     十二、事件绑定 / 初始化
     ========================================================= */
  function bindEvents() {
    // 委托：所有 data-roll
    var rollMap = {
      name: rollName, gender: rollGender, orient: rollOrient, appearance: rollAppearance, personality: rollPersonality, mbti: rollMbti,
      age: rollAge, birth: rollBirth,
      country: rollCountry, province: rollProvince, city: rollCity, residence: rollResidence,
      wealth: rollWealth, clan: rollClan, mood: rollMood,
      past: rollPast, luck: rollLuck, beauty: rollBeauty,
      pos: rollPos, neg: rollNeg, hid: rollHid,
      opening: rollOpening, favor: rollFavor, renown: rollRenown, iq: rollIq, occ: rollOcc, identity: rollIdentity,
      shengwang: rollShengwang,
      height: rollHeight, weight: rollWeight, bodytype: rollBodytype, devstage: rollDevstage,
      title: rollTitle, edustage: rollEduStage, eduschool: rollEduSchool, edugrade: rollEduGrade, edumajor: rollEduMajor
    };
    document.getElementById('cc-root').addEventListener('click', function (ev) {
      var t = ev.target.closest ? ev.target.closest('[data-roll],[data-add],[data-defect],[data-mbtipick],[data-appeardel],[data-mbtidel],.cc-t-del,.cc-chip-x,.cc-step-btn,#cc-npc-reroll,#appear-roll,#mbti-roll,#reptag-roll') : null;
      if (!t) return;
      if (t.hasAttribute('data-roll')) { var fn = rollMap[t.getAttribute('data-roll')]; if (fn) fn(); return; }
      if (t.hasAttribute('data-mbtipick')) { setMbti(t.getAttribute('data-mbtipick')); return; }
      if (t.hasAttribute('data-appeardel')) { delAppear(parseInt(t.getAttribute('data-appeardel'), 10)); return; }
      if (t.hasAttribute('data-mbtidel')) { clearMbti(); return; }
      if (t.id === 'appear-roll') { rollAppearance(); return; }
      if (t.id === 'mbti-roll') { rollMbti(); return; }
      if (t.id === 'reptag-roll') { rollRepTag(); return; }
      if (t.id === 'cc-npc-reroll') { rerollAllNpcs(); return; }
      if (t.hasAttribute('data-add')) { addCustomTalent(t.getAttribute('data-add')); return; }
      if (t.hasAttribute('data-defect')) { rollDefect(t.getAttribute('data-defect')); return; }
      if (t.classList.contains('cc-t-del')) {
        var kind = t.getAttribute('data-kind'), idx = parseInt(t.getAttribute('data-idx'), 10);
        state[kind].splice(idx, 1); renderTalents(kind); return;
      }
      if (t.classList.contains('cc-chip-x') && t.hasAttribute('data-dim')) {
        var dim = t.getAttribute('data-dim'), di = parseInt(t.getAttribute('data-idx'), 10);
        state.defects[dim].splice(di, 1); renderDefects(); return;
      }
      if (t.classList.contains('cc-step-btn')) {
        if (t.disabled) return;
        stepAttr(t.getAttribute('data-attr'), parseInt(t.getAttribute('data-d'), 10)); return;
      }
    });

    // 回车添加（天赋 / 缺陷自定义）
    document.getElementById('cc-root').addEventListener('keydown', function (ev) {
      if (ev.key !== 'Enter') return;
      var el = ev.target;
      if (el.id === 'add-pos') { ev.preventDefault(); addCustomTalent('pos'); }
      else if (el.id === 'add-neg') { ev.preventDefault(); addCustomTalent('neg'); }
      else if (el.id === 'add-hid') { ev.preventDefault(); addCustomTalent('hid'); }
      else if (el.hasAttribute && el.hasAttribute('data-defadd')) { ev.preventDefault(); addCustomDefect(el.getAttribute('data-defadd'), el.value); el.value = ''; }
      else if (el.id === 'add-skill') { ev.preventDefault(); addSkill(); }
      else if (el.id === 'add-item') { ev.preventDefault(); addItem(); }
      else if (el.id === 'add-hobby') { ev.preventDefault(); addHobby(); }
    });

    $('cc-rollall').addEventListener('click', rollAll);
    $('cc-confirm').addEventListener('click', onConfirm);
    // [新增] 折叠 / 分板块随机 委托
    document.getElementById('cc-root').addEventListener('click', function (ev) {
      var c = ev.target.closest ? ev.target.closest('[data-collapse],[data-secroll],[data-subcollapse]') : null;
      if (!c) return;
      if (c.hasAttribute('data-subcollapse')) { var sc = document.getElementById(c.getAttribute('data-subcollapse')); if (sc) sc.classList.toggle('cc-subcollapsed'); return; }
      if (c.hasAttribute('data-collapse')) { toggleSection(c.getAttribute('data-collapse')); return; }
      if (c.hasAttribute('data-secroll')) { rollSection(c.getAttribute('data-secroll')); return; }
    });
    // [新增] 体征/心理/学籍/声望 范围滑块实时数值
    [['f-shengwang', 'shengwang-val']].forEach(function (p) {
      var el = $(p[0]); if (el) el.addEventListener('input', function () { var lab = $(p[1]); if (lab) lab.textContent = this.value; });
    });
