    [['add-org-btn', addOrg], ['add-title-btn', addTitle], ['add-res-btn', addResidency], ['add-belief-btn', addBelief], ['add-secret-btn', addSecret]].forEach(function (pp) { var b = $(pp[0]); if (b) b.addEventListener('click', pp[1]); });
    document.addEventListener('click', function (ev) {
      var dt = ev.target && ev.target.closest ? ev.target.closest('[data-orgdel],[data-titledel],[data-resdel],[data-beliefdel],[data-secretdel]') : null;
