        else if (el.hasAttribute('data-skillprof')) { i = parseInt(el.getAttribute('data-skillprof'), 10); if (state.skills[i]) { state.skills[i].prof = parseInt(el.value, 10); var n2 = skBox.querySelector('[data-skillprofnum="' + i + '"]'); if (n2) n2.textContent = el.value + '%'; } }
