        if (el.hasAttribute('data-npctagroll')) { rollNpcRelTag(parseInt(el.getAttribute('data-npctagroll'), 10)); return; }
        if (el.hasAttribute('data-npctagdel')) { delNpcRelTag(parseInt(el.getAttribute('data-npctagdel'), 10), parseInt(el.getAttribute('data-j'), 10)); return; }
        if (el.hasAttribute('data-npcnotetoggle')) { toggleNpcNote(parseInt(el.getAttribute('data-npcnotetoggle'), 10)); return; }
