  if(typeof waitGlobalInitialized==='undefined')return;
  waitGlobalInitialized('Mvu').then(function(){
    var msgId=typeof getCurrentMessageId==='function'?getCurrentMessageId():0;
    var mvu=Mvu.getMvuData({type:'message',message_id:msgId});
    if(mvu){
      _.set(mvu,'stat_data.流程状态.写实程度',document.getElementById('sm-diff').value);
