<body>
<style>
.ft-root {
  --bg-page:#e9e6dd; --bg-card:#fbfaf6; --bg-sub:#f2efe7; --bg-input:#fff; --bg-chip:#f6f4ec;
  --ink:#15130e; --ink-soft:#4a4639; --ink-mute:#8b8676;
  --line:#15130e; --line-mid:#b7b2a3; --line-soft:#ded9cb;
  --accent:#15130e; --accent-ink:#fbfaf6; --warn:#8a3a2a; --ok:#2f5d3a; --gold:#8a6d2a;
  --fs-xs:clamp(10px,2vw,11px); --fs-sm:clamp(11px,2.2vw,12.5px); --fs-base:clamp(12.5px,2.5vw,14px);
  --fs-md:clamp(13px,2.8vw,15px); --fs-lg:clamp(15px,3.2vw,18px); --fs-xl:clamp(18px,4vw,22px);
  --fs-2xl:clamp(22px,5vw,28px);
  --sp-xs:clamp(4px,1vw,7px); --sp-sm:clamp(7px,1.8vw,11px); --sp-md:clamp(11px,2.6vw,16px);
  --sp-lg:clamp(16px,3.6vw,24px); --sp-xl:clamp(20px,5vw,34px);
  --safe-bottom:env(safe-area-inset-bottom,0px);
  --ff-serif:'Noto Serif SC','Songti SC','SimSun',serif;
  --ff-sans:'PingFang SC','Microsoft YaHei','Noto Sans SC','system-ui','-apple-system','Segoe UI',sans-serif;
}
.ft-root, .ft-root *, .ft-root *::before, .ft-root *::after { margin:0; padding:0; box-sizing:border-box; -webkit-tap-highlight-color:transparent; }
.ft-root {
  display:flex; justify-content:center; width:100%;
  background:var(--bg-page); color:var(--ink); font-family:var(--ff-sans); font-size:var(--fs-base); line-height:1.6;
  padding:clamp(8px,3vw,24px);
  background-image:radial-gradient(var(--line-soft) 0.5px, transparent 0.6px); background-size:7px 7px;
}
.ft-paper { position:relative; width:100%; max-width:780px; background:var(--bg-card); border:2px solid var(--line); box-shadow:7px 7px 0 var(--line); }

.ft-head { padding:var(--sp-lg) var(--sp-lg) var(--sp-md); border-bottom:2px solid var(--line); display:flex; align-items:center; gap:var(--sp-md); }
.ft-head-icon { width:32px; height:32px; stroke:var(--ink); flex:0 0 auto; }
.ft-kicker { font-size:var(--fs-xs); letter-spacing:0.4em; color:var(--ink-mute); text-transform:uppercase; }
.ft-title { font-family:var(--ff-serif); font-size:var(--fs-2xl); font-weight:800; letter-spacing:clamp(2px,1vw,6px); }

.ft-body { padding:var(--sp-lg); display:flex; flex-direction:column; gap:var(--sp-md); }

.ft-empty { text-align:center; color:var(--ink-mute); font-size:var(--fs-sm); padding:var(--sp-xl); border:1px dashed var(--line-mid); }

.ft-node { border:1.5px solid var(--line); background:var(--bg-card); margin-bottom:var(--sp-md); }
.ft-node.alive { border-left:4px solid var(--ok); }
.ft-node.dead { border-left:4px solid var(--ink-mute); }
.ft-node-head { display:flex; align-items:center; gap:var(--sp-sm); padding:var(--sp-sm) var(--sp-md); border-bottom:1px solid var(--line-soft); background:var(--bg-sub); cursor:pointer; user-select:none; }
.ft-node-head:hover { background:var(--bg-chip); }
.ft-node-av { width:28px; height:28px; border-radius:50%; border:1.5px solid var(--line); display:flex; align-items:center; justify-content:center; font-family:var(--ff-serif); font-weight:800; font-size:var(--fs-sm); flex:0 0 auto; }
.ft-node.dead .ft-node-av { opacity:.5; }
.ft-node-name { font-family:var(--ff-serif); font-size:var(--fs-md); font-weight:700; flex:1; min-width:0; }
.ft-node-meta { display:flex; gap:6px; flex-wrap:wrap; }
.ft-node-tag { font-size:var(--fs-xs); padding:2px 8px; border:1px solid var(--line-mid); color:var(--ink-mute); }
.ft-node-tag.alive { border-color:var(--ok); color:var(--ok); }
.ft-node-tag.dead { border-color:var(--ink-mute); }
.ft-chev { width:16px; height:16px; transition:transform .3s; flex:0 0 auto; }
.ft-chev svg { width:16px; height:16px; stroke:var(--ink); }
.ft-node.expanded .ft-chev { transform:rotate(180deg); }
.ft-node-body { max-height:0; overflow:hidden; transition:max-height .4s ease; }
.ft-node.expanded .ft-node-body { max-height:600px; }
.ft-node-inner { padding:var(--sp-md); display:flex; flex-direction:column; gap:6px; }
.ft-row { display:flex; gap:10px; font-size:var(--fs-sm); padding:3px 0; border-bottom:1px dashed var(--line-soft); }
.ft-row:last-child { border-bottom:none; }
.ft-rk { flex:0 0 auto; min-width:5em; color:var(--ink-mute); text-align:right; letter-spacing:.06em; }
.ft-rv { flex:1; color:var(--ink); word-break:break-word; }
.ft-verdict { font-family:var(--ff-serif); font-style:italic; color:var(--ink-soft); padding:var(--sp-sm) 0; line-height:1.8; }

.ft-foot { padding:var(--sp-md) var(--sp-lg); border-top:2px solid var(--line); background:var(--bg-sub); text-align:center; }
.ft-foot-tip { font-size:var(--fs-xs); color:var(--ink-mute); }

@media (prefers-reduced-motion:reduce){ .ft-root *{ transition:none!important; } }
</style>

<div class="ft-root" id="ft-root">
  <div class="ft-paper">
    <header class="ft-head">
      <svg class="ft-head-icon" viewBox="0 0 24 24" fill="none" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
      <div>
        <div class="ft-kicker">Family Tree</div>
        <div class="ft-title">家族树</div>
      </div>
    </header>

    <main class="ft-body" id="ft-body">
      <div class="ft-empty" id="ft-empty">尚无家族记录</div>
    </main>

    <footer class="ft-foot">
      <span class="ft-foot-tip">点击人物卡片展开详情</span>
    </footer>
  </div>
</div>

<script>
(function(){
  'use strict';
  function $(id){ return document.getElementById(id); }
  function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

  function readStat(){
    try{
      if(typeof Mvu!=='undefined' && Mvu.getMvuData){
        var d=Mvu.getMvuData({type:'message',message_id:'latest'})||{};
        if(d.stat_data) return d.stat_data;
      }
    }catch(e){}
    return null;
  }

  function avatar(name){
    var s=String(name||'?').trim();
    return s?s.charAt(0):'?';
  }

  function renderNode(id, node){
    var alive=node.状态==='在世';
    var cls='ft-node '+(alive?'alive':'dead');
    var av=avatar(node.姓名);
    var tags='';
    tags+='<span class="ft-node-tag '+(alive?'alive':'dead')+'">'+(alive?'在世':'已故')+'</span>';
    if(node.总评等级) tags+='<span class="ft-node-tag">'+esc(node.总评等级)+'</span>';

    var lifespan='';
    if(node.出生年份){
      lifespan=esc(node.出生年份);
      if(node.死亡年份) lifespan+=' — '+esc(node.死亡年份);
      if(node.存活年数) lifespan+=' ('+node.存活年数+'年)';
    }

    var rows=[];
    if(node.性别) rows.push(['性别', node.性别]);
    if(node.出生地) rows.push(['出生地', node.出生地]);
    if(lifespan) rows.push(['生卒', lifespan]);
    if(node.配偶) rows.push(['配偶', node.配偶]);
    if(node.子女 && node.子女.length) rows.push(['子女', node.子女.join('、')]);
    if(node.关键成就 && node.关键成就.length) rows.push(['成就', node.关键成就.join('、')]);
    if(node.传家宝 && node.传家宝.length) rows.push(['传家宝', node.传家宝.join('、')]);

    var rowsHtml=rows.map(function(r){
      return '<div class="ft-row"><span class="ft-rk">'+esc(r[0])+'</span><span class="ft-rv">'+esc(String(r[1]))+'</span></div>';
    }).join('');

    var verdict=node.一句话总评?('<div class="ft-verdict">'+esc(node.一句话总评)+'</div>'):'';

    return '<div class="'+cls+'" data-id="'+esc(id)+'">'+
      '<div class="ft-node-head">'+
        '<span class="ft-node-av">'+esc(av)+'</span>'+
        '<span class="ft-node-name">'+esc(node.姓名||id)+'</span>'+
        '<span class="ft-node-meta">'+tags+'</span>'+
        '<span class="ft-chev"><svg viewBox="0 0 24 24" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M6 9l6 6 6-6"/></svg></span>'+
      '</div>'+
      '<div class="ft-node-body"><div class="ft-node-inner">'+rowsHtml+verdict+'</div></div>'+
    '</div>';
  }

  function init(){
    var stat=readStat();
    var tree=(stat&&stat.全局&&stat.全局.家族树)||{};
    var keys=Object.keys(tree);
    var body=$('ft-body');
    var empty=$('ft-empty');

    if(!keys.length){
      // Try mock data for preview
      tree={
        'CHAR_001':{ 角色ID:'CHAR_001', 姓名:'林知夏', 性别:'女', 出生年份:'1996', 死亡年份:'2068', 出生地:'中国·云南·昆明', 存活年数:72, 总评等级:'精彩', 一句话总评:'她用一生证明：热爱可以穿越一切。', 状态:'已故', 子女:['林晓雨'], 配偶:'苏未', 关键成就:['校乐队成员','省级音乐奖'], 传家宝:['母亲的旧钢笔'] }
      };
      keys=Object.keys(tree);
      if(!keys.length){ return; }
    }

    empty.style.display='none';
    var html='';
    keys.forEach(function(k){ html+=renderNode(k, tree[k]); });
    body.innerHTML=html;

    // Toggle expand
    body.addEventListener('click', function(ev){
      var head=ev.target.closest('.ft-node-head');
      if(!head) return;
      var node=head.closest('.ft-node');
      if(node) node.classList.toggle('expanded');
    });
  }

  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',init); else init();
})();
</script>
</body>
</html>

