}
.tl-paper { position:relative; width:100%; max-width:760px; background:var(--bg-card); border:2px solid var(--line); box-shadow:7px 7px 0 var(--line); }

/* 刊头 */
.tl-head { padding:var(--sp-lg) var(--sp-lg) var(--sp-md); border-bottom:2px solid var(--line); display:flex; justify-content:space-between; align-items:flex-end; gap:var(--sp-md); flex-wrap:wrap; }
.tl-head-l{ min-width:0; }
.tl-kicker{ font-size:var(--fs-xs); letter-spacing:0.4em; color:var(--ink-mute); text-transform:uppercase; margin-bottom:4px; }
.tl-title{ font-family:var(--ff-serif); font-size:var(--fs-2xl); font-weight:800; letter-spacing:clamp(2px,1vw,6px); }
