.tl-head-r .tl-line{ font-family:var(--ff-serif); font-size:var(--fs-sm); color:var(--ink); }
/* 等级图例 */
.tl-legend{ display:flex; gap:var(--sp-md); padding:var(--sp-sm) var(--sp-lg); border-bottom:1px solid var(--line-mid); background:var(--bg-sub); font-size:var(--fs-xs); color:var(--ink-soft); flex-wrap:wrap; align-items:center; }
.tl-legend .lg{ display:inline-flex; align-items:center; gap:5px; }
.tl-dot{ width:9px; height:9px; border:1.4px solid var(--ink); display:inline-block; }
.tl-dot.lv-琐碎{ border-style:dashed; } .tl-dot.lv-普通{ } .tl-dot.lv-重要{ background:var(--ink); } .tl-dot.lv-命运{ background:var(--ink); border-radius:50%; transform:rotate(45deg); }

/* 时间线主体 */
.tl-body{ padding:var(--sp-lg) var(--sp-lg) var(--sp-md); position:relative; }
.tl-track{ position:relative; padding-left:clamp(58px,16vw,86px); }
