.tl-c-sub{ font-size:var(--fs-xs); color:var(--ink-mute); margin-top:2px; }
.tl-c-right{ display:flex; flex-direction:column; align-items:flex-end; gap:6px; flex:0 0 auto; }
.tl-rp{ display:inline-flex; align-items:center; gap:4px; font-size:10px; color:var(--ink-mute); cursor:pointer; user-select:none; }
.tl-rp .box{ width:15px; height:15px; border:1.5px solid var(--line); display:inline-flex; align-items:center; justify-content:center; }
.tl-rp .box svg{ width:10px; height:10px; stroke:var(--accent-ink); opacity:0; }
.tl-rp.on .box{ background:var(--accent); } .tl-rp.on .box svg{ opacity:1; }
.tl-chev{ width:16px; height:16px; transition:transform .3s; }
.tl-chev svg{ width:16px; height:16px; stroke:var(--ink); }
.tl-event.expanded .tl-chev{ transform:rotate(180deg); }

/* 详情展开 */
.tl-detail{ max-height:0; overflow:hidden; transition:max-height .4s ease; border-top:0 solid var(--line-soft); }
.tl-event.expanded .tl-detail{ max-height:1400px; border-top-width:1px; }
.tl-detail-in{ padding:var(--sp-md); display:flex; flex-direction:column; gap:var(--sp-sm); }
.tl-desc{ font-size:var(--fs-sm); color:var(--ink-soft); line-height:1.8; }
.tl-points{ display:flex; flex-wrap:wrap; gap:6px; }
.tl-pt{ font-size:var(--fs-xs); padding:2px 8px; border:1px solid var(--line-mid); background:var(--bg-sub); letter-spacing:0.04em; }
.tl-pt.up{ border-color:var(--ink); } .tl-pt.down{ color:var(--warn); border-color:var(--warn); }
.tl-opts-label{ font-size:var(--fs-xs); color:var(--ink-mute); letter-spacing:0.14em; margin-top:2px; }
.tl-opts{ display:flex; flex-direction:column; gap:6px; }
.tl-opt{ display:flex; align-items:flex-start; gap:8px; padding:8px var(--sp-sm); border:1px solid var(--line-mid); background:var(--bg-input); cursor:pointer; transition:background .12s,border-color .12s; }
.tl-opt:hover{ background:var(--bg-chip); }
.tl-opt.sel{ border-color:var(--ink); background:rgba(21,19,14,0.05); box-shadow:inset 2px 0 0 var(--ink); }
.tl-opt-key{ font-family:var(--ff-serif); font-weight:800; font-size:var(--fs-sm); width:18px; flex:0 0 auto; }
.tl-opt-text{ font-size:var(--fs-sm); min-width:0; }
.tl-custom{ display:none; margin-top:4px; }
.tl-custom.show{ display:block; }
.tl-custom textarea{ width:100%; min-height:48px; padding:7px 10px; background:var(--bg-input); border:1px solid var(--line); color:var(--ink); font-family:var(--ff-sans); font-size:var(--fs-sm); resize:vertical; outline:none; }
.tl-trivial{ font-size:var(--fs-xs); color:var(--ink-mute); border:1px dashed var(--line-mid); padding:7px var(--sp-sm); letter-spacing:0.06em; }

/* 底部 */
.tl-foot{ display:flex; align-items:center; gap:var(--sp-sm); padding:var(--sp-md) var(--sp-lg) var(--sp-lg); border-top:2px solid var(--line); background:var(--bg-sub); flex-wrap:wrap; }
.tl-progress{ font-size:var(--fs-xs); color:var(--ink-mute); }
.tl-progress strong{ color:var(--ink); font-family:var(--ff-serif); }
.tl-foot-btns{ margin-left:auto; display:flex; gap:var(--sp-sm); }
.tl-btn{ min-height:44px; padding:0 var(--sp-lg); font-family:var(--ff-serif); font-size:var(--fs-md); font-weight:700; letter-spacing:0.12em; cursor:pointer; border:1.5px solid var(--line); background:var(--bg-card); color:var(--ink); touch-action:manipulation; transition:transform .08s,background .12s; }
.tl-btn:hover{ background:var(--bg-chip); } .tl-btn:active{ transform:translate(1px,1px); }
.tl-btn.primary{ background:var(--accent); color:var(--accent-ink); box-shadow:4px 4px 0 var(--line-mid); display:inline-flex; align-items:center; gap:8px; }
.tl-btn.primary:hover{ transform:translate(-1px,-1px); box-shadow:5px 5px 0 var(--line-mid); }
.tl-btn.primary:disabled{ opacity:.6; cursor:progress; }
.tl-btn.primary svg{ width:16px; height:16px; }
.tl-btn.primary.done{ background:var(--bg-card); color:var(--ok); border-color:var(--ok); }
.tl-btn.primary.err{ background:var(--bg-card); color:var(--warn); border-color:var(--warn); }

.tl-toast{ position:fixed; left:50%; bottom:calc(18px + var(--safe-bottom)); transform:translateX(-50%) translateY(20px); background:var(--accent); color:var(--accent-ink); border:1px solid var(--line); padding:10px 18px; font-size:var(--fs-sm); z-index:9999; opacity:0; pointer-events:none; transition:opacity .25s,transform .25s; max-width:82vw; text-align:center; }
.tl-toast.show{ opacity:1; transform:translateX(-50%) translateY(0); } .tl-toast.warn{ background:var(--warn); } .tl-toast.ok{ background:var(--ok); }
@media (prefers-reduced-motion:reduce){ .tl-root *{ animation:none!important; transition:none!important; } .tl-event{ opacity:1!important; transform:none!important; } }
</style>

<div class="tl-root" id="tl-root">
  <!-- 由正则注入的原始时间线数据（生产环境为 $1） -->
  <div id="tl-data" style="display:none;">$1</div>

  <div class="tl-paper">
    <header class="tl-head">
      <div class="tl-head-l">
        <div class="tl-kicker">Event Log</div>
        <div class="tl-title">事件系统</div>
      </div>
      <div class="tl-head-r">
        <div>当前时间线</div>
        <div class="tl-line" id="tl-period">——</div>
      </div>
    </header>
    <div class="tl-legend">
      <span style="letter-spacing:.16em;color:var(--ink-mute)">事件等级</span>
      <span class="lg"><span class="tl-dot lv-琐碎"></span>琐碎</span>
      <span class="lg"><span class="tl-dot lv-普通"></span>普通</span>
      <span class="lg"><span class="tl-dot lv-重要"></span>重要</span>
      <span class="lg"><span class="tl-dot lv-命运"></span>命运</span>
      <span style="margin-left:auto;color:var(--ink-mute)">点击事件展开详情 · 勾选 RP 进入小剧场</span>
    </div>

    <main class="tl-body">
      <div class="tl-track" id="tl-track"></div>
    </main>

    <footer class="tl-foot">
      <span class="tl-progress" id="tl-progress">待选择 <strong>0</strong> / 0</span>
      <div class="tl-foot-btns">
        <button class="tl-btn" type="button" id="tl-toggle-all">全部展开</button>
        <button class="tl-btn primary" type="button" id="tl-settle">
          进入结算
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14"/><path d="M13 6l6 6-6 6"/></svg>
        </button>
      </div>
    </footer>
  </div>
  <div class="tl-toast" id="tl-toast"></div>
</div>

<script>
(function(){
  'use strict';
  function $(id){ return document.getElementById(id); }
  function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  var toastTimer=null;
  function toast(msg,kind){ var t=$('tl-toast'); if(!t)return; t.className='tl-toast show'+(kind?' '+kind:''); t.textContent=msg; if(toastTimer)clearTimeout(toastTimer); toastTimer=setTimeout(function(){t.className='tl-toast';},1900); }
  function escST(str){ if(typeof str!=='string')return str; return str.replace(/(\\+)?([|{}])/g,function(m,s,c){ s=s||''; return s+s+'\\'+c; }); }

  /* ── 预览用模拟数据（生产环境 $1 会被真实数据替换，此处仅在解析不到 <evt> 时兜底） ── */
  var MOCK = '' +
    '<evt id="E001" time="1995年04月23日" level="普通" tag="成长" schedule="与家人互动" location="上海·家" npc="母亲">' +
      '<evt-title>第一次翻身</evt-title>' +
      '<evt-detail>在妈妈的陪伴下，你第一次学会了翻身，感受到了世界的不同视角，家人都为你欢呼。</evt-detail>' +
      '<evt-points>体质+1 心理+1</evt-points>' +
      '<evt-options>A. 继续努力练习翻身\nB. 满足地咯咯笑\nC. 累了大哭起来\nD. 自定义行动</evt-options>' +
    '</evt>' +
    '<evt id="E002" time="1995年06月01日" level="琐碎" tag="日常" schedule="休息睡觉" location="上海·家" npc="父亲">' +
      '<evt-title>午后的安睡</evt-title>' +
      '<evt-detail>阳光正好，你在父亲怀里安然入睡，做了一个香甜的梦。</evt-detail>' +
      '<evt-points>精力+5</evt-points>' +
    '</evt>' +
    '<evt id="E003" time="1995年08月15日" level="重要" tag="社交" schedule="户外探索" location="上海·小区" npc="邻居小男孩">' +
      '<evt-title>邻居的小朋友来访</evt-title>' +
      '<evt-detail>邻居家的小朋友来找你玩，大家一起在院子里嬉戏，分享玩具和零食，建立了最初的友谊。</evt-detail>' +
      '<evt-points>魅力+1</evt-points>' +
      '<evt-options>A. 主动分享玩具\nB. 一起搭积木\nC. 忽略他，自己玩\nD. 自定义行动</evt-options>' +
    '</evt>' +
    '<evt id="E004" time="1995年11月02日" level="命运" tag="健康" schedule="" location="上海·家" npc="母亲">' +
      '<evt-title>第一次生病发烧</evt-title>' +
      '<evt-detail>你因为感冒发烧，躺在床上，妈妈彻夜细心地照顾着你。这场小小的病痛，是你与世界最早的较量。</evt-detail>' +
      '<evt-points>体质-1 心理+2</evt-points>' +
      '<evt-options>A. 乖乖吃药休息\nB. 哭闹不止\nC. 强撑着想玩\nD. 自定义行动</evt-options>' +
    '</evt>';

  /* ── 清洗思维链 ── */
  function sanitize(text){ if(!text)return ''; return text.replace(/^[\s\S]*<\/(?:think|thinking)>/i,'').trim(); }

  /* ── 解析事件 ── */
  var events=[];
  function parseEvents(){
    var holder=$('tl-data');
    var raw = holder ? holder.innerHTML : '';
    // 若正则未替换（预览/无数据），用模拟数据
    var probe=document.createElement('div'); probe.innerHTML=raw;
    if(probe.querySelectorAll('evt').length===0){
      probe.innerHTML=MOCK;
    }
    var nodes=probe.querySelectorAll('evt');
    var out=[];
    for(var i=0;i<nodes.length;i++){
      var n=nodes[i];
      var titleEl=n.querySelector('evt-title');
      var detailEl=n.querySelector('evt-detail');
      var pointsEl=n.querySelector('evt-points');
      var optsEl=n.querySelector('evt-options');
      var opts=[];
      if(optsEl){
        var lines=optsEl.textContent.split('\n');
        for(var j=0;j<lines.length;j++){
          var m=lines[j].match(/^\s*([A-Za-z])[\.、:：\)]\s*(.+?)\s*$/);
          if(m) opts.push({ key:m[1].toUpperCase(), text:m[2] });
        }
      }
      out.push({
        id:n.getAttribute('id')||('E'+(i+1)),
        time:n.getAttribute('time')||'',
        level:n.getAttribute('level')||'普通',
        tag:n.getAttribute('tag')||'',
        schedule:n.getAttribute('schedule')||'',
        location:n.getAttribute('location')||'',
        npc:n.getAttribute('npc')||'',
        title:titleEl?titleEl.textContent.trim():'未命名事件',
        detail:detailEl?detailEl.textContent.trim():'',
        points:pointsEl?pointsEl.textContent.trim():'',
        options:opts,
        trivial:(n.getAttribute('level')==='琐碎')||opts.length===0,
        choice:null, custom:'', rp:false
      });
    }
    return out;
  }

  /* ── 日期拆分 ── */
  function splitDate(t){
    var y=(t.match(/(\d{3,4})\s*年/)||[])[1]||'';
    var md=t.replace(/^\d{3,4}\s*年\s*/,'');
    var mo=(md.match(/(\d{1,2})\s*月/)||[])[1];
    var da=(md.match(/(\d{1,2})\s*日/)||[])[1];
    return { y:y?y+'年':'', main:(mo?mo:'')+(mo?'.':'')+(da?da:''), raw:md };
  }

  /* ── 渲染属性变化 ── */
  function renderPoints(str){
    if(!str) return '';
    var tokens=str.split(/\s+/).filter(Boolean);
    var html='';
    tokens.forEach(function(tk){
      var down=/[-−](?=\d)/.test(tk) || /-\d/.test(tk);
      html+='<span class="tl-pt '+(down?'down':'up')+'">'+esc(tk)+'</span>';
    });
    return '<div class="tl-points">'+html+'</div>';
  }

  /* ── 渲染时间线 ── */
  function render(){
    var track=$('tl-track'); track.innerHTML='';
    events.forEach(function(e,idx){
      var ev=document.createElement('div');
      ev.className='tl-event'; ev.setAttribute('data-idx',idx);
      var d=splitDate(e.time);
      var optsHtml='';
      if(e.trivial){
        optsHtml='<div class="tl-trivial">琐碎事件 · 将自动结算，无需选择</div>';
      }else{
        var inner='';
        e.options.forEach(function(o){
          var isD=/自定义|自行输入/.test(o.text) || o.key==='D';
          inner+='<div class="tl-opt" data-key="'+o.key+'" data-custom="'+(isD?'1':'0')+'">'+
                   '<span class="tl-opt-key">'+esc(o.key)+'</span>'+
                   '<span class="tl-opt-text">'+esc(o.text)+'</span></div>';
        });
        optsHtml='<div class="tl-opts-label">可选选项</div><div class="tl-opts">'+inner+
                 '</div><div class="tl-custom"><textarea placeholder="输入你的自定义行动……" maxlength="120"></textarea></div>';
      }
      var subBits=[];
      if(e.location) subBits.push('地点 '+esc(e.location));
      if(e.npc) subBits.push('NPC '+esc(e.npc));
      ev.innerHTML=
        '<div class="tl-node">'+
          '<div class="tl-date-y">'+esc(d.y)+'</div>'+
          '<div class="tl-date-d">'+esc(d.main||e.time)+'</div>'+
        '</div>'+
        '<div class="tl-marker lv-'+esc(e.level)+'"></div>'+
        '<div class="tl-card lv-'+esc(e.level)+'">'+
          '<div class="tl-card-head" data-act="toggle">'+
            '<div class="tl-c-main">'+
              '<div class="tl-c-meta">'+
                '<span class="tl-id">#'+esc(e.id)+'</span>'+
                (e.tag?'<span class="tl-tag">'+esc(e.tag)+'</span>':'')+
                '<span class="tl-tag lv">'+esc(e.level)+'</span>'+
              '</div>'+
              '<div class="tl-c-title">'+esc(e.title)+'</div>'+
              (subBits.length?'<div class="tl-c-sub">'+subBits.join(' ｜ ')+'</div>':'')+
            '</div>'+
            '<div class="tl-c-right">'+
              '<span class="tl-rp" data-act="rp"><span class="box"><svg viewBox="0 0 24 24" fill="none" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M5 13l4 4L19 7"/></svg></span>RP</span>'+
              '<span class="tl-chev"><svg viewBox="0 0 24 24" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M6 9l6 6 6-6"/></svg></span>'+
            '</div>'+
          '</div>'+
          '<div class="tl-detail"><div class="tl-detail-in">'+
            '<div class="tl-desc">'+esc(e.detail)+'</div>'+
            renderPoints(e.points)+
            optsHtml+
          '</div></div>'+
        '</div>';
      track.appendChild(ev);
    });
    updateProgress();
    // 依次丝滑浮现
    var evs=track.querySelectorAll('.tl-event');
    for(var i=0;i<evs.length;i++){
      (function(el,delay){ setTimeout(function(){ el.classList.add('revealed'); }, delay); })(evs[i], 120*i+80);
    }
  }

  /* ── 进度 ── */
  function needChoiceCount(){ return events.filter(function(e){ return !e.trivial; }).length; }
  function chosenCount(){ return events.filter(function(e){ return !e.trivial && e.choice; }).length; }
  function updateProgress(){
    var need=needChoiceCount(), done=chosenCount();
    $('tl-progress').innerHTML='已选择 <strong>'+done+'</strong> / '+need+' · RP '+events.filter(function(e){return e.rp;}).length;
  }

  /* ── 交互 ── */
  function toggleExpand(ev){ ev.classList.toggle('expanded'); }
  function selectOption(idx, optEl){
    var e=events[idx];
    var opts=optEl.parentElement.querySelectorAll('.tl-opt');
    for(var i=0;i<opts.length;i++) opts[i].classList.remove('sel');
    optEl.classList.add('sel');
    e.choice=optEl.getAttribute('data-key');
    var isCustom=optEl.getAttribute('data-custom')==='1';
    var customBox=optEl.parentElement.parentElement.querySelector('.tl-custom');
    if(customBox) customBox.classList.toggle('show', isCustom);
    updateProgress();
  }
  function toggleRP(idx, rpEl){
    var e=events[idx]; e.rp=!e.rp; rpEl.classList.toggle('on', e.rp);
    updateProgress();
  }

  function bind(){
    var track=$('tl-track');
    track.addEventListener('click', function(ev){
      var evEl=ev.target.closest('.tl-event'); if(!evEl) return;
      var idx=parseInt(evEl.getAttribute('data-idx'),10);
      var rp=ev.target.closest('[data-act="rp"]');
      if(rp){ ev.stopPropagation(); toggleRP(idx, rp); return; }
      var opt=ev.target.closest('.tl-opt');
      if(opt){ selectOption(idx, opt); return; }
      if(ev.target.closest('textarea')) return;
      var head=ev.target.closest('[data-act="toggle"]');
      if(head){ toggleExpand(evEl); return; }
    });
    track.addEventListener('input', function(ev){
      var ta=ev.target.closest('.tl-custom textarea'); if(!ta) return;
      var evEl=ev.target.closest('.tl-event'); var idx=parseInt(evEl.getAttribute('data-idx'),10);
      events[idx].custom=ta.value;
    });
    $('tl-toggle-all').addEventListener('click', function(){
      var evs=track.querySelectorAll('.tl-event');
      var anyClosed=false; for(var i=0;i<evs.length;i++){ if(!evs[i].classList.contains('expanded')) anyClosed=true; }
      for(var j=0;j<evs.length;j++){ evs[j].classList.toggle('expanded', anyClosed); }
      this.textContent=anyClosed?'全部收起':'全部展开';
    });
    $('tl-settle').addEventListener('click', onSettle);
  }

  /* ── 结算提交 ── */
  function buildSettlementText(){
    var L=['[EVENT_SETTLEMENT]'];
    events.forEach(function(e){
      if(e.trivial){
        L.push(e.id+'-自动-琐碎事件自动结算-否');
      }else{
        var optText='';
        var picked=null;
        for(var i=0;i<e.options.length;i++){ if(e.options[i].key===e.choice){ picked=e.options[i]; break; } }
        if(e.choice==='D' || (picked && /自定义|自行输入/.test(picked.text))){
          optText='自定义：'+(e.custom||'（玩家未填写，自由发挥）');
        }else if(picked){
          optText=picked.text;
        }
        L.push(e.id+'-'+e.choice+'-'+optText+'-'+(e.rp?'RP':'否'));
      }
    });
    L.push('');
    L.push('请根据以上选择结算所有事件的属性/关系变动，按结算格式输出，并据 RP 标记决定是否进入小剧场。');
    return L.join('\n');
  }
  function setSettle(txt,cls,disabled){
    var b=$('tl-settle'); b.disabled=!!disabled; b.className='tl-btn primary'+(cls?' '+cls:'');
    b.innerHTML=esc(txt)+(cls==='done'
      ?' <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><path d="M5 13l4 4L19 7"/></svg>'
      :(!cls?' <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14"/><path d="M13 6l6 6-6 6"/></svg>':''));
  }
  function onSettle(){
    var need=needChoiceCount(), done=chosenCount();
    if(done<need){
      // 展开并滚动到第一个未选择事件
      for(var i=0;i<events.length;i++){
        if(!events[i].trivial && !events[i].choice){
          var el=$('tl-track').querySelectorAll('.tl-event')[i];
          el.classList.add('expanded');
          el.scrollIntoView({behavior:'smooth', block:'center'});
          break;
        }
      }
      toast('还有 '+(need-done)+' 个事件未做选择','warn');
      return;
    }
    var text=buildSettlementText();
    if(typeof createChatMessages==='undefined'){
      toast('未在酒馆环境，已在控制台打印结算','warn');
      console.log('[事件结算]\n'+text);
      return;
    }
    setSettle('结算中…','',true);
    var existingData;
    Promise.resolve()
      .then(function(){ if(typeof waitGlobalInitialized==='function' && typeof Mvu!=='undefined') return waitGlobalInitialized('Mvu'); })
      .then(function(){
        if(typeof Mvu!=='undefined' && Mvu.getMvuData) existingData=Mvu.getMvuData({type:'message',message_id:'latest'})||{};
        return createChatMessages([{role:'user', message:text, data:existingData}], {refresh:'all'});
      })
      .then(function(){
        setSettle('已进入结算','done',true);
        toast('选择已提交 · 结算中','ok');
        return generate({ user_input:'', should_stream:true });
      })
      .then(function(aiReply){
        if(aiReply==null) return null;
        return createChatMessages([{role:'assistant', message:String(aiReply), data:existingData}], {refresh:'all'});
      })
      .catch(function(err){
        console.error('[事件结算] 失败:',err);
        setSettle('提交失败 · 重试','err',false);
        toast('提交失败，请重试','warn');
      });
  }

  /* ── 初始化 ── */
  function init(){
    events=parseEvents();
    if(events.length){
