<script>
(function(){
  'use strict';
  function $(id){ return document.getElementById(id); }
  function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  var toastTimer=null;
  function toast(msg,kind){ var t=$('ls-toast'); if(!t)return; t.className='ls-toast show'+(kind?' '+kind:''); t.textContent=msg; if(toastTimer)clearTimeout(toastTimer); toastTimer=setTimeout(function(){t.className='ls-toast';},2200); }

  var SECTION_MAP={
    '人生概览':'Overview','属性巅峰':'Peak Stats','寿命等级':'Lifespan',
    '人生大事年表':'Chronicle','关系统计':'Bonds','声望收尾':'Fame',
    '物品归宿':'Legacy Items','难度回顾':'Difficulty','天赋评价':'Talents',
    '天赋/缺陷评价':'Talents','总评':'Verdict','上帝之手使用记录':'God Hand',
    '成就':'Achievements','成就·里程碑·称号':'Milestones','继承选项':'Inherit'
  };

  function parseContent(){
    var holder=$('ls-data');
    var raw=holder?holder.innerHTML:'';
    var probe=document.createElement('div'); probe.innerHTML=raw;
    return probe.textContent.trim();
  }

  function renderSections(text){
    var body=$('ls-body');
    var sections=text.split(/\*\*([^*]+)\*\*/);
    if(sections.length<3){
      body.innerHTML='<div class="ls-block">'+esc(text).replace(/\n/g,'<br>')+'</div>';
      return;
    }
    var html='';
    for(var i=1;i<sections.length;i+=2){
      var title=sections[i].trim();
      var content=(sections[i+1]||'').trim();
      var en=SECTION_MAP[title]||'';
      html+='<section>';
      html+='<div class="ls-sec-cap"><h3>'+esc(title)+'</h3>'+(en?'<span class="en">'+en+'</span>':'')+'</div>';
      if(title==='总评'){
        var lines=content.split('\n');
        var grade=''; var verdict=''; var rest=[];
        for(var j=0;j<lines.length;j++){
          var l=lines[j].trim();
          if(!l) continue;
          var gm=l.match(/总评等级[:：]\s*(.+)/);
          if(gm){ grade=gm[1]; continue; }
          var vm=l.match(/一句话总评[:：]\s*(.+)/);
          if(vm){ verdict=vm[1]; continue; }
          rest.push(l);
        }
        html+='<div class="ls-block">';
        if(rest.length) html+='<p>'+rest.map(esc).join('<br>')+'</p>';
        if(grade) html+='<div class="ls-grade">'+esc(grade)+'</div>';
        if(verdict) html+='<div class="ls-quote"><p>'+esc(verdict)+'</p></div>';
        html+='</div>';
      }else if(title==='人生大事年表'){
        html+='<div class="ls-timeline">';
        var lines=content.split('\n');
        for(var j=0;j<lines.length;j++){
          var l=lines[j].trim();
          if(!l) continue;
          var ym=l.match(/^(\d{4})\s*年?\s*[:：\-—]\s*(.+)/);
          if(ym){
            html+='<div class="ls-tl-row"><span class="ls-tl-year">'+esc(ym[1])+'</span><span class="ls-tl-text">'+esc(ym[2])+'</span></div>';
          }else{
            html+='<div class="ls-tl-row"><span class="ls-tl-text" style="padding-left:4em;">'+esc(l)+'</span></div>';
          }
        }
        html+='</div>';
      }else{
        html+='<div class="ls-block">'+esc(content).replace(/\n/g,'<br>')+'</div>';
      }
      html+='</section>';
    }
    body.innerHTML=html;
  }

  window.restartLife=function(){
    var btn=$('ls-restart');
    btn.disabled=true; btn.textContent='重开中…';
    toast('准备全新人生','ok');
    console.log('[SUMMARY] restart requested');
    if(typeof window.parent!=='undefined' && typeof window.parent.triggerSlash==='function'){
      window.parent.triggerSlash('/newchat');
    }else if(typeof triggerSlash==='function'){
      triggerSlash('/newchat');
    }else{
      toast('请手动新建聊天','warn');
      btn.disabled=false; btn.textContent='全新重开';
    }
  };

  function init(){
    var text=parseContent();
    if(!text) text='人生的故事已经写完。';
    var nm=text.match(/姓名[:：\s]*(\S+)/);
    if(nm) $('ls-name').textContent=nm[1];
    renderSections(text);
  }

  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',init); else init();
})();
</script>
