    return { ok:false, msg:'引擎未就绪（' + name + '）' };
  }
  function $(id){ return document.getElementById(id); }
  function esc(s){ return String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }

  var state = { packs:[], search:'', selectedTags:[], confirmId:'', confirmClear:false, _ct:null, _cct:null };
  var toastTimer = null;
  function toast(msg, kind){ var t = $('mp-toast'); if(!t) return; t.className = 'mp-toast show' + (kind ? ' ' + kind : ''); t.textContent = msg; if(toastTimer) clearTimeout(toastTimer); toastTimer = setTimeout(function(){ t.className = 'mp-toast'; }, 2100); }

  function setList(r){ if (Array.isArray(r)) state.packs = r; else if (r && Array.isArray(r.list)) state.packs = r.list; render(); }
  function refresh(){ var r = call('LIFE_MODPACK_LIST'); setList(Array.isArray(r) ? r : (r && r.list) || []); }
  function findPack(id){ for (var i=0;i<state.packs.length;i++){ if(state.packs[i].pack_id===id) return state.packs[i]; } return null; }

