    var tg = (p.tags||[]).map(function(t){ var on=state.selectedTags.indexOf(t)>=0; return '<span class="mp-chip'+(on?' on':'')+'" data-act="tag" data-tag="'+esc(t)+'">'+esc(t)+'</span>'; }).join('');
