      + '<div class="mp-card-top"><span class="mp-pid">'+esc(p.pack_id)+'</span>'
      + (p.namespace ? '<span class="mp-ns">· '+esc(p.namespace)+'</span>' : '')
      + '<span class="mp-status '+st[0]+'">'+st[1]+'</span></div>'
      + (tg ? '<div class="mp-card-tags">'+tg+'</div>' : '')
      + '<div class="mp-card-foot"><span class="mp-meta">'+(p.count||0)+' 个事件</span>'
      + '<div class="mp-card-btns">'
      + '<button class="mp-btn sm" type="button" data-act="toggle" data-id="'+esc(p.pack_id)+'">'+(p.enabled?'停用':'启用')+'</button>'
      + '<button class="mp-btn sm warn" type="button" data-act="remove" data-id="'+esc(p.pack_id)+'">'+del+'</button>'
