  function renderCount(){ var m=state.packs.filter(function(p){return p.mounted;}).length; $('mp-count').innerHTML = '<b>'+m+'</b> / '+state.packs.length; var c=$('mp-clear'); if(c) c.textContent = state.confirmClear ? '确认清空?' : '清空全部'; }
  function render(){ renderCount(); renderTagbar(); renderList(); }

