.sc-ap-title::before { content:'\26A1'; font-size:13px; }
.sc-ap-nums { margin-left:auto; font-size:var(--fs-xs); color:var(--ink-mute); letter-spacing:.04em; }
.sc-ap-nums strong { font-family:var(--ff-serif); font-size:var(--fs-md); color:var(--ink); }
.sc-ap-nums strong.neg { color:var(--warn); }
.sc-ap-nums strong.zero { color:var(--ink-mute); }
.sc-ap-track { display:flex; flex-wrap:wrap; gap:4px; align-items:center; min-height:14px; }
.sc-ap-pip { width:14px; height:14px; border:1.5px solid var(--line-mid); background:var(--bg-input); box-sizing:border-box; transition:background .12s,border-color .12s; }
.sc-ap-pip.avail { border-color:var(--line); background:var(--bg-card); }
.sc-ap-pip.spent { border-color:var(--line); background:var(--ink); }
.sc-ap-pip.spent.over { background:var(--warn); border-color:var(--warn); }
.sc-ap-pip.lock { border-style:dashed; border-color:var(--line-soft); background:transparent; opacity:.7; }
.sc-ap-meter { display:flex; width:100%; height:12px; border:1.5px solid var(--line); background:var(--bg-input); overflow:hidden; }
