/* ── 行动子卡槽 + 加号 ── */
.sc-act-zones { display:flex; flex-direction:column; gap:7px; }
.sc-act-item { border:1px solid var(--line-soft); background:var(--bg-sub); padding:6px; display:flex; flex-direction:column; gap:5px; }
.sc-act-no { display:flex; align-items:center; gap:6px; font-family:var(--ff-sans); font-size:9px; font-weight:700; letter-spacing:.12em; color:var(--ink-mute); }
.sc-act-no .cost { color:var(--ink-soft); }
.sc-act-no .sc-act-item-x { margin-left:auto; width:15px; height:15px; display:inline-flex; align-items:center; justify-content:center; border-radius:50%; cursor:pointer; }
.sc-act-no .sc-act-item-x:hover { background:var(--accent); } .sc-act-no .sc-act-item-x:hover svg{ stroke:var(--accent-ink); }
.sc-act-no .sc-act-item-x svg { width:9px; height:9px; stroke:var(--ink); stroke-width:2.6; }
.sc-z-cost { flex:0 0 auto; font-size:9px; font-weight:700; color:var(--ink-soft); padding:0 3px; }
.sc-add-act { display:inline-flex; align-items:center; justify-content:center; gap:5px; width:100%; min-height:26px; padding:2px 8px; background:transparent; border:1px dashed var(--line-mid); color:var(--ink-mute); font-family:var(--ff-sans); font-size:9px; letter-spacing:.12em; cursor:pointer; transition:background .12s,color .12s,border-color .12s; }
.sc-add-act:hover { background:var(--ink); color:var(--accent-ink); border-color:var(--ink); border-style:solid; }
.sc-add-act .sc-add-act-ico { display:inline-flex; }
.sc-add-act .sc-add-act-ico svg { width:11px; height:11px; stroke:currentColor; display:block; }
.sc-slot-ap { margin-left:auto; font-size:9px; font-weight:700; color:var(--ink-mute); letter-spacing:.05em; }
.sc-zone.filled.act { gap:5px; }

/* ── 时间粒度 tab ── */
.sc-grain-bar { display:flex; align-items:center; gap:var(--sp-sm); padding:var(--sp-md) var(--sp-lg); border-bottom:1px solid var(--line-mid); flex-wrap:wrap; }
.sc-grain-label { font-size:var(--fs-sm); letter-spacing:0.16em; color:var(--ink-soft); }
.sc-grain-tabs { display:inline-flex; border:1.5px solid var(--line); }
.sc-grain-tab { min-width:46px; min-height:34px; padding:0 var(--sp-md); background:var(--bg-card); border:none; border-right:1px solid var(--line); color:var(--ink-soft); font-family:var(--ff-serif); font-size:var(--fs-sm); font-weight:700; letter-spacing:0.1em; cursor:pointer; touch-action:manipulation; transition:background .15s,color .15s; }
.sc-grain-tab:last-child { border-right:none; }
.sc-grain-tab.active { background:var(--accent); color:var(--accent-ink); }
.sc-grain-note { margin-left:auto; font-size:var(--fs-xs); color:var(--ink-mute); }

/* ── ��体双栏 ── */
.sc-body { display:grid; grid-template-columns:1fr clamp(220px,32%,300px); gap:0; }
.sc-slots-wrap { padding:var(--sp-lg); border-right:1px solid var(--line-mid); min-width:0; }
.sc-palette-wrap { padding:var(--sp-md); background:var(--bg-sub); min-width:0; }
@media (max-width:680px){ .sc-body{ grid-template-columns:1fr; } .sc-slots-wrap{ border-right:none; border-bottom:1px solid var(--line-mid); } }

.sc-sec-cap { display:flex; align-items:baseline; gap:var(--sp-sm); margin-bottom:var(--sp-md); padding-bottom:6px; border-bottom:1.5px solid var(--line); }
.sc-sec-cap h3 { font-family:var(--ff-serif); font-size:var(--fs-md); letter-spacing:0.14em; }
.sc-sec-cap .en { margin-left:auto; font-size:var(--fs-xs); letter-spacing:0.3em; color:var(--ink-mute); text-transform:uppercase; }

/* ── 卡槽 ── */
.sc-slots { display:grid; grid-template-columns:repeat(auto-fill,minmax(min(150px,100%),1fr)); gap:var(--sp-sm); }
.sc-slot { border:1px solid var(--line); background:var(--bg-card); display:flex; flex-direction:column; }
.sc-slot-head { display:flex; align-items:center; gap:6px; padding:6px var(--sp-sm); border-bottom:1px solid var(--line-soft); background:var(--bg-sub); }
.sc-slot-no { font-family:var(--ff-serif); font-weight:800; font-size:var(--fs-sm); color:var(--ink-mute); min-width:1.6em; }
.sc-slot-name { font-size:var(--fs-sm); letter-spacing:0.08em; font-weight:600; }
.sc-slot-body { padding:var(--sp-sm); display:flex; flex-direction:column; gap:5px; }
.sc-zone { min-height:30px; border:1px dashed var(--line-mid); display:flex; align-items:center; gap:5px; padding:4px 7px; font-size:var(--fs-xs); color:var(--ink-mute); cursor:pointer; transition:background .12s,border-color .12s; background:var(--bg-input); }
.sc-zone:hover { border-color:var(--line); }
.sc-zone.droppable { border-color:var(--accent); border-style:solid; background:rgba(21,19,14,0.05); }
.sc-zone.dragover { background:rgba(21,19,14,0.12); border-color:var(--accent); }
.sc-zone .sc-z-ico { width:13px; height:13px; flex:0 0 auto; opacity:.6; }
.sc-zone .sc-z-ico svg { width:13px; height:13px; display:block; stroke:var(--ink); }
.sc-zone.filled { color:var(--ink); border-style:solid; border-color:var(--line-mid); justify-content:space-between; }
.sc-zone.filled.act { background:var(--bg-chip); border-color:var(--line); font-weight:600; }
.sc-z-text { overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
.sc-z-x { flex:0 0 auto; width:16px; height:16px; display:inline-flex; align-items:center; justify-content:center; border-radius:50%; cursor:pointer; }
.sc-z-x:hover { background:var(--accent); } .sc-z-x:hover svg{ stroke:var(--accent-ink); }
.sc-z-x svg { width:9px; height:9px; stroke:var(--ink); stroke-width:2.6; }
.sc-zone-mini-row { display:flex; flex-direction:column; gap:5px; }

/* ── 卡片面板 ── */
.sc-tabs { display:flex; border:1px solid var(--line); margin-bottom:var(--sp-sm); }
.sc-tab { flex:1; min-height:34px; background:var(--bg-card); border:none; border-right:1px solid var(--line); color:var(--ink-soft); font-family:var(--ff-sans); font-size:var(--fs-sm); letter-spacing:0.06em; cursor:pointer; touch-action:manipulation; }
.sc-tab:last-child{ border-right:none; } .sc-tab.active{ background:var(--accent); color:var(--accent-ink); }
.sc-cards { display:flex; flex-direction:column; gap:6px; max-height:min(46vh,420px); overflow-y:auto; -webkit-overflow-scrolling:touch; overscroll-behavior:contain; padding-right:2px; }
.sc-card { display:flex; align-items:flex-start; gap:8px; padding:8px var(--sp-sm); background:var(--bg-card); border:1px solid var(--line); cursor:grab; user-select:none; touch-action:manipulation; transition:transform .08s,background .12s,box-shadow .12s; width:100%; min-width:0; max-width:100%; box-sizing:border-box; }
.sc-card:hover { background:var(--bg-chip); }
.sc-card:active { cursor:grabbing; }
.sc-card.picked { background:var(--accent); color:var(--accent-ink); box-shadow:3px 3px 0 var(--line-mid); }
.sc-card.picked .sc-card-ico svg{ stroke:var(--accent-ink); }
.sc-card.picked .sc-card-sub{ color:rgba(251,250,246,.7); }
.sc-card-ico { flex:0 0 auto; width:26px; height:26px; border:1px solid currentColor; display:flex; align-items:center; justify-content:center; border-radius:50%; }
.sc-card-ico svg{ width:15px; height:15px; stroke:var(--ink); fill:none; stroke-width:1.6; }
.sc-card-tx { flex:1 1 0; min-width:0; max-width:100%; display:flex; flex-direction:column; gap:1px; }
.sc-card-name { font-size:var(--fs-sm); font-weight:600; letter-spacing:0.04em; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
.sc-card-sub { font-size:10px; color:var(--ink-mute); white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
.sc-add-row { display:flex; gap:6px; margin-top:var(--sp-sm); flex-wrap:wrap; align-items:stretch; min-width:0; }
.sc-add-input { flex:1 1 0; min-width:0; min-height:34px; padding:6px 9px; background:var(--bg-input); border:1px solid var(--line-mid); color:var(--ink); font-family:var(--ff-sans); font-size:var(--fs-sm); outline:none; }
.sc-add-input:focus{ border-color:var(--line); }
.sc-add-btn { flex:0 0 auto; min-height:34px; padding:0 var(--sp-md); background:var(--bg-card); border:1px dashed var(--line); color:var(--ink-soft); font-family:var(--ff-sans); font-size:var(--fs-xs); letter-spacing:0.1em; cursor:pointer; touch-action:manipulation; }
.sc-add-btn:hover{ background:var(--accent); color:var(--accent-ink); border-style:solid; }
/* [NEW] 限定卡片容器宽度，防止被NPC标签撑爆 */
.sc-cards { width:100%; min-width:0; max-width:100%; box-sizing:border-box; }
/* [NEW] tab 行 + 垃圾桶按钮 */
.sc-tabs-wrap { display:flex; gap:6px; margin-bottom:var(--sp-sm); align-items:stretch; }
.sc-tabs-wrap .sc-tabs { flex:1 1 0; min-width:0; margin-bottom:0; }
.sc-trash-btn { flex:0 0 auto; min-width:36px; min-height:34px; padding:0 8px; background:var(--bg-card); border:1px solid var(--line); color:var(--ink-soft); cursor:pointer; display:inline-flex; align-items:center; justify-content:center; gap:4px; font-size:var(--fs-xs); letter-spacing:.08em; transition:background .12s,color .12s; position:relative; }
.sc-trash-btn:hover { background:var(--ink); color:var(--accent-ink); }
.sc-trash-btn svg { width:16px; height:16px; display:block; }
.sc-trash-num { font-family:var(--ff-serif); font-weight:700; font-size:9px; padding:0 4px; min-width:14px; height:14px; line-height:14px; display:inline-block; text-align:center; background:var(--warn); color:var(--accent-ink); border-radius:7px; }
.sc-trash-num.empty { display:none; }
/* [NEW] 回收站模态内容 */
.sc-trash-list { display:flex; flex-direction:column; gap:6px; }
/* [NEW] 回收站分类页签 */
.sc-trash-tabs { display:flex; gap:0; margin:0 0 var(--sp-sm) 0; border:1px solid var(--line); background:var(--bg-card); }
.sc-trash-tab { flex:1 1 0; padding:8px 6px; background:transparent; border:none; border-right:1px solid var(--line-soft); cursor:pointer; font-family:var(--ff-serif); font-size:var(--fs-xs); color:var(--ink-mute); letter-spacing:.16em; transition:background .12s,color .12s; }
.sc-trash-tab:last-child{ border-right:none; }
.sc-trash-tab:hover{ background:var(--bg-sub); color:var(--ink); }
.sc-trash-tab.active{ background:var(--ink); color:var(--accent-ink); font-weight:800; }
.sc-trash-tab .sc-trash-tab-num{ display:inline-block; min-width:18px; padding:0 5px; margin-left:6px; border-radius:9px; background:var(--bg-sub); color:var(--ink-mute); font-size:9px; line-height:14px; vertical-align:middle; }
.sc-trash-tab.active .sc-trash-tab-num{ background:var(--accent-ink); color:var(--ink); }
.sc-trash-sec-title { font-family:var(--ff-serif); font-size:var(--fs-sm); font-weight:800; letter-spacing:.14em; color:var(--ink-mute); padding:8px 0 4px; border-bottom:1px dashed var(--line-soft); }
.sc-trash-item { display:flex; align-items:center; gap:8px; padding:6px 8px; background:var(--bg-sub); border:1px solid var(--line-soft); }
.sc-trash-item .sc-trash-name { flex:1 1 0; min-width:0; font-size:var(--fs-sm); color:var(--ink); white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
.sc-trash-item .sc-trash-type { flex:0 0 auto; font-size:9px; padding:1px 5px; border:1px solid var(--line-mid); color:var(--ink-mute); letter-spacing:.1em; }
.sc-trash-item .sc-trash-restore { flex:0 0 auto; min-height:28px; padding:0 10px; background:var(--bg-card); border:1px solid var(--line); color:var(--ink); cursor:pointer; font-size:var(--fs-xs); letter-spacing:.1em; transition:background .12s,color .12s; }
.sc-trash-item .sc-trash-restore:hover { background:var(--ok); color:var(--accent-ink); border-color:var(--ok); }
/* [NEW] 彻底删除变量按钮（仅行动卡可用） */
.sc-trash-item .sc-trash-purge { flex:0 0 auto; min-height:28px; padding:0 10px; background:var(--bg-card); border:1px solid var(--warn); color:var(--warn); cursor:pointer; font-size:var(--fs-xs); letter-spacing:.1em; transition:background .12s,color .12s; }
.sc-trash-item .sc-trash-purge:hover { background:var(--warn); color:var(--accent-ink); }
.sc-trash-item .sc-trash-purge[disabled]{ opacity:.35; cursor:not-allowed; }
.sc-trash-note { padding:6px 8px; margin-top:4px; font-size:10px; color:var(--ink-mute); background:var(--bg-sub); border:1px dashed var(--line-soft); letter-spacing:.04em; }
.sc-trash-empty { padding:var(--sp-lg); text-align:center; color:var(--ink-mute); font-size:var(--fs-sm); }

/* ── 拾取提示 ── */
.sc-pickbar { display:none; align-items:center; gap:8px; margin-top:var(--sp-sm); padding:7px var(--sp-sm); border:1px dashed var(--line); background:var(--bg-chip); font-size:var(--fs-xs); color:var(--ink-soft); }
.sc-pickbar.show{ display:flex; }
.sc-pickbar strong{ color:var(--ink); }
.sc-pickbar .sc-pick-cancel{ margin-left:auto; cursor:pointer; text-decoration:underline; color:var(--ink-mute); }

/* ── 底部 ── */
.sc-foot { display:flex; align-items:center; justify-content:space-between; gap:var(--sp-md); padding:var(--sp-lg); border-top:2px solid var(--line); background:var(--bg-sub); flex-wrap:wrap; }
.sc-foot-tip { font-size:var(--fs-xs); color:var(--ink-mute); }
.sc-btns { display:flex; gap:var(--sp-sm); align-items:center; margin-left:auto; }
.sc-btn { min-height:46px; padding:0 var(--sp-lg); font-family:var(--ff-serif); font-size:var(--fs-md); font-weight:700; letter-spacing:0.14em; cursor:pointer; touch-action:manipulation; border:1.5px solid var(--line); background:var(--bg-card); color:var(--ink); transition:transform .08s,background .12s; }
.sc-btn:hover{ background:var(--bg-chip); } .sc-btn:active{ transform:translate(1px,1px); }
.sc-btn.primary { background:var(--accent); color:var(--accent-ink); box-shadow:4px 4px 0 var(--line-mid); display:inline-flex; align-items:center; gap:8px; }
.sc-btn.primary:hover{ background:var(--accent); transform:translate(-1px,-1px); box-shadow:5px 5px 0 var(--line-mid); }
.sc-btn.primary:disabled{ opacity:.6; cursor:progress; }
.sc-btn.primary svg{ width:17px; height:17px; }
.sc-btn.primary.done{ background:var(--bg-card); color:var(--ok); border-color:var(--ok); }
.sc-btn.primary.err{ background:var(--bg-card); color:var(--warn); border-color:var(--warn); }

/* ── toast ── */
.sc-toast { position:fixed; left:50%; bottom:calc(18px + var(--safe-bottom)); transform:translateX(-50%) translateY(20px); background:var(--accent); color:var(--accent-ink); border:1px solid var(--line); padding:10px 18px; font-size:var(--fs-sm); z-index:9999; opacity:0; pointer-events:none; transition:opacity .25s,transform .25s; max-width:82vw; text-align:center; }
.sc-toast.show{ opacity:1; transform:translateX(-50%) translateY(0); }
.sc-toast.warn{ background:var(--warn); } .sc-toast.ok{ background:var(--ok); }

/* ── 角色状态栏（只读 · 折叠可下拉 · sc- 编辑部风格） ── */
.sc-status { border-top:2px solid var(--line); background:var(--bg-sub); }
.sc-status-head { width:100%; min-height:48px; display:flex; align-items:center; gap:var(--sp-md); padding:var(--sp-md) var(--sp-lg); background:var(--bg-card); border:none; border-bottom:1px solid var(--line-mid); cursor:pointer; touch-action:manipulation; text-align:left; font-family:var(--ff-sans); color:var(--ink); }
.sc-status-head:hover { background:var(--bg-chip); }
.sc-status-ttl { display:inline-flex; align-items:center; gap:8px; font-family:var(--ff-serif); font-size:var(--fs-md); font-weight:800; letter-spacing:.14em; flex:0 0 auto; }
.sc-status-chev { display:inline-flex; transition:transform .2s; }
.sc-status-chev svg { width:14px; height:14px; stroke:var(--ink); }
.sc-status.open .sc-status-chev { transform:rotate(90deg); }
.sc-status-sub { margin-left:auto; font-size:var(--fs-xs); color:var(--ink-mute); letter-spacing:.04em; text-align:right; max-width:56%; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
.sc-status-body { display:none; padding:var(--sp-md) var(--sp-lg) var(--sp-lg); }
.sc-status.open .sc-status-body { display:block; }
.sc-st-grid { display:grid; grid-template-columns:repeat(auto-fit,minmax(min(270px,100%),1fr)); gap:var(--sp-md); align-items:start; }
.sc-st-sec { border:1px solid var(--line-soft); background:var(--bg-card); padding:var(--sp-sm) var(--sp-md) var(--sp-md); min-width:0; }
.sc-st-sec-h { width:100%; font-family:var(--ff-serif); font-size:var(--fs-sm); font-weight:800; letter-spacing:.16em; color:var(--ink); padding:2px 0 6px; margin-bottom:5px; border:none; border-bottom:1.5px solid var(--line); display:flex; align-items:center; gap:6px; background:none; cursor:pointer; touch-action:manipulation; text-align:left; }
.sc-st-sec-h:hover { color:var(--ink-soft); }
.sc-st-sec-h .en { margin-left:auto; font-size:9px; letter-spacing:.24em; color:var(--ink-mute); text-transform:uppercase; }
.sc-st-sec-chev { display:inline-flex; flex:0 0 auto; transition:transform .2s; }
.sc-st-sec-chev svg { width:12px; height:12px; stroke:var(--ink); }
.sc-st-sec.open .sc-st-sec-chev { transform:rotate(90deg); }
.sc-st-sec-b { display:none; }
.sc-st-sec.open .sc-st-sec-b { display:block; }
.sc-st-row { display:flex; align-items:center; gap:10px; padding:3px 0; border-bottom:1px dashed var(--line-soft); font-size:var(--fs-sm); min-width:0; }
.sc-st-row:last-child { border-bottom:none; }
.sc-st-k { flex:0 0 78px; color:var(--ink-mute); letter-spacing:.06em; }
.sc-st-v { flex:1 1 0; min-width:0; color:var(--ink); word-break:break-word; }
.sc-st-row.bar .sc-st-v { display:flex; align-items:center; gap:8px; }
.sc-st-bar { position:relative; flex:1 1 0; min-width:40px; height:7px; background:var(--line-soft); overflow:hidden; }
.sc-st-bar-fill { position:absolute; top:0; height:100%; }
.sc-st-bar-fill.pos { background:var(--ink); left:0; }
.sc-st-bar-fill.neg { background:var(--warn); }
.sc-st-bar-num { flex:0 0 auto; font-size:9px; color:var(--ink-mute); white-space:nowrap; font-family:var(--ff-serif); }
.sc-st-chips { display:flex; flex-wrap:wrap; gap:4px; }
.sc-st-empty { font-size:var(--fs-xs); color:var(--ink-mute); padding:4px 0; }
.sc-st-item { display:flex; align-items:center; gap:8px; padding:3px 0; border-bottom:1px dashed var(--line-soft); font-size:var(--fs-sm); min-width:0; }
.sc-st-item:last-child { border-bottom:none; }
.sc-st-item-name { flex:0 0 auto; font-weight:600; color:var(--ink); max-width:48%; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
.sc-st-item-meta { flex:1 1 0; min-width:0; text-align:right; color:var(--ink-mute); font-size:var(--fs-xs); overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
.sc-st-sub { min-width:0; margin-top:6px; }
