<script>
(function () {
  'use strict';

  /* ===== 工具 ===== */
  function $(id){ return document.getElementById(id); }
  function ce(tag,cls){ var e=document.createElement(tag); if(cls)e.className=cls; return e; }
  function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  var toastTimer=null;
  function toast(msg,kind){ var t=$('sc-toast'); if(!t)return; t.className='sc-toast show'+(kind?' '+kind:''); t.textContent=msg; if(toastTimer)clearTimeout(toastTimer); toastTimer=setTimeout(function(){t.className='sc-toast';},1900); }
  // ST 文本转义（防管道/花括号截断）
  function escST(str){ if(typeof str!=='string')return str; return str.replace(/(\\+)?([|{}])/g,function(m,s,c){ s=s||''; return s+s+'\\'+c; }); }

  /* ===== 默认数据 ===== */
  // 行动卡按人生阶段
  var STAGE_ACTIONS = {
    '婴幼儿':['学习爬行','咿呀学语','与家人互动','安睡休息','玩耍探索','听儿歌'],
    '学龄前':['学习知识','户外探索','与家人互动','阅读绘本','艺术启蒙','休息睡觉'],
    '小学生':['上学读书','完成作业','课外补习','和同学玩耍','运动锻炼','看课外书','帮忙做家务','发展兴趣'],
    '中学生':['上课学习','刷题备考','社团活动','和朋友出游','打游戏放松','运动锻炼','偷偷早恋','课外阅读'],
    '大学生':['上课听讲','泡图书馆','社团/学生会','兼职打工','约会恋爱','结伴旅行','打游戏','尝试创业'],
    '成年':['投入工作','加班奋斗','相亲约会','陪伴家人','健身运动','进修充电','投资理财','社交应酬','外出旅行','经营副业','看病休养','发展爱好']
  };
  var STAGE_EN = { '婴幼儿':'Infant','学龄前':'Preschool','小学生':'Primary','中学生':'Middle','大学生':'College','成年':'Adult' };
  var DEFAULT_LOCATIONS = ['家','学校','公司','商业区','公园','医院','朋友家'];
  var DEFAULT_NPCS = ['父亲','母亲','同学','朋友','同事'];
  var DEFAULT_ITEMS = ['现金','手机','钥匙','水杯'];

  // 时间粒度 → 卡槽
  function slotsFor(grain){
    if(grain==='年') return ['1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月'];
    if(grain==='月') return ['第一周','第二周','第三周','第四周'];
    if(grain==='周') return ['周一','周二','周三','周四','周五','周六','周日'];
    return ['清晨','上午','午间','下午','夜晚'];
  }
  function ageToStage(age){
    age=Number(age)||0;
    if(age<=2)return '婴幼儿'; if(age<=5)return '学龄前'; if(age<=11)return '小学生';
    if(age<=17)return '中学生'; if(age<=22)return '大学生'; return '成年';
  }

  /* ===== 状态 ===== */
  var state = {
    grain:'月', stage:'成年', age:0, name:'主角',
    slotStore:{},             // grain -> { slotName -> {actions:[...],location,npc} }（各粒度独立留存）
    slots:{},                 // 指向当前粒度的卡槽对象
    picked:null,              // {type, value}
    tab:'action',
    customs:{ action:[], location:[], npc:[], item:[] },
    removed:{ action:[], location:[], npc:[], item:[] },   // 被删除的卡片（隐藏默认项 / 移除自定义项）
    combos:[],                                    // 组合���忆（内存权威源）
    actions:[], locations:[], npcs:[], items:[],
    ap:{ cur:0, cap:0 },                          // 行动点（读 主角.行动点）
    actionCost:{},                                // 行动名 → 行动点消耗（读 ��动卡库）
    season:'', climate:''                         // 季节 / 派生气候（实时读变量，不按日期推断）
  };
  function grainSlots(g){ if(!state.slotStore[g]) state.slotStore[g]={}; return state.slotStore[g]; }

  /* ===== MVU 访问工具：跨 iframe 作用域 + 元组解包 ===== */
  function findGlobal(name){
    var scopes=[];
    try{ scopes.push(window); }catch(e){}
    try{ if(window.parent && window.parent!==window) scopes.push(window.parent); }catch(e){}
    try{ if(window.top && window.top!==window.parent && window.top!==window) scopes.push(window.top); }catch(e){}
    for(var i=0;i<scopes.length;i++){
      try{ var v=scopes[i] && scopes[i][name]; if(v!=null) return v; }catch(e){}
    }
    return null;
  }
  function findMvu(){ var m=findGlobal('Mvu'); return (m && typeof m.getMvuData==='function') ? m : null; }
  function isMvuTuple(v){ return Array.isArray(v) && v.length===2 && typeof v[1]==='string'; }
  function unwrapMvu(v){
    if(isMvuTuple(v)) return unwrapMvu(v[0]);
    if(Array.isArray(v)){ var a=[]; for(var i=0;i<v.length;i++) a.push(unwrapMvu(v[i])); return a; }
    if(v && typeof v==='object'){ var out={}; for(var k in v){ if(Object.prototype.hasOwnProperty.call(v,k)) out[k]=unwrapMvu(v[k]); } return out; }
    return v;
  }
  function setLeaf(root, path, value){
    if(!root || !path || !path.length) return false;
    var node=root;
    for(var i=0;i<path.length-1;i++){
      var k=path[i];
      if(node[k]==null) node[k]={};
      if(isMvuTuple(node[k])){
        if(node[k][0]==null || typeof node[k][0]!=='object') node[k][0]={};
        node=node[k][0];
      } else {
        if(typeof node[k]!=='object') node[k]={};
        node=node[k];
      }
    }
    var last=path[path.length-1];
    if(isMvuTuple(node[last])) node[last][0]=value;
    else node[last]=value;
    return true;
  }

  /* ===== 读取 MVU（多作用域 + 自动解包；无酒馆环境则回退 mock） ===== */
  // [BUGFIX] 优先读 stat_data���最新写入的原始变量），display_data 仅作兜底；
  // 原本 `display_data || stat_data` 的问题：空对象 {} 亦为 truthy，会返回空变量表导致“只显示默认内容”。
  function isMeaningful(x){
    if(!x) return false;
    if(typeof x!=='object') return false;
    if(Array.isArray(x)) return x.length>0;
    return Object.keys(x).length>0;
  }
  function readStat(){
    try{
      var mvu=findMvu();
      if(mvu){
        // 1) 优先从 latest 消息读 stat_data
        var d=mvu.getMvuData({type:'message', message_id:'latest'}) || {};
        var raw=d.stat_data || d.display_data;
        if(isMeaningful(raw)) return unwrapMvu(raw)||{};
        // 2) 兜底：chat 级数据
        d=mvu.getMvuData({type:'chat'}) || {};
        raw=d.stat_data || d.display_data;
        if(isMeaningful(raw)) return unwrapMvu(raw)||{};
        // 3) 再兜底：指定 message_id:0
