        if(out.indexOf(name)<0) out.push(name);
        state.locMeta[name]=v;
      });
    }else{
      keys.forEach(function(area){
        var sub=map[area];
        if(sub && typeof sub==='object'){
          Object.keys(sub).forEach(function(loc){
            var disp=area+'·'+loc; out.push(disp);
            var m=(sub[loc]&&typeof sub[loc]==='object')?sub[loc]:{};
            m=Object.assign({}, m); if(m.所属区域==null) m.所属区域=area;
            state.locMeta[disp]=m;
          });
        }else{ out.push(area); state.locMeta[area]={}; }
      });
    }
    if(out.length===0){ out=DEFAULT_LOCATIONS.slice(); out.forEach(function(n){ state.locMeta[n]={}; }); }
    return out;
  }
