  // 行动点消耗表：读自 行动卡库（名称/键 → 行动点消耗，缺省 1）
  function collectActionCosts(stat){
    var m={};
    function addCosts(o){ if(!o||typeof o!=='object') return; Object.keys(o).forEach(function(k){ var v=o[k]; if(!v||typeof v!=='object'){ m[k]=1; return; } var raw=(v.行动点消耗!=null)?v.行动点消耗:v.消耗行动点; var c=(raw==null)?1:Number(raw); if(isNaN(c)) c=1; m[v.名称||k]=c; m[k]=c; }); }
    var GR=['年','季','月','周','日'];
    var pool=stat&&stat.行动卡片池;
    if(pool&&typeof pool==='object'){
      var nested=Object.keys(pool).some(function(k){ return GR.indexOf(k)>=0; });
      if(nested){ GR.forEach(function(g){ addCosts(pool[g]); }); addCosts(pool['通用']); addCosts(pool['全部']); }
