  // 过滤：① 适用年龄段（含当前 身份阶段/人生阶段 才显示；空=不限）② 行动卡库 适用粒度（含当前粒度才显示；空=不限）
  function actionAgeOk(v){
    var ages=v&&v.适用年龄段;
    if(!Array.isArray(ages)||!ages.length) return true;
    for(var i=0;i<ages.length;i++){ var a=String(ages[i]); if(a===state.stage||a==='全部'||a==='不限') return true; }
    return false;
