  function collectActions(stat){
    // 两遍式：先按 适用年龄段/适用粒度 过滤；若为空则去过滤兜底；仍为空则按人生阶段默认
    function gather(useFilter){
      var names=[], seen={};
      function add(nm){ nm=(nm==null?'':String(nm)).trim(); if(nm && !seen[nm]){ seen[nm]=1; names.push(nm); } }
      function addObj(o){ if(!o||typeof o!=='object') return; Object.keys(o).forEach(function(k){ var v=o[k]; if(useFilter && v&&typeof v==='object' && !actionAgeOk(v)) return; add(v&&typeof v==='object'&&v.名称?v.名称:k); }); }
      var GR=['年','季','月','周','日'];
      var pool=stat&&stat.行动卡片池;
      if(pool&&typeof pool==='object'){
        var nested=Object.keys(pool).some(function(k){ return GR.indexOf(k)>=0; });
        if(nested){ GR.forEach(function(g){ addObj(pool[g]); }); addObj(pool['通用']); addObj(pool['全部']); }
        else addObj(pool);
      }
      var lib=stat&&stat.行动卡库;
      if(lib&&typeof lib==='object'){ Object.keys(lib).forEach(function(k){ var v=lib[k]; if(useFilter && v&&typeof v==='object'){ if(!actionGrainOk(v)) return; if(!actionAgeOk(v)) return; } add(v&&typeof v==='object'&&v.名称?v.名称:k); }); }
      return names;
    }
    var n=gather(true);
    if(!n.length) n=gather(false);
    if(!n.length) n=(STAGE_ACTIONS[state.stage]||STAGE_ACTIONS['成年']).slice();
    return n;
  }
