  /* ===== 卡槽数据模型（行动支持多项） ===== */
  function normSlot(s){
    if(!s||typeof s!=='object') return {items:[{action:'',location:'',npc:'',item:''}]};
    // 迁移旧结构（每槽单一地点/同行 + 多行动）→ 每个行动独立绑定地点/同行/物品
    if(!Array.isArray(s.items)){
      var items=[];
      if(Array.isArray(s.actions)){
        var loc=s.location||'', np=s.npc||'', it0=s.item||'';
        s.actions.forEach(function(a){ items.push({action:a||'',location:loc,npc:np,item:it0}); });
      }else if(s.action!=null||s.location!=null||s.npc!=null||s.item!=null){
        items.push({action:s.action||'',location:s.location||'',npc:s.npc||'',item:s.item||''});
      }
      if(items.length===0) items=[{action:'',location:'',npc:'',item:''}];
      s={items:items};
    }
    if(!Array.isArray(s.items)||s.items.length===0) s.items=[{action:'',location:'',npc:'',item:''}];
    s.items=s.items.map(function(it){ it=(it&&typeof it==='object')?it:{}; return {action:it.action||'',location:it.location||'',npc:it.npc||'',item:it.item||''}; });
    return s;
  }
