      head.innerHTML='<span class="sc-slot-no">'+(i+1<10?'0':'')+(i+1)+'</span><span class="sc-slot-name">'+esc(name)+'</span>'+(sc>0?'<span class="sc-slot-ap" title="本格行动点消耗">⚡'+sc+'</span>':'');
      var body=ce('div','sc-slot-body');
      // 每个行动独立成组：行动 + 所需行动点 + 专属地点 + 专属同行
      var zones=ce('div','sc-act-zones');
      s.items.forEach(function(it,ai){
        var item=ce('div','sc-act-item'); item.setAttribute('data-aidx',ai);
        var no=ce('div','sc-act-no');
        no.innerHTML='<span>行动 '+(ai+1)+'</span>'+(it.action?'<span class="cost" title="所需行动点">⚡'+actionCost(it.action)+'</span>':'')+(s.items.length>1?'<span class="sc-act-item-x" data-slot="'+esc(name)+'" data-aidx="'+ai+'" title="移除该行动">'+xIco()+'</span>':'');
        item.appendChild(no);
        item.appendChild(zoneEl(name,'action',it.action,ai));
        var mini=ce('div','sc-zone-mini-row');
        mini.appendChild(zoneEl(name,'location',it.location,ai));
        mini.appendChild(zoneEl(name,'npc',it.npc,ai));
        mini.appendChild(zoneEl(name,'item',it.item,ai));
        item.appendChild(mini);
        zones.appendChild(item);
      });
      body.appendChild(zones);
      var add=ce('button','sc-add-act'); add.type='button'; add.setAttribute('data-slot',name);
      add.innerHTML='<span class="sc-add-act-ico">'+plusIco()+'</span>增加行动';
      body.appendChild(add);
      slot.appendChild(head); slot.appendChild(body);
      box.appendChild(slot);
    });
    refreshDroppableHints();
    renderAP();
  }
  function zoneEl(slotName,type,value,aidx){
    var z=ce('div','sc-zone'+(type==='action'?' act':'')+(value?' filled':''));
    z.setAttribute('data-slot',slotName); z.setAttribute('data-ztype',type);
    z.setAttribute('data-aidx', aidx==null?0:aidx);
    if(value){
      if(type==='action'){
        z.innerHTML='<span class="sc-z-ico">'+zoneIco('action')+'</span><span class="sc-z-text">'+esc(value)+'</span><span class="sc-z-cost">⚡'+actionCost(value)+'</span><span class="sc-z-x" data-x="1">'+xIco()+'</span>';
      }else{
        var eyeBtn=(type==='location'||type==='npc'||type==='item')?'<span class="sc-z-eye" data-eye="1" title="查看详情">'+eyeIco()+'</span>':'';
        z.innerHTML='<span class="sc-z-ico">'+zoneIco(type)+'</span><span class="sc-z-text">'+esc(value)+'</span>'+eyeBtn+'<span class="sc-z-x" data-x="1">'+xIco()+'</span>';
      }
    }else{
      var ph=type==='action'?'添加行动':type==='location'?'地点':type==='npc'?'同行':'物品';
      z.innerHTML='<span class="sc-z-ico">'+zoneIco(type)+'</span><span class="sc-z-text">'+ph+'</span>';
    }
    return z;
  }
  // 当有拾取卡片时，高亮对应类型的可放置区
  function refreshDroppableHints(){
    var zones=document.querySelectorAll('#sc-slots .sc-zone');
    for(var i=0;i<zones.length;i++){
      zones[i].classList.remove('droppable');
      if(state.picked && zones[i].getAttribute('data-ztype')===state.picked.type){ zones[i].classList.add('droppable'); }
    }
  }

  /* ===== 渲染卡片库 ===== */
  function poolFor(type){
    var base = type==='action'?state.actions : type==='location'?state.locations : type==='npc'?state.npcs : state.items;
    var all = base.concat(state.customs[type]||[]);
    var rm = state.removed[type]||[];
    return all.filter(function(n){ return rm.indexOf(n)<0; });
  }
  function currentCards(){ return poolFor(state.tab); }
  function renderCards(){
    var box=$('sc-cards'); box.innerHTML='';
    var list=currentCards();
    var sub = state.tab==='action'?('默认行动 · '+state.stage):state.tab==='location'?'来自地图变量':state.tab==='npc'?'来自 NPC 变量':'来自 主角.物品';
    list.forEach(function(name){
      var c=ce('div','sc-card');
      c.setAttribute('data-type',state.tab); c.setAttribute('data-value',name); c.setAttribute('draggable','true');
      if(state.picked && state.picked.type===state.tab && state.picked.value===name) c.classList.add('picked');
      var extra='';
      if(state.tab==='npc'){
        var nm=(state.npcMeta||{})[name]||{};
        var chips=[];
        if(nm.关系标签) chips.push('<span class="sc-tag-chip id">'+esc(nm.关系标签)+'</span>');
        if(nm.关系大类) chips.push('<span class="sc-tag-chip">'+esc(nm.关系大类)+'</span>');
        if(nm.重要等级) chips.push('<span class="sc-tag-chip">'+esc(nm.重要等级)+'</span>');
        if(chips.length) extra+='<div class="sc-card-tags">'+chips.join('')+'</div>';
        if(nm.好感度!=null && nm.好感度!=='') extra+=affinityBar(nm.好感度);
        c.setAttribute('title','双击查看角色详情');
      }else if(state.tab==='location'){
        var lm=(state.locMeta||{})[name]||{};
        var ltags=[];
        if(lm.类别) ltags.push(esc(lm.类别));
        if(lm.社交开放度) ltags.push('社交·'+esc(lm.社交开放度));
        if(lm.可达性) ltags.push(esc(lm.可达性));
        if(ltags.length) extra+='<div class="sc-card-tags">'+ltags.map(function(t){return '<span class="sc-tag-chip">'+t+'</span>';}).join('')+'</div>';
        c.setAttribute('title','双击查看地点详情');
      }else if(state.tab==='item'){
        var im=(state.itemMeta||{})[name]||{};
        var its=[];
        if(im.数量!=null && im.数量!=='') its.push('×'+esc(String(im.数量)));
        if(im.重要级别) its.push(esc(im.重要级别));
        if(im.类别) its.push(esc(im.类别));
        if(its.length) extra+='<div class="sc-card-tags">'+its.map(function(t){return '<span class="sc-tag-chip">'+t+'</span>';}).join('')+'</div>';
      }
      var acts='<span class="sc-card-acts">';
      if(state.tab==='npc'||state.tab==='location'||state.tab==='item') acts+='<button class="sc-card-detail" type="button" draggable="false" title="查看详情">详情</button>';
      acts+='<button class="sc-card-del" type="button" draggable="false" title="删除该卡片">×</button></span>';
      if(state.tab!=='action'){
        c.classList.add('sc-card--stack');
        c.innerHTML='<div class="sc-card-head"><span class="sc-card-ico">'+ico(state.tab)+'</span><span class="sc-card-name">'+esc(name)+'</span>'+acts+'</div><div class="sc-card-sub">'+esc(sub)+'</div>'+extra;
      }else{
        c.innerHTML='<span class="sc-card-ico">'+ico(state.tab)+'</span><span class="sc-card-tx"><span class="sc-card-name">'+esc(name)+'</span><span class="sc-card-sub">'+esc(sub)+'</span>'+extra+'</span>'+acts;
      }
      box.appendChild(c);
    });
    if(list.length===0){ box.innerHTML='<div style="font-size:var(--fs-xs);color:var(--ink-mute);padding:var(--sp-md);text-align:center;">暂无卡片，可在下方自定义添加</div>'; }
  }

  /* ===== 详情弹窗（双击卡片打开，全部读自变量） ===== */
  function fieldRow(k,v){
    if(v==null||v==='') return '';
    if(typeof k==='string' && k.indexOf('是否')===0){ var bn=Number(v); v=(v===true||v==='是'||(!isNaN(bn)&&bn>0))?'是':'否'; }
    else if(Array.isArray(v)) v=v.join('、');
    else if(typeof v==='object') v=JSON.stringify(v);
    return '<div class="sc-d-row"><span class="sc-d-k">'+esc(k)+'</span><span class="sc-d-v">'+esc(String(v))+'</span></div>';
  }
  // 带友好标签与固定顺序的已知字段；其余变量库字段自动补充展示
  var NPC_FIELDS=[['关系标签','关系/身份'],['关系大类','关系大类'],['重要等级','重要等级'],['身份','身份'],['性别','性别'],['年龄','年龄'],['性格','性格'],['外貌','外貌'],['背景','背景'],['印象标签','印象标签'],['关联地点','关联地点'],['备注','备注']];
  var LOC_FIELDS=[['类别','类别'],['所属区域','所属区域'],['社交开放度','社交开放度'],['危险度','危险度'],['可达性','可达性'],['意象标签','意象标签'],['情绪色彩','情绪色彩'],['是否已解锁','是否已解锁'],['备注','备注']];
  var ITEM_FIELDS=[['类别','类别'],['数量','数量'],['重要级别','重要级别'],['来源','来源'],['获得日期','获得日期'],['存放位置','存放位置'],['描述','描述'],['备注','备注']];
  var DETAIL_SKIP={'称呼':1,'名称':1};
  // 按 order 的友好标签依次渲染，再把 meta 里剩余未展示的变量全部补上
function renderMeta(meta, order, skip){
    var html='', shown={};
    if(skip) Object.keys(skip).forEach(function(k){ shown[k]=1; });
    order.forEach(function(p){ if(shown[p[0]]) return; shown[p[0]]=1; var v=meta[p[0]]; if(v!=null && v!=='') html+=fieldRow(p[1], v); });
    Object.keys(meta).forEach(function(k){
      if(shown[k]||DETAIL_SKIP[k]) return;
      var v=meta[k]; if(v==null||v==='') return;
      html+=fieldRow(k, v);
    });
    return html;
  }
  function secretFold(arr){
    if(!Array.isArray(arr)||!arr.length) return '';
    var items=arr.map(function(o){
      o=o||{};
      var id=o.条目标识||'秘密';
      var exposed=Number(o.是否已暴露)>0;
      var hint=o.暴露条件提示||'';
      return '<div class="sc-secret-item"><span class="k">'+esc(String(id))+'<span class="tag '+(exposed?'on':'')+'">'+(exposed?'已暴露':'未暴露')+'</span></span>'+(hint?'<span class="meta">暴露条件：'+esc(String(hint))+'</span>':'')+'</div>';
    }).join('');
    return '<details class="sc-d-fold"><summary>秘密索引 · '+arr.length+' 项</summary><div class="sc-d-fold-b">'+items+'</div></details>';
  }
  function openDetail(type,name){
    var meta = type==='npc'?((state.npcMeta||{})[name]) : type==='location'?((state.locMeta||{})[name]) : ((state.itemMeta||{})[name]);
    var title=name, html='';
    if(!meta || !Object.keys(meta).length){ html='<div class="sc-d-empty">暂无该条目的变量详情</div>'; }
    else if(type==='npc'){
      title=meta.称呼||name;
      var skip={};
      if(meta.好感度!=null && meta.好感度!==''){ html+=fieldRow('好感度', meta.好感度)+affinityBar(meta.好感度,'好感度'); skip['好感度']=1; }
      if(meta.信任度!=null && meta.信任度!==''){ var _tr=Math.max(0,Math.min(100,Number(meta.信任度)||0)); html+=fieldRow('信任度', _tr+' / 100')+depthBar(meta.信任度); skip['信任度']=1; }
      if(meta.关系深度!=null && meta.关系深度!==''){ var _dep=Math.max(0,Math.min(100,Number(meta.关系深度)||0)); html+=fieldRow('关系深度', _dep+' / 100')+depthBar(meta.关系深度); skip['关系深度']=1; }
      if(meta.是否在场!=null){ html+=fieldRow('是否在场', meta.是否在场?'在场':'不在场'); skip['是否在场']=1; }
      if(meta.存活状态){ html+=fieldRow('存活状态', meta.存活状态); skip['存活状态']=1; }
      // [NEW] 不录入显示栏的内部字段
      ['基准录入周期','基线','召回权重','人生阶段','上次互动周期','死亡周期','性格轴','秘密索引','记忆','本轮同步行动'].forEach(function(k){ skip[k]=1; });
      html+=renderMeta(meta, NPC_FIELDS, skip);
      // [NEW] 性格轴 → 同角色的雷达五边形
      if(meta.性格轴 && typeof meta.性格轴==='object' && Object.keys(meta.性格轴).length){
        html+='<div class="sc-d-sub"><div class="sc-d-sub-h">性格五轴</div>'+stRadar(meta.性格轴)+'</div>';
      }
      // [NEW] 秘密索引 → 默认折叠模块
      html+=secretFold(meta.秘密索引);
    }else if(type==='location'){
      title=meta.名称||name;
      html+=renderMeta(meta, LOC_FIELDS, null);
    }else{
      title=meta.名称||name;
      html+=renderMeta(meta, ITEM_FIELDS, null);
    }
    if(!html) html='<div class="sc-d-empty">该条目暂无更多变量</div>';
    $('sc-modal-title').textContent=title;
    $('sc-modal-body').innerHTML=html;
    $('sc-modal').classList.add('show');
  }
  function closeDetail(){ $('sc-modal').classList.remove('show'); }

  /* ===== 通用确认弹窗 ===== */
  var _confirmCb=null;
  function confirmDialog(msg, onYes){
    var box=$('sc-confirm');
    if(!box){ if(window.confirm(msg) && onYes) onYes(); return; }
    $('sc-confirm-msg').textContent=msg; _confirmCb=onYes||null;
    box.classList.add('show');
  }
  function closeConfirm(){ var box=$('sc-confirm'); if(box) box.classList.remove('show'); _confirmCb=null; }

  /* ===== [NEW] 回收站 localStorage 持久化（跨轮/跨会话保留） =====
     存储粒度：「角色姓名」隔离，不同存档互不污染。仅在 UI 层过滤，不修改 MVU 变量。 */
  function trashStorageKey(){
    var key='schedule_ui_removed_v1';
    try{
      var st=readStat()||{}; var name=(st.主角&&st.主角.姓名)||'';
      if(name && name!=='待初始化') key+='::'+name;
    }catch(e){}
    return key;
  }
  function loadRemoved(){
    try{
      var s=localStorage.getItem(trashStorageKey()); if(!s) return {action:[],location:[],npc:[],item:[]};
      var o=JSON.parse(s)||{};
      return { action:Array.isArray(o.action)?o.action:[], location:Array.isArray(o.location)?o.location:[], npc:Array.isArray(o.npc)?o.npc:[], item:Array.isArray(o.item)?o.item:[] };
    }catch(e){ return {action:[],location:[],npc:[],item:[]}; }
  }
  function saveRemoved(){ try{ localStorage.setItem(trashStorageKey(), JSON.stringify(state.removed||{})); }catch(e){} }
  function trashCount(){ var r=state.removed||{}; return (r.action||[]).length+(r.location||[]).length+(r.npc||[]).length+(r.item||[]).length; }
  function refreshTrashBadge(){
    var el=document.getElementById('sc-trash-num'); if(!el) return;
    var n=trashCount(); el.textContent=String(n);
    if(n>0) el.classList.remove('empty'); else el.classList.add('empty');
  }

  /* ===== 删除卡片（进回收站，仅UI隐藏） ===== */
  function deleteCard(type,name){
    confirmDialog('确认将「'+name+'」移至回收站吗？以后每一轮都不再显示，可从垃圾桶找回。', function(){
      var ci=(state.customs[type]||[]).indexOf(name);
      if(ci>=0){
        // 自定义卡：进回收站；记录"原来是自定义"以便恢复
        state.customs[type].splice(ci,1);
        if((state.removed[type]||[]).indexOf(name)<0) state.removed[type].push(name);
        state._customRemoved=state._customRemoved||{action:{},location:{},npc:{},item:{}};
        state._customRemoved[type][name]=1;
      }else{
        if((state.removed[type]||[]).indexOf(name)<0) state.removed[type].push(name);
      }
      saveRemoved();
      Object.keys(state.slotStore).forEach(function(g){
        var st=state.slotStore[g]||{};
        Object.keys(st).forEach(function(sl){ var s=st[sl]; if(!s) return; s=st[sl]=normSlot(s);
          s.items.forEach(function(it){ if(it[type]===name) it[type]=''; });
        });
      });
      if(state.picked && state.picked.type===type && state.picked.value===name) clearPick();
      renderCards(); renderSlots(); refreshTrashBadge();
      toast('已移至回收站「'+name+'」','warn');
    });
  }
  /* ===== [NEW] 从回收站恢复 ===== */
  function restoreCard(type,name){
    var arr=state.removed[type]||[]; var i=arr.indexOf(name);
    if(i>=0) arr.splice(i,1);
    if(state._customRemoved && state._customRemoved[type] && state._customRemoved[type][name]){
      if((state.customs[type]||[]).indexOf(name)<0) state.customs[type].push(name);
      delete state._customRemoved[type][name];
    }
    saveRemoved();
    renderCards(); refreshTrashBadge(); renderTrash();
    toast('已恢复「'+name+'」','ok');
  }
  /* ===== [NEW] 渲染回收站 ===== */
  // [NEW] 当前选中的回收站分类页签（默认「全部」，会话内存保持）
  if(!state.trashTab) state.trashTab='all';   // 'all' | 'action' | 'location' | 'npc'
  function renderTrash(){
    var body=document.getElementById('sc-trash-body'); if(!body) return;
    var groups=[ ['action','行动'], ['location','地点'], ['npc','人物'], ['item','物品'] ];
    // [NEW] 页签条（含计数徽章）
    var counts={
      all: ((state.removed&&state.removed.action)||[]).length
         + ((state.removed&&state.removed.location)||[]).length
         + ((state.removed&&state.removed.npc)||[]).length
         + ((state.removed&&state.removed.item)||[]).length,
      action:   ((state.removed&&state.removed.action)||[]).length,
      location: ((state.removed&&state.removed.location)||[]).length,
      npc:      ((state.removed&&state.removed.npc)||[]).length,
      item:     ((state.removed&&state.removed.item)||[]).length
    };
    var tabs=[ ['all','全部'],['action','行动'],['location','地点'],['npc','人物'],['item','物品'] ];
    var html='<div class="sc-trash-tabs">';
    tabs.forEach(function(t){
      var k=t[0], lab=t[1], n=counts[k];
      html+='<button type="button" class="sc-trash-tab'+(state.trashTab===k?' active':'')+'" data-trash-tab="'+k+'">'
          +    lab + '<span class="sc-trash-tab-num">'+n+'</span>'
          +  '</button>';
    });
    html+='</div>';
    var total=0;
    groups.forEach(function(g){
      var key=g[0], label=g[1];
      var list=(state.removed&&state.removed[key])||[];
      if(!list.length) return;
      if(state.trashTab!=='all' && state.trashTab!==key) return;   // [NEW] 分类过滤
      total+=list.length;
      html+='<div class="sc-trash-sec-title">'+label+' · '+list.length+' 项</div>';
      html+='<div class="sc-trash-list">';
      list.forEach(function(n){
        // [NEW] 行动卡 + 用户自定义卡（人物/地点/行动）显示「彻底删除」
        var isCustom = !!(state._customRemoved && state._customRemoved[key] && state._customRemoved[key][n]);
        var canPurge = (key==='action') || isCustom;
        var purgeBtn = canPurge
          ? '<button class="sc-trash-purge" type="button" data-type="'+key+'" data-name="'+esc(n)+'" title="从变量与回收站中彻底移除，不再出现">彻底删除</button>'
          : '';
        html+='<div class="sc-trash-item">'
            +  '<span class="sc-trash-type">'+label+'</span>'
            +  '<span class="sc-trash-name">'+esc(n)+'</span>'
            +  '<button class="sc-trash-restore" type="button" data-type="'+key+'" data-name="'+esc(n)+'">找回</button>'
            +  purgeBtn
            +'</div>';
      });
      html+='</div>';
    });
    // 说明文案
    if(total>0) html+='<div class="sc-trash-note">「找回」：仅在前端重新显示；「彻底删除」：从 MVU 变量与回收站中彻底移除（行动卡及你自定义的人物/地点/行动卡），不再出现。</div>';
    // [NEW] 根据当前页签显示不同的空状态提示
    if(total===0){
      var emptyMsg = state.trashTab==='all' ? '回收站是空的'
                    : (state.trashTab==='action'   ? '行动卡分类内没有被删除的项'
                    :  state.trashTab==='location' ? '地点卡分类内没有被删除的项'
                    :  state.trashTab==='npc'      ? '人物卡分类内没有被删除的项'
                    :                                '回收站是空的');
      html += '<div class="sc-trash-empty">'+emptyMsg+'</div>';
    }
    body.innerHTML=html;
  }
  /* ===== [NEW] 彻底删除变量（仅行动卡）：从 行动卡片池.{粒度}[名称] 清除 ===== */
  function purgeAction(name){
    confirmDialog('不可逆！确认从 MVU 变量中完全删除行动卡「'+name+'」吗？\n删除后本卡不会出现在任何玩家的资源里。', function(){
      try{
        var mvu=findMvu(); if(!mvu){ toast("未检测到 MVU","warn"); return; }
        var d=mvu.getMvuData({type:'chat'}) || mvu.getMvuData({type:'message', message_id:'latest'}) || {};
        var raw=d.stat_data || d.display_data || {};
        var pool=raw && raw['行动卡片池']; pool = pool && pool[0] ? pool[0] : pool;
        if(pool){
          // 递归清除所有粒度：年/季/月/周/日
          ['年','季','月','周','日'].forEach(function(g){
            var bucket=pool[g]; bucket = bucket && bucket[0] ? bucket[0] : bucket;
            if(bucket && bucket[name]) delete bucket[name];
          });
        }
        // 老式扣底：顺便清除可能存在的「行动卡库」平坂键
        if(raw && raw['行动卡库']){
          var lib=raw['行动卡库']; lib = lib && lib[0] ? lib[0] : lib;
          if(lib && lib[name]) delete lib[name];
        }
        // 回写（chat 作用域跨轮保留）
        mvu.replaceMvuData(d, {type:'chat'});
        // 同步从回收站中移除该项（彻底消失）
        var arr=state.removed.action||[]; var i=arr.indexOf(name); if(i>=0) arr.splice(i,1);
        if(state._customRemoved && state._customRemoved.action) delete state._customRemoved.action[name];
        saveRemoved();
        renderCards(); refreshTrashBadge(); renderTrash();
        toast('已从 MVU 变量中彻底删除行动卡「'+name+'」','warn');
      }catch(e){
        try{ console.error('[schedule_ui] purgeAction:', e); }catch(_){}
        toast('彻底删除失败：'+((e&&e.message)||e),'warn');
      }
    });
  }
  /* ===== [NEW] 彻底删除（行动卡 + 自定义人物/地点/行动）：从 MVU 变量与回收站移除 ===== */
  function purgeCard(type,name){
    var labels={action:'行动卡',location:'地点',npc:'人物',item:'物品'}; var lab=labels[type]||'卡片';
    confirmDialog('不可逆！确认彻底删除'+lab+'「'+name+'」吗？\n删除后将从 MVU 变量与回收站中移除，不再出现。', function(){
      try{
        var mvu=findMvu();
        if(mvu){
          var d=mvu.getMvuData({type:'chat'}) || mvu.getMvuData({type:'message', message_id:'latest'}) || {};
          var raw=d.stat_data || d.display_data || {};
          var uw=function(x){ return x && x[0] ? x[0] : x; };
          var changed=false;
          if(type==='action'){
            var pool=uw(raw && raw['行动卡片池']);
            if(pool){ ['年','季','月','周','日'].forEach(function(g){ var b=uw(pool[g]); if(b && b[name]){ delete b[name]; changed=true; } }); }
            var lib=uw(raw && raw['行动卡库']);
            if(lib && lib[name]){ delete lib[name]; changed=true; }
          }else if(type==='npc'){
            var npc=uw(raw && raw['NPC']);
            if(npc && typeof npc==='object'){ Object.keys(npc).forEach(function(k){ var v=npc[k]||{}; if(k===name || v.称呼===name){ delete npc[k]; changed=true; } }); }
          }else if(type==='location'){
            var map=uw(raw && raw['地图']);
            if(map && typeof map==='object'){ Object.keys(map).forEach(function(k){ var v=map[k];
              if(k===name || (v && v.名称===name)){ delete map[k]; changed=true; return; }
              if(v && typeof v==='object'){ Object.keys(v).forEach(function(sk){ if((k+'·'+sk)===name){ delete v[sk]; changed=true; } }); }
            }); }
          }
          if(changed) mvu.replaceMvuData(d, {type:'chat'});
        }
      }catch(e){ try{ console.error('[schedule_ui] purgeCard:', e); }catch(_){} toast('彻底删除时变量写入失败：'+((e&&e.message)||e),'warn'); }
      var ca=state.customs[type]||[]; var ci=ca.indexOf(name); if(ci>=0) ca.splice(ci,1);
      var ra=state.removed[type]||[]; var ri=ra.indexOf(name); if(ri>=0) ra.splice(ri,1);
      if(state._customRemoved && state._customRemoved[type]) delete state._customRemoved[type][name];
      Object.keys(state.slotStore).forEach(function(g){ var st=state.slotStore[g]||{}; Object.keys(st).forEach(function(sl){ var ss=st[sl]; if(!ss) return; ss=st[sl]=normSlot(ss); ss.items.forEach(function(it){ if(it[type]===name) it[type]=''; }); }); });
      saveRemoved();
      renderCards(); try{ renderSlots(); }catch(_){} refreshTrashBadge(); renderTrash();
      toast('已彻底删除'+lab+'「'+name+'」','warn');
    });
  }
