  /* ===== 拾取 / 放置 ===== */
  function pickCard(type,value){
    if(state.picked && state.picked.type===type && state.picked.value===value){ clearPick(); return; }
    state.picked={type:type,value:value};
    $('sc-pick-name').textContent=value+'（'+(type==='action'?'行动':type==='location'?'地点':type==='npc'?'人物':'物品')+'）';
    $('sc-pickbar').classList.add('show');
    renderCards(); refreshDroppableHints();
  }
  function clearPick(){ state.picked=null; $('sc-pickbar').classList.remove('show'); renderCards(); refreshDroppableHints(); }
  function placeInto(slotName,type,value,aidx){
    var s=state.slots[slotName]=normSlot(state.slots[slotName]||null);
    var idx=(aidx==null)?0:Number(aidx);
    if(idx>=s.items.length) idx=s.items.length-1; if(idx<0) idx=0;
    var it=s.items[idx];
    if(type==='action'){
      if(value){
        var prevCost=it.action?actionCost(it.action):0;
        var projected=totalPlannedCost()-prevCost+actionCost(value);
        if(state.ap && state.ap.cur>0 && projected>state.ap.cur){
          toast('行动点不足 · 可用 '+state.ap.cur+'，将达 '+projected,'warn');
          return false;
        }
      }
      it.action=value;
    }else if(type==='location'){ it.location=value; }
    else { it.npc=value; }
    renderSlots();
    return true;
  }
