  /* ===== 序列化 + 提交 ===== */
  function buildScheduleObj(){
    var obj={}; var names=slotsFor(state.grain);
    var uniq=function(a){ return a.filter(function(v,i){ return v&&a.indexOf(v)===i; }); };
    names.forEach(function(n){
      var s=state.slots[n]; if(!s) return;
      var arr=(s.items||[]).filter(function(it){ return it.action||it.location||it.npc||it.item; });
      if(!arr.length) return;
      // 每个行动独立绑定地点/同行，并标注所需行动点
      var plan=arr.map(function(it){ return { 行动:it.action||'', 地点:it.location||'', 同行NPC:it.npc||'', 使用物品:it.item||'', 行动点消耗:it.action?actionCost(it.action):0 }; });
      obj[n]={
        行动安排:plan,
        行动:uniq(arr.map(function(it){return it.action;})).join('、'),
        地点:uniq(arr.map(function(it){return it.location;})).join('、'),
        同行NPC:uniq(arr.map(function(it){return it.npc;})).join('、'),
        使用物品:uniq(arr.map(function(it){return it.item;})).join('、')
      };
    });
    return obj;
  }
  function scheduleHasAny(){ var o=buildScheduleObj(); return Object.keys(o).length>0; }
  function apCurrent(stat){
    try{ var ap=stat&&stat.主角&&stat.主角.行动点; if(ap&&ap.当前!=null){ var n=Math.floor(Number(ap.当前)); if(!isFinite(n)||isNaN(n)) return null; return n<0?0:n; } }catch(e){}
    return null;
  }
  function buildAdvanceText(fallback){
    var o=buildScheduleObj();
    var L=['[ADVANCE_TIME]'];
    L.push('时间粒度：'+state.grain);
    L.push('行动点：可用 '+((state.ap&&state.ap.cur)||0)+' ｜ 已规划消耗 '+totalPlannedCost()+' ｜ 上限 '+((state.ap&&state.ap.cap)||0));
    if(state.season||state.climate) L.push('当季：'+(state.season||'未知')+(state.climate?(' ｜ 气候：'+state.climate):''));
    L.push('人称：'+$('sc-person').value+' ｜ 难度：'+$('sc-difficulty').value+' ｜ 写实程度：'+$('sc-realism').value+' ｜ 事件倾向：'+$('sc-tendency').value+' ｜ 叙事风格：'+$('sc-narrative').value);
    if(fallback){
      L.push('');
      L.push('【空日程兜底】本次日程为空（行动点耗尽或玩家未放置任何行动卡），但不空过。');
      L.push('<TIMEthink>：请勿空过。依据已完成的背景判定（年龄／能力边界／时代／社会／科技／节日／制度 ＋ 当前地点社交开放度 ＋ 在场 NPC ＋ 到期延时种子 ＋ 生活感小事件）生成合理的随机／生活流事件，与既有思维链内容一致、不跳脱；这类事件多为低强度被动遭遇（偶遇／突发小插曲／他人来访／环境或身体变化），仍走 P2.7 检定与 P2.8 种子接口（与 P4「直接开始」空白默认日程同源）。</TIMEthink>');
    }else{
      L.push('— 本期日程 —');
      Object.keys(o).forEach(function(k){
        var s=o[k];
        var plan=Array.isArray(s.行动安排)?s.行动安排:null;
        if(plan && plan.length){
          L.push(k+'：');
          plan.forEach(function(p){
            var line='  · '+(p.行动||'（自由安排）')+'（⚡'+(p.行动点消耗!=null?p.行动点消耗:0)+'）';
            if(p.地点) line+=' @'+p.地点;
            if(p.同行NPC) line+=' &'+p.同行NPC;
            if(p.使用物品) line+=(p.同行NPC?'':' ')+'&'+p.使用物品;
            L.push(line);
          });
        }else{
          var line=k+': '+(s.行动||'（自由安排）');
          if(s.地点) line+=' @'+s.地点;
          if(s.同行NPC) line+=' &'+s.同行NPC;
          if(s.使用物品) line+=(s.同行NPC?'':' ')+'&'+s.使用物品;
          L.push(line);
        }
      });
    }
    L.push('');
    L.push('请将以上日程写入变量，按时间粒度生成本周期事件，并将 $游戏模式 设为 TIME_ADVANCE。');
    return L.join('\n');
  }

  function setSubmit(txt,cls,disabled){
