    b.className='sc-btn primary'+(cls?' '+cls:'');
    b.innerHTML=esc(txt)+(cls==='done'
      ? ' <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><path d="M5 13l4 4L19 7"/></svg>'
      : (!cls?' <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14"/><path d="M13 6l6 6-6 6"/></svg>':''));
  }

  function onSubmit(){
    // 空日程兜底：不再硬性阻止空提交；改为标记并交由 TIME_ADVANCE 走随机/生活流事件分支
    var emptySched=!scheduleHasAny();
    if(!emptySched) saveCombo(null, true);   // 固定记住玩家上一轮提交的日程组��（含地点/NPC）
    var mvu=findMvu();
    var createChatMessagesFn=findGlobal('createChatMessages');
    var generateFn=findGlobal('generate');
    var waitGlobalInitializedFn=findGlobal('waitGlobalInitialized');
    if(!mvu || typeof createChatMessagesFn!=='function'){
      var stat0=readStat(); var ap0=apCurrent(stat0);
      var fb0=emptySched || (ap0!=null && ap0<=0);
      toast(fb0?'空日程兜底已标记 · 已在控制台打印':'未在酒馆环境，已在控制台打��日程','warn');
      console.log('[日程安排]\n'+buildAdvanceText(fb0));
      return;
    }
    setSubmit('生成中…','',true);
    var existingData, advanceText, scheduleObj=buildScheduleObj();
    Promise.resolve()
      .then(function(){ if(typeof waitGlobalInitializedFn==='function') return waitGlobalInitializedFn('Mvu'); })
      .then(function(){
        existingData = mvu.getMvuData({type:'message', message_id:'latest'}) || {};
        var stat = existingData.stat_data || (existingData.stat_data={});
        // 引擎四项 → 流程状态（setLeaf 自动兼容 [value, desc] 元组形态）
        setLeaf(stat, ['流程状态','难度'], $('sc-difficulty').value);
        setLeaf(stat, ['流程状态','写实程度'], $('sc-realism').value);
        setLeaf(stat, ['流程状态','事件倾向'], $('sc-tendency').value);
        setLeaf(stat, ['流程状态','叙事风格'], $('sc-narrative').value);
        setLeaf(stat, ['流程状态','人称'], $('sc-person').value);
        setLeaf(stat, ['世界','当前时间粒度'], state.grain);
        // 检测「行动点=0 或日程为空」→ 置空日程兜底标记（基于解包后的视图判断）
        var ap=apCurrent(unwrapMvu(stat));
        var fallback = emptySched || (ap!=null && ap<=0);
        setLeaf(stat, ['流程状态','空日程兜底'], fallback);
        stat.日程=scheduleObj;
        advanceText=buildAdvanceText(fallback);
        return mvu.replaceMvuData(existingData,{type:'message', message_id:'latest'});
      })
      .then(function(){
        return createChatMessagesFn([{role:'user', message:advanceText, data:existingData}], {refresh:'all'});
      })
      .then(function(){
        setSubmit('已���成日程','done',true);
        toast('日程已提交 · 时间推进中','ok');
        if(typeof generateFn==='function') return generateFn({ user_input:'', should_stream:true });
        return null;
      })
      .then(function(aiReply){
        if(aiReply==null) return null;
        return createChatMessagesFn([{role:'assistant', message:String(aiReply), data:existingData}], {refresh:'all'});
      })
      .catch(function(err){
        console.error('[日程安排] 提交失败:',err);
        setSubmit('提交失败 · 重试','err',false);
        toast('提交失败，请重试','warn');
      });
  }

  /* ===== 随机填满 ===== */
  function pickRand(arr){ return (arr && arr.length)? arr[Math.floor(Math.random()*arr.length)] : ''; }
  function actionPool(){ return poolFor('action'); }
  function locationPool(){ return poolFor('location'); }
  function npcPool(){ return poolFor('npc'); }
  function randomFill(){
    var names=slotsFor(state.grain);
    var acts=actionPool(), locs=locationPool(), npcs=npcPool();
    if(!acts.length){ toast('暂无可用行动卡','warn'); return; }
    var store=grainSlots(state.grain);
    var budget=(state.ap && state.ap.cur>0)? state.ap.cur : Infinity;
    var used=0;
    names.forEach(function(n){
      var a=pickRand(acts), c=actionCost(a), action='', loc='', npc='';
      if(used+c<=budget){ action=a; used+=c; loc=locs.length?pickRand(locs):''; npc=(npcs.length && Math.random()<0.7)?pickRand(npcs):''; }
      store[n]={ items:[{action:action,location:loc,npc:npc}] };
    });
    renderSlots();
    toast('已随机填满 · 规划行动点 '+used+(budget!==Infinity?(' / '+budget):''),'ok');
  }

  /* ===== 组合记忆（localStorage，按 script_id 命名空间） ===== */
  var LS_COMBO_PREFIX='LIFE_SCHEDULE_COMBOS_V1';
  function comboKey(){
    var sid='';
    try{ if(typeof getScriptId==='function') sid=getScriptId()||''; }catch(e){}
    try{ if(!sid && typeof TavernHelper!=='undefined' && TavernHelper.getScriptId) sid=TavernHelper.getScriptId()||''; }catch(e){}
    return LS_COMBO_PREFIX+(sid?(':'+sid):'');
  }
  // —— 组合持久化：内存为权威源，localStorage + 酒馆聊天变量 双写。
  // （沙箱 iframe 内 localStorage 常被禁用，所以必须有内存兑底，否则��存后刷��即丢失）
  function thReadCombos(){
    try{
      if(typeof TavernHelper!=='undefined' && TavernHelper.getVariables){
        var v=TavernHelper.getVariables({type:'chat'})||{};
        var a=v[comboKey()];
        if(Array.isArray(a)) return a;
      }
    }catch(e){}
    return null;
  }
  function thWriteCombos(arr){
    try{
      if(typeof TavernHelper!=='undefined' && TavernHelper.insertOrAssignVariables){
        var o={}; o[comboKey()]=arr; TavernHelper.insertOrAssignVariables(o,{type:'chat'}); return;
      }
    }catch(e){}
    try{
      if(typeof TavernHelper!=='undefined' && TavernHelper.replaceVariables && TavernHelper.getVariables){
        var cur=TavernHelper.getVariables({type:'chat'})||{}; cur[comboKey()]=arr; TavernHelper.replaceVariables(cur,{type:'chat'});
      }
    }catch(e){}
  }
  function lsReadCombos(){ try{ var a=JSON.parse(localStorage.getItem(comboKey())||'null'); return Array.isArray(a)?a:null; }catch(e){ return null; } }
  function lsWriteCombos(arr){ try{ localStorage.setItem(comboKey(), JSON.stringify(arr)); }catch(e){} }
  // 初始化���把已持久化的组合载入内存（优��聊天变量，其次 localStorage）
  function loadCombosOnce(){
    var a=thReadCombos(); if(!a) a=lsReadCombos();
    state.combos = Array.isArray(a)? a : [];
  }
  function loadCombos(){ return state.combos; }
  function persistCombos(arr){ state.combos=arr; lsWriteCombos(arr); thWriteCombos(arr); }
  function snapshotSlots(){
    var names=slotsFor(state.grain), slots={};
    names.forEach(function(n){ var s=state.slots[n]; if(!s) return; var arr=(s.items||[]).filter(function(it){ return it.action||it.location||it.npc; }); if(arr.length) slots[n]={items:arr.map(function(it){ return {action:it.action||'',location:it.location||'',npc:it.npc||''}; })}; });
    return { grain:state.grain, slots:slots };
  }
  function countFilled(combo){ return (combo && combo.slots)? Object.keys(combo.slots).length : 0; }
  // 保存：name 指定名称；auto=true 时复用固定「上一轮」记忆
  function saveCombo(name, auto){
    var snap=snapshotSlots();
    if(!auto && countFilled(snap)===0){ toast('当前日程为空，无法保存','warn'); return; }
    var arr=loadCombos().slice();
    if(auto){
      snap.id='__last__'; snap.name='上一轮'; snap.auto=true; snap.ts=Date.now();
      arr=arr.filter(function(c){ return c.id!=='__last__'; });
      arr.unshift(snap);
    }else{
      snap.id='c'+Date.now(); snap.name=(name||'').trim()||('组合'+(arr.length+1)); snap.ts=Date.now();
      arr.push(snap);
    }
    persistCombos(arr); renderCombos();
    if(!auto){ toast('已保存组合「'+snap.name+'」','ok'); var inp=$('sc-combo-name'); if(inp) inp.value=''; }
  }
  function applyCombo(id){
    var arr=loadCombos(), c=null;
    for(var i=0;i<arr.length;i++){ if(arr[i].id===id){ c=arr[i]; break; } }
    if(!c){ toast('未找到该组合','warn'); return; }
    if(c.grain && c.grain!==state.grain) setGrain(c.grain);
    var store=grainSlots(state.grain);
    Object.keys(store).forEach(function(k){ delete store[k]; });   // 先清空当前粒度，再套用组合
    Object.keys(c.slots||{}).forEach(function(k){ store[k]=normSlot(c.slots[k]); });
    renderSlots();
    toast('已调用组合「'+c.name+'」','ok');
  }
  function deleteCombo(id){
    var c=null; for(var i=0;i<state.combos.length;i++){ if(state.combos[i].id===id){ c=state.combos[i]; break; } }
    confirmDialog('确认删除组合「'+((c&&c.name)||'')+'」吗？', function(){
      var arr=loadCombos().filter(function(x){ return x.id!==id; });
      persistCombos(arr); renderCombos(); toast('已删除组合','warn');
    });
  }
  function renderCombos(){
    var box=$('sc-combos-list'); if(!box) return;
    var arr=loadCombos(); box.innerHTML='';
    if(!arr.length){ box.innerHTML='<span class="sc-combos-empty">暂无保存的组合 · 排好日程后点「存为组合」，或提交后自动记住上一轮</span>'; return; }
    arr.forEach(function(c){
      var chip=ce('div','sc-combo-chip'+(c.auto?' auto':''));
      chip.setAttribute('data-id', c.id);
      chip.innerHTML='<span class="name">'+esc(c.name)+'</span><span class="meta">'+esc(c.grain||'')+'·'+countFilled(c)+'项</span><span class="del" data-del="1" title="删除">×</span>';
      box.appendChild(chip);
    });
  }

  /* ============================================================
     角色状态栏（只读 · 完整版 · 全部读自变量；长分区折叠下拉）
     ============================================================ */
  function stNum(v){ var n=Number(v); return (isFinite(n)&&!isNaN(n))?n:null; }
  function stHas(v){ if(v==null||v==='') return false; if(Array.isArray(v)) return v.length>0; if(typeof v==='object') return Object.keys(v).length>0; return true; }
  function stText(v){
    if(v==null||v==='') return '';
    if(v===true) return '是'; if(v===false) return '否';
    if(Array.isArray(v)) return v.map(function(x){ return (x&&typeof x==='object')?(x.名称||x.称呼||JSON.stringify(x)):String(x); }).join('、');
    if(typeof v==='object') return Object.keys(v).join('、');
    return String(v);
  }
  function stRow(k,v){ if(!stHas(v)) return ''; return '<div class="sc-st-row"><span class="sc-st-k">'+esc(k)+'</span><span class="sc-st-v">'+esc(stText(v))+'</span></div>'; }
  function stRowRaw(k,htmlV){ return '<div class="sc-st-row"><span class="sc-st-k">'+esc(k)+'</span><span class="sc-st-v">'+htmlV+'</span></div>'; }
  function stBar(k, val, lo, hi, unit){
    var n=stNum(val); if(n==null) return stRow(k, val);
    lo=(lo==null?0:lo); hi=(hi==null?100:hi);
    var v=n; if(v<lo)v=lo; if(v>hi)v=hi;
    var pct, cls='pos', style='left:0;';
    if(lo<0){
      var half=(hi-lo)/2; pct=Math.min(100, Math.abs(n)/half*100);
      if(n<0){ cls='neg'; style='right:50%;left:auto;'; } else { style='left:50%;'; }
    }else{ pct=(hi-lo)?((v-lo)/(hi-lo)*100):0; }
    var rng=(lo<0)?(lo+'~'+hi):('/ '+hi);
    var num=n+(unit?(' '+unit):'')+' · '+rng;
    var bar='<span class="sc-st-bar"><span class="sc-st-bar-fill '+cls+'" style="width:'+pct.toFixed(0)+'%;'+style+'"></span></span><span class="sc-st-bar-num">'+esc(num)+'</span>';
    return '<div class="sc-st-row bar"><span class="sc-st-k">'+esc(k)+'</span><span class="sc-st-v">'+bar+'</span></div>';
  }
  function stSec(title, en, bodyHtml){ if(!bodyHtml) return ''; return '<div class="sc-st-sec"><button class="sc-st-sec-h" type="button"><span class="sc-st-sec-chev"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><path d="M9 6l6 6-6 6"/></svg></span>'+esc(title)+(en?'<span class="en">'+esc(en)+'</span>':'')+'</button><div class="sc-st-sec-b">'+bodyHtml+'</div></div>'; }
  function stChips(arr){ if(!arr||!arr.length) return ''; return '<div class="sc-st-chips">'+arr.map(function(t){ return '<span class="sc-tag-chip">'+esc(String(t))+'</span>'; }).join('')+'</div>'; }
  function stRecord(obj, fmt){
    var keys=Object.keys(obj||{}); if(!keys.length) return '<div class="sc-st-empty">暂无</div>';
    var h='';
    keys.forEach(function(key){
      var v=obj[key]; var o=(v&&typeof v==='object')?v:{};
      var name=o.名称||o.称呼||key;
      var meta=fmt?fmt(o,key,v):'';
      h+='<div class="sc-st-item"><span class="sc-st-item-name">'+esc(String(name))+'</span><span class="sc-st-item-meta">'+esc(String(meta||''))+'</span></div>';
    });
    return h;
  }
  function stFold(title, count, bodyHtml){
    return '<div class="sc-st-fold"><button class="sc-st-fold-h" type="button"><span class="sc-st-fold-chev"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><path d="M9 6l6 6-6 6"/></svg></span>'+esc(title)+'<span class="cnt">'+(count!=null?(count+' 项'):'')+'</span></button><div class="sc-st-fold-b">'+bodyHtml+'</div></div>';
  }
  function cycleTxt(c){ var n=stNum(c); if(n==null) return stText(c); if(n<0) return '永久'; return '剩 '+n+' 周期'; }

  function stRadar(axis){
    var keys=['外向','亲和','尽责','情绪稳定','开放'];
    var labels=['外向','亲和','尽责','稳定','开放'];
    var size=200, vh=220, cx=100, cy=104, R=60, n=keys.length, ang=[], i;
    for(i=0;i<n;i++){ ang.push((-90 + i*(360/n))*Math.PI/180); }
    function pt(idx, r){ return [ cx+Math.cos(ang[idx])*r, cy+Math.sin(ang[idx])*r ]; }
    var svg='<svg viewBox="0 0 '+size+' '+vh+'" class="sc-radar-svg" preserveAspectRatio="xMidYMid meet">';
    var rings=[0.25,0.5,0.75,1], ri, pp, cpt;
    for(ri=0;ri<rings.length;ri++){
      pp=[];
      for(i=0;i<n;i++){ cpt=pt(i, R*rings[ri]); pp.push(cpt[0].toFixed(1)+','+cpt[1].toFixed(1)); }
      svg+='<polygon points="'+pp.join(' ')+'" class="sc-radar-grid"/>';
    }
    var vals=[], edge, v, co, lp, anchor;
    for(i=0;i<n;i++){
      edge=pt(i,R);
      svg+='<line x1="'+cx+'" y1="'+cy+'" x2="'+edge[0].toFixed(1)+'" y2="'+edge[1].toFixed(1)+'" class="sc-radar-axis"/>';
      v=stNum(axis[keys[i]]); if(v==null)v=0; if(v<0)v=0; if(v>100)v=100; vals.push(v);
      co=Math.cos(ang[i]); lp=pt(i, R+15);
      anchor=(Math.abs(co)<0.3)?'middle':(co>0?'start':'end');
      svg+='<text x="'+lp[0].toFixed(1)+'" y="'+lp[1].toFixed(1)+'" text-anchor="'+anchor+'" class="sc-radar-label">'+esc(labels[i])+'</text>';
      svg+='<text x="'+lp[0].toFixed(1)+'" y="'+(lp[1]+10).toFixed(1)+'" text-anchor="'+anchor+'" class="sc-radar-val">'+v+'</text>';
    }
    var dp=[], dc;
    for(i=0;i<n;i++){ dc=pt(i, R*vals[i]/100); dp.push(dc[0].toFixed(1)+','+dc[1].toFixed(1)); }
    svg+='<polygon points="'+dp.join(' ')+'" class="sc-radar-area"/>';
    for(i=0;i<n;i++){ dc=pt(i, R*vals[i]/100); svg+='<circle cx="'+dc[0].toFixed(1)+'" cy="'+dc[1].toFixed(1)+'" r="2.4" class="sc-radar-dot"/>'; }
    svg+='</svg>';
    return '<div class="sc-radar">'+svg+'</div>';
  }
  function stSkills(skills){
    var keys=Object.keys(skills||{}); if(!keys.length) return '<div class="sc-st-empty">暂无技能</div>';
    var h='';
    keys.forEach(function(key){
      var o=(skills[key]&&typeof skills[key]==='object')?skills[key]:{};
      var prof=stNum(o.熟练度); if(prof==null)prof=0; if(prof<0)prof=0; if(prof>100)prof=100;
      var meta=[];
      if(o.等级!=null&&o.等级!=='') meta.push('Lv'+o.等级);
      if(o.类别) meta.push(o.类别);
      meta.push('熟练 '+prof+'/100');
      h+='<div class="sc-sk"><div class="sc-sk-top"><span class="sc-sk-name">'+esc(key)+'</span><span class="sc-sk-meta">'+esc(meta.join(' · '))+'</span></div><div class="sc-sk-bar"><span class="sc-sk-fill" style="width:'+prof.toFixed(0)+'%;"></span></div></div>';
    });
    return h;
  }
  function vitalBlock(k, val, max, cls){
    var n=stNum(val); if(n==null) return '';
    var m=stNum(max); if(m==null||m<=0) m=(cls==='en'?1000:100);
    var pct=n/m*100; if(pct<0)pct=0; if(pct>100)pct=100;
    return '<div class="sc-vital"><div class="sc-vital-top"><span class="sc-vital-k">'+esc(k)+'</span><span class="sc-vital-num">'+n+' / '+m+'</span></div><div class="sc-vital-bar"><span class="sc-vital-fill '+cls+'" style="width:'+pct.toFixed(0)+'%;"></span></div></div>';
  }

  function memList(rec){
    var keys=Object.keys(rec||{}); if(!keys.length) return '<div class="sc-st-empty">暂无</div>';
    keys.sort(function(a,b){ return (stNum(rec[b]&&rec[b].周期)||0)-(stNum(rec[a]&&rec[a].周期)||0); });
    return keys.map(function(k){
      var o=rec[k]||{}; var title=o.标题||o.摘要||k; var sum=(o.标题&&o.摘要)?o.摘要:'';
      var meta=[]; if(o.日期)meta.push(o.日期); else if(o.周期!=null)meta.push('周期 '+o.周期);
      if(o.重要度)meta.push(o.重要度); if(o.涉及人物)meta.push('人物：'+o.涉及人物); if(o.涉及地点)meta.push('地点：'+o.涉及地点); if(o.情绪基调)meta.push(o.情绪基调);
      return '<div class="sc-mem"><div class="sc-mem-t">'+esc(String(title))+'</div>'+(sum?'<div class="sc-mem-s">'+esc(String(sum))+'</div>':'')+(meta.length?'<div class="sc-mem-m">'+esc(meta.join(' · '))+'</div>':'')+'</div>';
    }).join('');
  }
  function eggList(rec){
    var keys=Object.keys(rec||{}); if(!keys.length) return '<div class="sc-st-empty">暂无</div>';
    return keys.map(function(k){
      var o=rec[k]||{}; var title=o.摘要||o.模糊钥匙||k;
      var meta=[]; if(o.情绪基调)meta.push(o.情绪基调); if(o.来源)meta.push('来源：'+o.来源); if(o.触发日期)meta.push('触发：'+o.触发日期); meta.push(Number(o.已浮现)>0?'已浮现':'待浮现');
      return '<div class="sc-mem"><div class="sc-mem-t">'+esc(String(title))+'</div><div class="sc-mem-m">'+esc(meta.join(' · '))+'</div></div>';
    }).join('');
  }
  function recallList(wm, lt){
    var src=[wm||{},lt||{}], maxC=-1;
    src.forEach(function(rec){ Object.keys(rec).forEach(function(k){ var c=stNum(rec[k]&&rec[k].上次浮现周期); if(c!=null&&c>maxC) maxC=c; }); });
    if(maxC<0) return { html:'<div class="sc-st-empty">本轮无召回记忆</div>', count:0 };
    var picked={};
    src.forEach(function(rec){ Object.keys(rec).forEach(function(k){ if(stNum(rec[k]&&rec[k].上次浮现周期)===maxC) picked[k]=rec[k]; }); });
    return { html:memList(picked), count:Object.keys(picked).length };
  }
  function renderStatus(stat){
