  /* ===== 事件绑定 ===== */
  function bind(){
    var root=$('sc-root');
    // 委托点击
    root.addEventListener('click',function(ev){
      var t=ev.target;
      var del=t.closest && t.closest('.sc-card-del');
      if(del){ var dc=del.closest('.sc-card'); if(dc){ deleteCard(dc.getAttribute('data-type'), dc.getAttribute('data-value')); } return; }
      var det=t.closest && t.closest('.sc-card-detail');
      if(det){ var pc=det.closest('.sc-card'); if(pc){ openDetail(pc.getAttribute('data-type'), pc.getAttribute('data-value')); } return; }
      var card=t.closest && t.closest('.sc-card');
