// ═══════════════════════════════════════════════════════════════════

// ─── V3 常量表 ───

// 家境系数（泛化后）
var V3_FAMILY_COEF = { 寒门: 0.5, 温饱: 0.75, 小资: 1.0, 富庶: 2.0, 豪门: 4.0 };

