// ============================================================
// 事件包管理器 v2 (Event-Pack Manager) · TavernHelper 脚本
// 持久化：TavernHelper 脚本变量 (getVariables / insertOrAssignVariables, type:'script')，localStorage 兜底
// 能力：导入 / 列表 / 启用停用切换 / 删除 / 清空；启动与切换聊天时自动重新应用
// 依赖引擎：window.LIFE_REGISTER_EVENT_PACK / _UNREGISTER_ / _LIST_
// ============================================================
(function () {
  var LS_KEY = 'LIFE_EVENT_PACKS_V2';
  var STORE_KEY = '事件包仓库'; // 脚本变量中的存储键
  var ATTR_WHITELIST = ['HP','精力','体质','智力','魅力','运气','财富','金钱','压力','好感度','关系深度','状态标签','业力','人望','知名度','寿命预期','颜值','注入种子'];

  function W() { return (typeof window !== 'undefined') ? window : {}; }
  function packId(p) { return (p && (p.pack_id || p.id || p.namespace)) || ''; }
  // 标签：包级 tags + 各事件 事件库标签 自动聚合去重
  function packTags(p) {
    var set = {};
    if (p && Array.isArray(p.tags)) p.tags.forEach(function (t) { if (t) set[String(t)] = 1; });
    if (p && Array.isArray(p.events)) p.events.forEach(function (ev) { var ts = ev && ev['事件库标签']; if (Array.isArray(ts)) ts.forEach(function (t) { if (t) set[String(t)] = 1; }); });
    return Object.keys(set);
  }

  // ---------- 脚本变量作用域（随卡导出、跨设备） ----------
  function scriptOpt() {
    try { if (typeof getScriptId === 'function') return { type: 'script', script_id: getScriptId() }; } catch (e) {}
    return null;
  }
  function readStore() {
    var opt = scriptOpt();
    if (opt && typeof getVariables === 'function') {
      try { var v = getVariables(opt); if (v && Array.isArray(v[STORE_KEY])) return v[STORE_KEY]; } catch (e) {}
    }
    try { return JSON.parse(localStorage.getItem(LS_KEY) || '[]') || []; } catch (e) { return []; }
  }
  function writeStore(arr) {
    var opt = scriptOpt();
    if (opt && typeof insertOrAssignVariables === 'function') {
      try { var o = {}; o[STORE_KEY] = arr; insertOrAssignVariables(o, opt); } catch (e) {}
    }
    try { localStorage.setItem(LS_KEY, JSON.stringify(arr)); } catch (e) {}
  }

  // ---------- 导入前校验 ----------
  function validatePack(pack) {
    if (!pack || typeof pack !== 'object') return { ok: false, msg: '不是对象' };
    if (!packId(pack)) return { ok: false, msg: '缺少 pack_id / namespace' };
    if (pack.tags != null && !Array.isArray(pack.tags)) return { ok: false, msg: 'tags 必须是字符串数组' };
    if (!Array.isArray(pack.events) || !pack.events.length) return { ok: false, msg: 'events 为空' };
    for (var i = 0; i < pack.events.length; i++) {
      var ev = pack.events[i];
      if (!ev || typeof ev['内容'] !== 'string' || !ev['内容']) return { ok: false, msg: '第 ' + (i + 1) + ' 条缺少 内容' };
      var seeds = ev['加点种子'];
      if (Array.isArray(seeds)) {
        for (var j = 0; j < seeds.length; j++) {
          var s = seeds[j];
          var key = (typeof s === 'string') ? s : (s && (s['属性'] || s.key || s.name));
          if (key && ATTR_WHITELIST.indexOf(key) < 0) return { ok: false, msg: '第 ' + (i + 1) + ' 条 加点种子 "' + key + '" 不在白名单' };
        }
      }
      // P13 因果链校验（缺失合法 · 向后兼容）
      var chains = ev['因果链'];
      if (Array.isArray(chains)) {
        for (var ci = 0; ci < chains.length; ci++) {
          var ch = chains[ci];
          if (!ch || typeof ch !== 'object') continue;
          var cSeed = ch.seed;
          if (cSeed && typeof cSeed === 'object') {
            var cSeeds = cSeed['加点种子'];
            if (Array.isArray(cSeeds)) {
              for (var ck = 0; ck < cSeeds.length; ck++) {
                var cs = cSeeds[ck];
                var cKey = (typeof cs === 'string') ? cs : (cs && (cs['属性'] || cs.key || cs.name));
                if (cKey && ATTR_WHITELIST.indexOf(cKey) < 0) return { ok: false, msg: '第 ' + (i + 1) + ' 条 因果链[' + ci + '].seed 加点种子 "' + cKey + '" 不在白名单' };
              }
            }
          }
        }
      }
    }
    return { ok: true };
  }

  // ---------- 应用仓库：重置注册表后只挂载 enabled 的包 ----------
  function applyStore() {
    var w = W();
    if (typeof w.LIFE_REGISTER_EVENT_PACK !== 'function') return 0;
    if (typeof w.LIFE_LIST_EVENT_PACKS === 'function' && typeof w.LIFE_UNREGISTER_EVENT_PACK === 'function') {
      var cur = w.LIFE_LIST_EVENT_PACKS() || [];
      for (var i = 0; i < cur.length; i++) w.LIFE_UNREGISTER_EVENT_PACK(cur[i].pack_id);
    }
    var store = readStore(), n = 0;
    for (var k = 0; k < store.length; k++) { if (store[k] && store[k].enabled) { if (w.LIFE_REGISTER_EVENT_PACK(store[k].pack)) n++; } }
    return n;
  }
  function autoApply(tries) {
    if (typeof W().LIFE_REGISTER_EVENT_PACK !== 'function') {
      if ((tries || 0) < 40) setTimeout(function () { autoApply((tries || 0) + 1); }, 300);
      return;
    }
    var n = applyStore();
    if (n) { try { toastr.info('已自动挂载 ' + n + ' 个事件包'); } catch (e) {} }
  }

  // ---------- 列表（带启用/挂载状态） ----------
  function listAll() {
    var store = readStore(), w = W(), mounted = {};
    if (typeof w.LIFE_LIST_EVENT_PACKS === 'function') {
      (w.LIFE_LIST_EVENT_PACKS() || []).forEach(function (p) { mounted[p.pack_id] = p.count; });
    }
    return store.map(function (s) {
      var id = packId(s.pack);
      return { pack_id: id, namespace: (s.pack && s.pack.namespace) || '', count: (s.pack && s.pack.events ? s.pack.events.length : 0), tags: packTags(s.pack), enabled: !s.enabled, mounted: Object.prototype.hasOwnProperty.call(mounted, id) };
    });
  }

  // ---------- 暴露给 modal iframe (window.parent.*) ----------
  W().LIFE_MODPACK_IMPORT = function (jsonText) {
    var data; try { data = JSON.parse(jsonText); } catch (e) { return { ok: false, msg: 'JSON 解析失败：' + e.message, list: listAll() }; }
    var packs = Array.isArray(data) ? data : [data], store = readStore(), added = [];
    for (var i = 0; i < packs.length; i++) {
      var v = validatePack(packs[i]);
      if (!v.ok) return { ok: false, msg: '校验失败：' + v.msg, list: listAll() };
      var id = packId(packs[i]);
      store = store.filter(function (s) { return packId(s.pack) !== id; });
      store.push({ pack: packs[i], enabled: true });
      added.push(id);
    }
    writeStore(store); applyStore();
    return { ok: true, msg: '已导入并挂载：' + added.join(', '), list: listAll() };
  };
  W().LIFE_MODPACK_TOGGLE = function (id, enabled) {
    var store = readStore();
    for (var i = 0; i < store.length; i++) { if (packId(store[i].pack) === id) store[i].enabled = !enabled; }
    writeStore(store); applyStore();
    return { ok: true, list: listAll() };
  };
  W().LIFE_MODPACK_REMOVE = function (id) {
    var store = readStore().filter(function (s) { return packId(s.pack) !== id; });
    writeStore(store); applyStore();
    return { ok: true, list: listAll() };
  };
  W().LIFE_MODPACK_CLEAR = function () { writeStore([]); applyStore(); return { ok: true, list: listAll() }; };
  W().LIFE_MODPACK_LIST = listAll;
  W().LIFE_MODPACK_ALL_TAGS = function () {
    var counts = {}; listAll().forEach(function (p) { (p.tags || []).forEach(function (t) { counts[t] = (counts[t] || 0) + 1; }); });
    return Object.keys(counts).map(function (t) { return { tag: t, count: counts[t] }; }).sort(function (a, b) { return b.count - a.count; });
  };

  // ---------- 加载时：自动应用 + 注册按钮 + 监听切换聊天 ----------
  function boot() {
    autoApply(0);
    if (typeof appendInexistentScriptButtons === 'function') appendInexistentScriptButtons([{ name: '📦事件包', visible: true }]);
    if (typeof eventOn === 'function' && typeof getButtonEvent === 'function') {
      eventOn(getButtonEvent('📦事件包'), function () { triggerSlash('/sendas name={{user}} <modpack_panel></modpack_panel>'); });
    }
    if (typeof eventOn === 'function' && typeof tavern_events !== 'undefined' && tavern_events && tavern_events.CHAT_CHANGED) {
      eventOn(tavern_events.CHAT_CHANGED, function () { applyStore(); });
    }
  }
  if (typeof $ === 'function') { $(function () { (typeof errorCatched === 'function' ? errorCatched(boot) : boot)(); }); }
  else { boot(); }
})();

