    if (typeof w.LIFE_LIST_NPC_PACKS === 'function') {
      (w.LIFE_LIST_NPC_PACKS() || []).forEach(function (p) { mounted[p.pack_id] = p.count; });
    }
    return store.map(function (s) {
      var id = packId(s.pack);
      return { pack_id: id, namespace: (s.pack && s.pack.namespace) || '', count: (s.pack && s.pack.npcs ? s.pack.npcs.length : 0), tags: packTags(s.pack), enabled: !!s.enabled, mounted: Object.prototype.hasOwnProperty.call(mounted, id) };
    });
  }

  // ---------- 暴露给 modal iframe (window.parent.*) ----------
  W().LIFE_NPCPACK_IMPORT = function (jsonText) {
    var data; try { data = JSON.parse(jsonText); } catch (e) { return { ok: false, msg: 'JSON 解析失败：' + e.message, list: listAll() }; }
    var packs = Array.isArray(data) ? data : [data], store = readStore(), added = [];
    for (var i = 0; i < packs.length; i++) {
      var v = validatePack(packs[i]);
      if (!v.ok) return { ok: false, msg: '校验失败：' + v.msg, list: listAll() };
      var id = packId(packs[i]);
      store = store.filter(function (s) { return packId(s.pack) !== id; });
      store.push({ pack: packs[i], enabled: true });
      added.push(id);
    }
    writeStore(store); applyStore();
    return { ok: true, msg: '已导入并挂载：' + added.join(', '), list: listAll() };
  };
  W().LIFE_NPCPACK_TOGGLE = function (id, enabled) {
    var store = readStore();
    for (var i = 0; i < store.length; i++) { if (packId(store[i].pack) === id) store[i].enabled = !!enabled; }
    writeStore(store); applyStore();
    return { ok: true, list: listAll() };
  };
  W().LIFE_NPCPACK_REMOVE = function (id) {
    var store = readStore().filter(function (s) { return packId(s.pack) !== id; });
    writeStore(store); applyStore();
    return { ok: true, list: listAll() };
  };
  W().LIFE_NPCPACK_CLEAR = function () { writeStore([]); applyStore(); return { ok: true, list: listAll() }; };
  W().LIFE_NPCPACK_LIST = listAll;
  W().LIFE_NPCPACK_ALL_TAGS = function () {
    var counts = {}; listAll().forEach(function (p) { (p.tags || []).forEach(function (t) { counts[t] = (counts[t] || 0) + 1; }); });
    return Object.keys(counts).map(function (t) { return { tag: t, count: counts[t] }; }).sort(function (a, b) { return b.count - a.count; });
  };
  W().LIFE_NPCPACK_APPLY_TO_SAVE = function () {
    var w = W();
    if (typeof w.LIFE_APPLY_NPC_PACKS !== 'function' || typeof Mvu === 'undefined') return { ok: false, msg: '引擎未就绪' };
    try {
      var d = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
      var n = w.LIFE_APPLY_NPC_PACKS(d.stat_data);
      Mvu.replaceMvuData(d, { type: 'message', message_id: 'latest' });
      return { ok: true, msg: '已写入 ' + n + ' 个 NPC 到存档', list: listAll() };
    } catch (e) { return { ok: false, msg: String(e), list: listAll() }; }
  };

  // ---------- 加载时：自动应用 + 注册按钮 + 监听切换聊天 ----------
  function boot() {
    autoApply(0);
    if (typeof appendInexistentScriptButtons === 'function') appendInexistentScriptButtons([{ name: '📇NPC库', visible: true }]);
    if (typeof eventOn === 'function' && typeof getButtonEvent === 'function') {
      eventOn(getButtonEvent('📇NPC库'), function () { triggerSlash('/sendas name={{user}} <npcpack_panel></npcpack_panel>'); });
    }
    if (typeof eventOn === 'function' && typeof tavern_events !== 'undefined' && tavern_events && tavern_events.CHAT_CHANGED) {
      eventOn(tavern_events.CHAT_CHANGED, function () { applyStore(); });
    }
  }
  if (typeof $ === 'function') { $(function () { (typeof errorCatched === 'function' ? errorCatched(boot) : boot)(); }); }
  else { boot(); }
})();

