@@activate
@@private
<%_ toastr.info('mode=' + JSON.stringify(getvar('stat_data.流程状态'))); _%>
<%_
// ─── 读控制状态 ───
if (typeof mode === 'undefined') var mode = getvar('stat_data.流程状态.游戏模式', {defaults: 'CHARACTER_CREATION'});
if (typeof hearTrigger === 'undefined') var hearTrigger = getvar('stat_data.$聆听心声触发', {defaults: 0});

// ─── 事件队列指针自救 + 当前事件唯一注入口───
if (typeof queue === 'undefined') var queue = getvar('stat_data.待结算事件', {defaults: []});
if (typeof ptr === 'undefined') var ptr = Number(getvar('stat_data.事件队列指针', {defaults: 0})) || 0;
if (typeof rpPause === 'undefined') var rpPause = Number(getvar('stat_data.流程状态.RP暂停点', {defaults: -1}));

if (typeof queueLen === 'undefined') var queueLen = Array.isArray(queue) ? queue.length : 0;
if (typeof currentEvt === 'undefined') var currentEvt = (Array.isArray(queue) && ptr >= 0 && ptr < queueLen) ? queue[ptr] : null;

// 合法模式白名单兜底：未知/缺失模式时回落 SCHEDULE，杜绝无指令空回合
if (typeof VALID_MODES === 'undefined') var VALID_MODES = ['CHARACTER_CREATION','SCHEDULE','TIME_ADVANCE','EVENT_SETTLEMENT','RP_MODE','SUMMARY'];
if (VALID_MODES.indexOf(mode) === -1) { mode = 'SCHEDULE'; }

// ─── [ADVANCE_TIME] 强制切模式兜底 ───
// 即便前端未通过 Mvu.setMvuVariable 写回 游戏模式='TIME_ADVANCE'，
// 只要本回合用户消息中含 [ADVANCE_TIME] 指令，调度器立即把 mode 改写为 TIME_ADVANCE，
// 本回合直接进入事件队列生成模块（消除「切模式差一回合」延迟）。
if (typeof userMsg === 'undefined') var userMsg = '';
try {
  var _msgs = getChatMessages(-1, { role: 'user' });
  if (Array.isArray(_msgs) && _msgs.length > 0) userMsg = _msgs[0].message || '';
} catch (e) { userMsg = ''; }
if (mode === 'SCHEDULE' && userMsg.indexOf('[ADVANCE_TIME]') !== -1) {
  mode = 'TIME_ADVANCE';
}

// 自救：处于 EVENT_SETTLEMENT 但指针越界或队列为空 → 当回合改走 SCHEDULE 指令并请求 AI 写回流程
if (mode === 'EVENT_SETTLEMENT' && (!Array.isArray(queue) || queueLen === 0 || ptr < 0 || ptr >= queueLen)) {
  mode = 'SCHEDULE';
}

// 自救：处于 RP_MODE 但 RP暂停点 越界 / 队列为空 → 若指针仍有效则回 EVENT_SETTLEMENT让结算循环接管；否则回 SCHEDULE
// 并以 rescuedFromRP 标记驱动下游分支补一条 state_sync，请求 AI 写回流程状态
if (typeof rescuedFromRP === 'undefined') var rescuedFromRP = false;
if (mode === 'RP_MODE' && (!Array.isArray(queue) || queueLen === 0 || rpPause < 0 || rpPause >= queueLen)) {
  rescuedFromRP = true;
  if (Array.isArray(queue) && queueLen > 0 && ptr >= 0 && ptr < queueLen) {
    mode = 'EVENT_SETTLEMENT';
  } else {
    mode = 'SCHEDULE';
  }
}
_%>
<%_ if(mode === 'CHARACTER_CREATION') { _%>
<%- await getwi('[模式]角色创建指令') %>
<%_ } else if(mode === 'SCHEDULE') { _%>
<%- await getwi('[模式]日程安排指令') %>
<%_ // 自救：SCHEDULE 阶段事件队列残留（异常退出、回档等）→ 请求 AI 清理
if (Array.isArray(queue) && queueLen > 0) { _%>
<state_sync>
检测到 SCHEDULE 阶段事件队列残留（指针=<%= ptr %>，队列长度=<%= queueLen %>）。
在本回复末尾的 <UpdateVariable> 中执行：
- replace /待结算事件 value []
- replace /事件队列指针 value 0
- replace /流程状态/RP暂停点 value -1
- replace /流程状态/游戏模式 value "SCHEDULE"
</state_sync>
<%_ } _%>
<%_ } else if(mode === 'TIME_ADVANCE') { _%>
<%- await getwi('[模式]时间推进指令') %>
<%_
// 本轮日程注入（前端「提交日程」按钮通过 Mvu.setMvuVariable 在发送消息前写入 stat_data.日程）
if (typeof currentSchedule === 'undefined') var currentSchedule = getvar('stat_data.日程', {defaults: {}});
if (currentSchedule && typeof currentSchedule === 'object' && Object.keys(currentSchedule).length > 0) {
_%>
<current_schedule note="本轮玩家提交的日程；按 [模式]时间推进指令 中的日程解析规则消费">
<%= JSON.stringify(currentSchedule, null, 2) %>
</current_schedule>
<%_ } _%>
<%_
// 种子包注入：TIME_ADVANCE 时注入仲裁器选出的本轮种子包
if (typeof seedPackInfo === 'undefined') var seedPackInfo = getvar('stat_data.仲裁器.本轮种子包', {defaults: {}});
if (typeof seedPool === 'undefined') var seedPool = getvar('stat_data.$隐藏记忆库.延时种子', {defaults: {}});
var mainSeedId = seedPackInfo.主种子id || '';
var subSeedIds = seedPackInfo.副种子ids || [];
if (mainSeedId && seedPool[mainSeedId]) {
_%>
<seed_pack>
<main_seed id="<%= mainSeedId %>">
<%= JSON.stringify(seedPool[mainSeedId], null, 2) %>
</main_seed>
<%_ for (var si = 0; si < subSeedIds.length; si++) { if (seedPool[subSeedIds[si]]) { _%>
<sub_seed id="<%= subSeedIds[si] %>">
<%= JSON.stringify(seedPool[subSeedIds[si]], null, 2) %>
</sub_seed>
<%_ } } _%>
</seed_pack>
<%_ } _%>
<%_ } else if(mode === 'EVENT_SETTLEMENT') { _%>
<%- await getwi('[模式]事件结算指令') %>
<%_ // 当前事件唯一注入口：只注入指针所指那一条完整载荷
if (currentEvt) { _%>
<current_event index="<%= ptr %>" of="<%= queueLen %>">
<%= JSON.stringify(currentEvt, null, 2) %>
</current_event>
<%_ } _%>
<%_ // RP_MODE 越界救援被重定向至 EVENT_SETTLEMENT，或不在 RP_MODE 但 RP暂停点 仍 ≥0，都要请 AI 写回流程状态
if (rpPause >= 0 || rescuedFromRP) { _%>
<state_sync>
<%_ if (rescuedFromRP) { _%>检测到 RP_MODE 越界救援（RP暂停点=<%= rpPause %>，队列长度=<%= queueLen %>，指针=<%= ptr %>）。
<%_ } else { _%>检测到不在 RP_MODE 但 RP暂停点=<%= rpPause %> 仍未清零（可能上一轮 RP 异常退出）。
<%_ } _%>在本回复末尾的 <UpdateVariable> 中执行：
- replace /流程状态/RP暂停点 value -1
<%_ if (rescuedFromRP) { _%>- replace /流程状态/游戏模式 value "EVENT_SETTLEMENT"
<%_ } _%></state_sync>
<%_ } _%>
<%_ } else if(mode === 'RP_MODE') { _%>
<%- await getwi('[模式]RP模式指令') %>
<%_ // RP 也需注入暂停点所指那一条（防止 AI 失忆扮演错事件）
if (rpPause >= 0 && rpPause < queueLen) { _%>
<rp_target_event index="<%= rpPause %>">
<%= JSON.stringify(queue[rpPause], null, 2) %>
</rp_target_event>
<%_ } _%>
<%_ } else if(mode === 'SUMMARY') { _%>
<%- await getwi('[模式]人生总结指令') %>
<%_ } else { _%>
<%- await getwi('[模式]日程安排指令') %>
<%_ } _%>
<%_ if(Number(hearTrigger) === 1) { _%>
<%- await getwi('[特殊]聆听心声指令') %>
<%_ } _%>

